-- ─── carte_postale : Carte postale ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'carte_postale', '{}'::jsonb, 'fr', 'Carte postale personnalisée', array['carte postale','carte postale personnalisée','carte de correspondance','carte promotionnelle','carte A6','carte carrée','carte de remerciement','mailing postal','carte commerciale','impression carte postale']::text[],
  'Carte postale {{papier}} {{grammage}} — {{finition}} — {{quantite}} ex.', 'Carte postale imprimée en quadri sur {{papier}} {{grammage}}, finition {{finition}}. Un support compact et durable pour vos messages commerciaux ou personnels.',
  '## Présentation

La carte postale reste un des supports imprimés les plus conservés par ses destinataires. Format compact, carton rigide, message direct : elle sert aussi bien la correspondance client que la promotion d''un commerce, d''une exposition ou d''un lancement produit. Imprimée sur {{papier}} {{grammage}}, elle offre un toucher qualitatif dès la prise en main.

## Caractéristiques techniques

Deux formats au choix : A6 (105 × 148 mm), le standard postal, ou carré 100 × 100 mm pour sortir du lot. Impression quadrichromie recto seul ou recto/verso. Supports disponibles du couché demi-mat 350 g au bristol, avec variantes recyclées et papiers de création texturés. Finitions possibles : pelliculage mat, brillant ou soft touch, vernis sélectif, dorure à chaud, coins arrondis.

## Avantages

Un coût unitaire faible pour un support que l''on garde : affichée sur un frigo ou glissée dans un colis, la carte postale prolonge votre visibilité bien après l''envoi. Sa rigidité {{grammage}} garantit une tenue impeccable en boîte aux lettres comme en présentoir de comptoir.', 'Carte postale {{papier}} {{grammage}} personnalisée',
  'Impression carte postale personnalisée A6 et carrée', 'Cartes postales personnalisées : A6 105×148 mm ou carré 100×100 mm, couché 350 g, finitions dorure et vernis. Impression pro, petites et grandes séries.', array['carte postale personnalisée','impression carte postale','carte postale A6','carte postale carrée','carte de correspondance','carte postale entreprise','carte postale 350g','mailing carte postale']::text[], 'Product',
  'La carte postale est le support imprimé que vos clients gardent : un message direct, un carton rigide, un coût unitaire minime. Glissez-la dans vos colis ou vos mailings et restez visible des semaines durant.', '["Support conservé longtemps par le destinataire", "Carton rigide 350 g : tenue et toucher premium", "Format A6 compatible tarifs postaux courants", "Recto/verso : visuel fort + message et coordonnées", "Finitions dorure et vernis pour un rendu haut de gamme", "Versions recyclées disponibles pour une communication responsable"]'::jsonb, '["Carte glissée dans les colis e-commerce", "Mailing postal de fidélisation", "Promotion d''exposition ou de vernissage", "Carte de remerciement client", "Vente en boutique (illustrateurs, musées)"]'::jsonb,
  '[{"title": "Colis e-commerce", "description": "Une carte remerciant l''achat avec un code de parrainage au verso transforme chaque livraison en outil de fidélisation."}, {"title": "Commerce de proximité", "description": "Un restaurant annonce sa nouvelle carte saisonnière avec une carte postale déposée chez les commerçants voisins."}, {"title": "Artistes et illustrateurs", "description": "Tirage de séries de cartes vendues en boutique ou sur les marchés de créateurs, avec un rendu fidèle des couleurs."}, {"title": "Événementiel", "description": "Save-the-date ou invitation informelle envoyée en amont d''un salon professionnel pour marquer les esprits."}]'::jsonb, '[{"question": "Quel format de fichier fournir ?", "answer": "Un PDF haute définition (300 dpi) en CMJN, polices vectorisées ou incorporées. Les formats ouverts (AI, INDD) sont acceptés après conversion en PDF."}, {"question": "Faut-il prévoir des fonds perdus ?", "answer": "Oui, ajoutez 3 mm de fond perdu sur chaque bord et gardez les textes à 5 mm minimum du bord de coupe."}, {"question": "Quel grammage choisir ?", "answer": "Le couché 350 g est le standard : rigide, agréable en main, il tient parfaitement en présentoir. En dessous de 300 g, la carte paraît souple."}, {"question": "Puis-je écrire au verso ?", "answer": "Oui : choisissez un verso non pelliculé ou un papier offset/création pour écrire au stylo sans bavure."}, {"question": "Existe-t-il une version écologique ?", "answer": "Oui, papiers recyclés et papiers issus de forêts gérées durablement (certification FSC) disponibles sans surcoût prohibitif."}]'::jsonb, '{"formats": ["105 × 148 mm (A6)", "100 × 100 mm (carré)"], "supports": ["couché demi-mat 350 g", "couché brillant 350 g", "bristol blanc 400 g", "recyclé satin 350 g", "papiers de création 300-350 g"], "finitions": ["pelliculage mat", "pelliculage brillant", "pelliculage soft touch", "vernis sélectif 2D/3D", "dorure à chaud", "coins arrondis"], "impression": "quadri recto ou recto/verso", "quantites": "50 → 20 000 ex., paliers 50/100/250/500/1000", "delais": "standard 48-72 h, express possible", "options": ["multi-visuels dans une même commande", "verso inscriptible", "papier ensemencé"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── carton_invitation : Carton d'invitation / Faire-part ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'carton_invitation', '{}'::jsonb, 'fr', 'Carton d''invitation et faire-part', array['carton d''invitation','faire-part','invitation mariage','invitation entreprise','carte d''invitation','faire-part naissance','invitation inauguration','carton événement','invitation personnalisée','carte événementielle']::text[],
  'Carton d''invitation {{papier}} {{grammage}} — {{finition}} — {{quantite}} ex.', 'Carton d''invitation ou faire-part imprimé sur carte épaisse {{grammage}}, finition {{finition}}. L''annonce élégante de vos événements privés et professionnels.',
  '## Présentation

Mariage, inauguration, soirée d''entreprise, naissance : l''invitation imprimée donne le ton de l''événement avant même qu''il ne commence. Sur carte épaisse {{papier}} {{grammage}}, votre carton d''invitation conjugue tenue irréprochable et rendu soigné, avec des finitions qui font la différence dès l''ouverture de l''enveloppe.

## Caractéristiques techniques

Formats classiques : carré 140 × 140 mm, A6 (105 × 148 mm) ou DL (99 × 210 mm), en carte simple ou double volet rainé. Cartons épais à partir de 300 g : couché, papiers de création texturés (vergé, martelé, extra blanc), kraft ou recyclé. Finitions événementielles : dorure à chaud, letterpress, gaufrage, vernis sélectif 3D, thermorelief.

## Avantages

Une invitation papier annonce un événement qui compte : elle se conserve, se pose sur une cheminée, se montre. Les papiers texturés et la dorure créent une émotion tactile qu''aucun e-mail ne remplace, tandis que le double volet offre l''espace nécessaire au programme et au plan d''accès.', 'Carton d''invitation {{papier}} {{grammage}} sur mesure',
  'Carton d''invitation & faire-part — impression premium', 'Faire-parts et cartons d''invitation sur carte épaisse 300 g+ : dorure, letterpress, papiers de création. Mariage, entreprise, inauguration.', array['carton d''invitation','faire-part mariage','invitation entreprise','faire-part dorure','invitation inauguration','carte invitation personnalisée','faire-part letterpress','papier création']::text[], 'Product',
  'Votre événement mérite mieux qu''un e-mail : un carton épais, un papier texturé, une dorure qui accroche la lumière. L''invitation imprimée crée l''attente et donne à votre événement le statut qu''il mérite.', '["Carte épaisse 300 g+ : prestance immédiate en main", "Finitions émotionnelles : dorure, letterpress, gaufrage", "Papiers de création texturés pour se démarquer", "Format double volet pour programme et informations pratiques", "Petites séries possibles, adaptées aux événements privés", "Options écologiques : recyclé, kraft, papier ensemencé"]'::jsonb, '["Faire-part de mariage ou de naissance", "Invitation à une inauguration", "Soirée annuelle d''entreprise", "Vernissage ou lancement produit", "Gala ou remise de prix"]'::jsonb,
  '[{"title": "Mariage", "description": "Faire-part carré sur papier martelé avec dorure or : le premier objet que les invités associent à votre journée."}, {"title": "Inauguration de locaux", "description": "Un carton DL au nom de chaque invité crédibilise l''événement et améliore sensiblement le taux de présence."}, {"title": "Soirée client", "description": "Invitation double volet : visuel fort en couverture, programme et plan à l''intérieur, RSVP au dos."}, {"title": "Lancement produit", "description": "Carton avec vernis sélectif 3D reprenant la texture du produit : l''invitation devient un teaser tactile."}]'::jsonb, '[{"question": "Quel format de fichier fournir ?", "answer": "PDF 300 dpi en CMJN avec 3 mm de fonds perdus. Pour la dorure ou le vernis sélectif, fournissez un calque vectoriel séparé en aplat 100 %."}, {"question": "Quel grammage pour un faire-part ?", "answer": "Minimum 300 g pour une tenue digne de l''événement ; 350 g ou papier de création épais pour un rendu vraiment premium."}, {"question": "Puis-je commander de petites quantités ?", "answer": "Oui, les séries démarrent à quelques dizaines d''exemplaires, ce qui convient aux événements privés."}, {"question": "Le double volet est-il livré plié ?", "answer": "Le carton double est livré rainé et plié, prêt à mettre sous enveloppe."}, {"question": "Proposez-vous des enveloppes assorties ?", "answer": "Oui, des enveloppes aux formats correspondants (carrées, C6, DL) peuvent compléter la commande."}]'::jsonb, '{"formats": ["140 × 140 mm (carré)", "105 × 148 mm (A6)", "99 × 210 mm (DL)", "double volet 210 × 148 mm ouvert", "sur mesure"], "supports": ["couché demi-mat 350 g", "papiers de création 300-350 g (vergé, martelé, extra blanc)", "kraft 300 g", "recyclé 300-350 g"], "finitions": ["dorure à chaud", "letterpress", "gaufrage", "vernis sélectif 2D/3D", "thermorelief", "coins arrondis", "pelliculage soft touch"], "impression": "quadri recto ou recto/verso", "quantites": "25 → 5 000 ex., paliers 25/50/100/250/500", "delais": "standard 3-5 jours ouvrés, express possible", "options": ["rainage et pliage double volet", "enveloppes assorties", "papier ensemencé"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── flyer_a7 : Flyer A7 ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'flyer_a7', '{}'::jsonb, 'fr', 'Flyer A7 (74 × 105 mm)', array['flyer A7','mini flyer','petit flyer','flyer poche','prospectus A7','tract petit format','flyer 74x105','carte promotionnelle','flyer distribution','coupon publicitaire']::text[],
  'Flyer A7 {{papier}} {{grammage}} — {{quantite}} ex.', 'Mini flyer A7 (74 × 105 mm) imprimé en quadri sur {{papier}} {{grammage}}. Le format de poche idéal pour la distribution de masse et les offres flash.',
  '## Présentation

Le flyer A7 est le plus compact des prospectus : 74 × 105 mm, la taille d''une carte à jouer. Il se glisse dans une poche, un portefeuille, un sac de caisse. C''est le format de la distribution intensive : offre flash, code promo, invitation à un événement — un message unique, immédiatement lisible.

## Caractéristiques techniques

Format 74 × 105 mm (quart de A5), impression quadrichromie recto ou recto/verso. Papiers du couché 135 g souple, économique en distribution, jusqu''au couché 350 g rigide façon carte, en versions brillante, mate ou recyclée. Fonds perdus 3 mm requis, textes à 5 mm des bords.

## Avantages

À surface réduite, coût réduit : l''A7 permet des tirages massifs à budget maîtrisé, sans sacrifier la qualité d''impression. En 300-350 g, il devient carte-coupon : conservé dans le portefeuille, il ramène le client en boutique. Un excellent ratio impact/prix pour le street marketing.', 'Flyer A7 {{papier}} {{grammage}} — impression petit format',
  'Flyer A7 74×105 mm — impression mini flyer pas cher', 'Flyers A7 format poche 74×105 mm : quadri recto/verso, 135 à 350 g, grandes séries économiques. Idéal offres flash, coupons et street marketing.', array['flyer A7','mini flyer','flyer petit format','prospectus A7','flyer 74x105 mm','coupon promotionnel','flyer street marketing','impression flyer']::text[], 'Product',
  'Le flyer A7 tient dans toutes les poches et dans tous les budgets : un seul message, une distribution massive, un coût unitaire imbattable. En carton épais, il devient un coupon que vos clients gardent sur eux.', '["Format poche : se garde au lieu de se jeter", "Coût unitaire minimal pour les grandes distributions", "En 350 g, fait office de carte-coupon durable", "Message unique, lecture en 3 secondes", "Recto/verso : offre d''un côté, conditions de l''autre", "Léger : distribution main-à-main sans fatigue"]'::jsonb, '["Code promo distribué en caisse", "Street marketing devant un point de vente", "Coupon de réduction encarté en colis", "Invitation à une soirée ou un concert", "Carte de jeu-concours"]'::jsonb,
  '[{"title": "Offre de lancement", "description": "Un food-truck distribue 5 000 flyers A7 avec un code de réduction : format poche, le coupon revient en caisse pendant des semaines."}, {"title": "Sac de caisse", "description": "Glissé dans chaque sac par un commerçant, l''A7 annonce les ventes privées sans alourdir le passage en caisse."}, {"title": "Vie nocturne", "description": "Bars et clubs impriment leurs programmes du mois en A7 350 g : le format carte résiste à une soirée en poche."}, {"title": "Jeu-concours", "description": "Un centre commercial imprime des A7 numérotés à gratter les coordonnées : petit format, forte mécanique de collecte."}]'::jsonb, '[{"question": "Quel fichier fournir ?", "answer": "PDF 300 dpi en CMJN, format final 74 × 105 mm + 3 mm de fonds perdus sur chaque bord, textes à 5 mm minimum de la coupe."}, {"question": "Quel grammage choisir ?", "answer": "135-170 g pour la distribution volumique et économique ; 300-350 g si le flyer doit servir de coupon conservé."}, {"question": "Recto seul ou recto/verso ?", "answer": "Le recto/verso coûte peu de plus et double l''espace : visuel accrocheur au recto, offre détaillée et coordonnées au verso."}, {"question": "Quelle est la quantité minimale ?", "answer": "Les séries démarrent à 50 exemplaires, mais l''A7 devient réellement économique à partir de 1 000 exemplaires."}, {"question": "Existe-t-il une option écologique ?", "answer": "Oui : papiers recyclés et certifiés FSC, adaptés aux distributions grand public soucieuses de leur image."}]'::jsonb, '{"formats": ["74 × 105 mm (A7)"], "supports": ["couché brillant 135 g", "couché demi-mat 135 g", "couché 170 g", "couché 250 g", "couché 300-350 g", "recyclé 135-350 g"], "finitions": ["sans finition", "pelliculage mat ou brillant (grammages épais)", "coins arrondis"], "impression": "quadri recto ou recto/verso", "quantites": "50 → 100 000 ex., paliers 100/250/500/1000/2500/5000", "delais": "standard 48-72 h, express possible", "options": ["multi-visuels", "encre à gratter (jeux)", "papier ensemencé"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── flyer_carre : Flyer carré ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'flyer_carre', '{}'::jsonb, 'fr', 'Flyer carré (148 × 148 mm)', array['flyer carré','prospectus carré','flyer 148x148','flyer original','flyer design','tract carré','flyer créatif','support carré','flyer instagram','impression flyer carré']::text[],
  'Flyer carré {{papier}} {{grammage}} — {{quantite}} ex.', 'Flyer carré 148 × 148 mm imprimé en quadri sur {{papier}} {{grammage}}. Un format qui sort de la pile et met vos visuels au carré.',
  '## Présentation

Dans une pile de prospectus rectangulaires, le carré attire l''œil. Le flyer 148 × 148 mm reprend le langage visuel des réseaux sociaux — cadrage carré, visuel plein format — et le transpose dans la rue et en point de vente. Un choix graphique fort pour les marques qui soignent leur image.

## Caractéristiques techniques

Format 148 × 148 mm (base A5), impression quadrichromie recto ou recto/verso. Gamme complète de papiers : couché brillant ou demi-mat de 135 à 350 g, versions recyclées, papiers de création pour un rendu galerie. Finitions disponibles sur grammages épais : pelliculage, vernis sélectif, coins arrondis.

## Avantages

Le carré valorise la photographie et l''illustration : produit centré, portrait, packshot. Il se démarque physiquement des formats A5/A6 omniprésents et signale une attention au design. En 350 g pelliculé, il devient une carte d''image que l''on conserve — parfait pour les marques lifestyle, la restauration et la culture.', 'Flyer carré 148 × 148 mm {{papier}} {{grammage}}',
  'Flyer carré 148×148 mm — impression format design', 'Flyers carrés 148×148 mm : le format design qui se démarque. Quadri recto/verso, 135 à 350 g, finitions pelliculage et vernis. Séries de 50 à 100 000 ex.', array['flyer carré','flyer 148x148','prospectus carré','flyer design','flyer original','impression flyer carré','support communication carré','flyer créatif']::text[], 'Product',
  'Tous les flyers sont rectangulaires — le vôtre sera carré. Un format signature qui valorise vos visuels comme un post Instagram imprimé et distingue immédiatement votre marque dans la pile.', '["Se démarque visuellement des formats A5/A6 classiques", "Cadrage carré idéal pour photos produits et portraits", "Cohérence avec vos visuels réseaux sociaux", "Rendu premium en grammage épais pelliculé", "Recto/verso pour visuel + message structuré", "Gamme de papiers création pour un effet galerie"]'::jsonb, '["Communication de marque lifestyle", "Carte menu ou nouveauté restaurant", "Programme d''exposition ou de festival", "Lancement de collection boutique", "Support salon au design soigné"]'::jsonb,
  '[{"title": "Marque lifestyle", "description": "Une marque de cosmétiques décline ses visuels Instagram en flyers carrés 350 g soft touch remis à chaque achat."}, {"title": "Restauration", "description": "Un coffee shop annonce sa carte d''hiver sur flyer carré : le format évoque naturellement ses publications en ligne."}, {"title": "Culture", "description": "Une galerie imprime le programme de son exposition en carré sur papier de création : le flyer devient objet de collection."}, {"title": "Retail", "description": "Une boutique de mode encarte un flyer carré recto/verso dans chaque sac : nouveau drop d''un côté, réseaux et fidélité de l''autre."}]'::jsonb, '[{"question": "Quel fichier fournir ?", "answer": "PDF 300 dpi en CMJN au format 148 × 148 mm avec 3 mm de fonds perdus par bord ; textes et logos à 5 mm de la coupe."}, {"question": "Le format carré coûte-t-il plus cher ?", "answer": "Légèrement, car il optimise moins la feuille d''impression qu''un format standard, mais l''écart reste faible sur les séries courantes."}, {"question": "Quel grammage privilégier ?", "answer": "170 g pour la distribution, 300-350 g pelliculé pour un support d''image conservé par le client."}, {"question": "Peut-il être envoyé par courrier ?", "answer": "Oui, il entre dans une enveloppe carrée 155 × 155 mm ; vérifiez la tarification postale des plis carrés avant un mailing massif."}, {"question": "Recto/verso recommandé ?", "answer": "Oui : visuel plein format au recto, informations pratiques au verso — le carré rend cette répartition très lisible."}]'::jsonb, '{"formats": ["148 × 148 mm"], "supports": ["couché brillant 135-350 g", "couché demi-mat 135-350 g", "recyclé 135-350 g", "papiers de création 250-350 g"], "finitions": ["pelliculage mat/brillant/soft touch", "vernis sélectif 2D/3D", "dorure à chaud", "coins arrondis"], "impression": "quadri recto ou recto/verso", "quantites": "50 → 100 000 ex., paliers 100/250/500/1000/2500", "delais": "standard 48-72 h, express possible", "options": ["multi-visuels", "papier ensemencé", "découpe spéciale sur devis"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── depliant_2_volets : Dépliant 2 volets ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'depliant_2_volets', '{}'::jsonb, 'fr', 'Dépliant 2 volets (1 pli)', array['dépliant 2 volets','dépliant 1 pli','plaquette 2 volets','dépliant pli central','leaflet 2 volets','plaquette commerciale','dépliant A5','dépliant 4 pages','brochure 2 volets','impression dépliant']::text[],
  'Dépliant 2 volets {{papier}} {{grammage}} — {{quantite}} ex.', 'Dépliant 2 volets (1 pli central) imprimé en quadri sur {{papier}} {{grammage}}, livré plié. 4 faces pour structurer votre message comme une mini-plaquette.',
  '## Présentation

Le dépliant 2 volets est la plus simple des plaquettes : une feuille, un pli central, quatre faces. Couverture, développement intérieur en double page, dos pour les coordonnées. C''est le support d''une présentation d''entreprise, d''une offre de services ou d''un menu, avec la sobriété d''un document qui s''ouvre comme un livre.

## Caractéristiques techniques

Formats fermés courants : A5 (148 × 210 mm, soit A4 ouvert), A4 (210 × 297 mm, soit A3 ouvert), carré 210 × 210 mm et DL. Pli central ou pli décalé (une face dépasse pour créer un onglet). Papiers de 130 à 350 g : couché brillant ou demi-mat, offset, recyclé, création. Livré plié, impression quadri recto/verso.

## Avantages

Quatre faces au prix d''un pli : le 2 volets double l''espace d''un flyer tout en hiérarchisant la lecture — accroche, contenu, contact. En grammage épais avec pelliculage, il tient debout sur un comptoir et fait office de carte de présentation d''entreprise durable.', 'Dépliant 2 volets {{papier}} {{grammage}} — 4 faces',
  'Dépliant 2 volets — impression plaquette pli central', 'Dépliants 2 volets pliés : A5, A4, carré ou DL fermé, 4 faces quadri, papiers 130 à 350 g. Plaquette commerciale livrée pliée, séries dès 50 ex.', array['dépliant 2 volets','plaquette 2 volets','dépliant pli central','dépliant 4 pages','plaquette commerciale','dépliant A5 fermé','impression dépliant plié','leaflet']::text[], 'Product',
  'Quatre faces, une hiérarchie de lecture naturelle : le dépliant 2 volets transforme votre flyer en plaquette. Couverture qui accroche, intérieur qui déroule votre offre, dos qui donne vos coordonnées.', '["4 faces structurées : accroche, contenu, contact", "Ouverture type livre : lecture guidée et professionnelle", "Double page intérieure pour un visuel panoramique", "Livré plié, prêt à distribuer ou à poser en présentoir", "En 250-350 g : véritable plaquette d''entreprise", "Pli décalé possible pour créer un onglet d''appel"]'::jsonb, '["Plaquette de présentation d''entreprise", "Menu de restaurant recto intérieur", "Programme court d''événement", "Fiche produit ou offre de services", "Carte de vœux d''entreprise grand format"]'::jsonb,
  '[{"title": "Artisan / PME", "description": "Plaquette A5 fermée : métier en couverture, prestations et photos de réalisations en double page, zone d''intervention et contact au dos."}, {"title": "Restaurant", "description": "Menu 2 volets carré 350 g pelliculé : entrées-plats-desserts en intérieur, informations pratiques au dos, résistant au service."}, {"title": "Immobilier", "description": "Fiche de bien en A4 fermé : photo pleine page en couverture, plan et prestations à l''intérieur, agence au dos."}, {"title": "Événement", "description": "Programme d''une journée portes ouvertes : horaires et plan en double page intérieure, partenaires au dos."}]'::jsonb, '[{"question": "Comment préparer le fichier ?", "answer": "Fournissez un PDF au format ouvert (ex. A4 pour un A5 fermé) avec 3 mm de fonds perdus, pages dans l''ordre de lecture ; le pli est indiqué dans le gabarit téléchargeable."}, {"question": "Quel grammage pour qu''il tienne debout ?", "answer": "À partir de 250 g le dépliant tient en présentoir ; en 300-350 g il se comporte comme une carte double rigide."}, {"question": "Le dépliant est-il livré plié ?", "answer": "Oui, tous les dépliants sont livrés rainés et pliés, prêts à l''usage. Les forts grammages sont rainés pour éviter la casse du pli."}, {"question": "Fonds perdus obligatoires ?", "answer": "Oui : 3 mm sur les quatre bords du format ouvert, textes à 5 mm des bords et du pli."}, {"question": "Quelle quantité minimale ?", "answer": "Les séries démarrent à 50 exemplaires ; le coût unitaire baisse fortement à partir de 500."}]'::jsonb, '{"formats": ["A5 fermé 148 × 210 mm (A4 ouvert)", "A4 fermé 210 × 297 mm (A3 ouvert)", "carré fermé 210 × 210 mm", "DL fermé 99 × 210 mm", "sur mesure"], "supports": ["couché demi-mat 130-350 g", "couché brillant 130-350 g", "offset 90-120 g", "recyclé", "papiers de création"], "finitions": ["pelliculage mat/brillant/soft touch (grammages épais)", "vernis sélectif", "dorure à chaud", "rainage"], "impression": "quadri recto/verso (4 faces)", "quantites": "50 → 100 000 ex., paliers 100/250/500/1000/2500", "delais": "standard 48-72 h, express possible", "options": ["pli central ou pli décalé", "livré plié", "multi-visuels"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── depliant_accordeon : Dépliant accordéon ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'depliant_accordeon', '{}'::jsonb, 'fr', 'Dépliant accordéon (pli zigzag)', array['dépliant accordéon','pli accordéon','dépliant zigzag','leporello','dépliant 3 volets accordéon','dépliant 4 volets','pli en Z','dépliant panoramique','guide plié','impression dépliant accordéon']::text[],
  'Dépliant accordéon {{papier}} {{grammage}} — {{quantite}} ex.', 'Dépliant à pli accordéon (zigzag) imprimé en quadri sur {{papier}} {{grammage}}, livré plié. Des volets qui se déploient en panorama, parfaits pour guides et parcours.',
  '## Présentation

Le pli accordéon — ou pli en Z — replie les volets alternativement dans un sens puis dans l''autre, comme un soufflet. Résultat : un document compact fermé, qui se déploie d''un geste en frise panoramique. C''est le pliage des guides, des plans, des chronologies et des pas-à-pas, où le contenu se lit dans l''ordre du dépliage.

## Caractéristiques techniques

De 3 à 6 volets et plus (2 à 5 plis parallèles). Formats fermés courants : DL (100 × 210 mm), A5 ou carré ; formats ouverts jusqu''à 630 × 297 mm. Contrairement au pli roulé, tous les volets ont la même largeur. Papiers 130 à 350 g, couché brillant/demi-mat, offset ou recyclé. Livré plié, quadri recto/verso.

## Avantages

Chaque volet devient un écran de lecture : étape 1, étape 2, étape 3... L''accordéon guide naturellement le lecteur, sans jamais masquer un volet derrière un autre. Il se referme à plat et tient debout en zigzag sur un comptoir — un vrai plus en présentoir.', 'Dépliant accordéon {{papier}} {{grammage}} — pli zigzag',
  'Dépliant accordéon (pli Z) — impression en ligne', 'Dépliants accordéon 3 à 6 volets : pliage zigzag panoramique, formats DL à 630 mm ouverts, papiers 130-350 g. Guides, plans et parcours, livrés pliés.', array['dépliant accordéon','pli accordéon','pli en Z','dépliant zigzag','leporello','dépliant panoramique','guide plié','impression dépliant']::text[], 'Product',
  'L''accordéon déplie votre message comme une frise : chaque volet est une étape, chaque pli une respiration. Le pliage idéal pour raconter un parcours, un guide ou une gamme, volet après volet.', '["Lecture séquencée : parfait pour étapes et parcours", "Déploiement panoramique pour visuels continus", "Volets de largeur égale : mise en page simple", "Tient debout en zigzag sur un comptoir", "Compact fermé, généreux ouvert (jusqu''à 6 volets et plus)", "Se referme facilement, sans forcer le pli"]'::jsonb, '["Guide touristique ou plan de visite", "Mode d''emploi ou pas-à-pas produit", "Chronologie ou frise d''entreprise", "Présentation de gamme volet par volet", "Carte de circuit ou d''itinéraire"]'::jsonb,
  '[{"title": "Office de tourisme", "description": "Plan de ville en accordéon 6 volets : compact en poche, panoramique une fois ouvert, chaque volet couvrant un quartier."}, {"title": "Industrie", "description": "Un fabricant détaille l''installation de son produit en 5 étapes, un volet par étape, dans l''ordre exact du dépliage."}, {"title": "Vignoble", "description": "Frise du domaine dépliée en accordéon : histoire, terroir, cuvées, dégustation — un storytelling physique."}, {"title": "Musée", "description": "Livret d''exposition en leporello posé debout en boutique : l''objet lui-même attire la main."}]'::jsonb, '[{"question": "Accordéon ou pli roulé, comment choisir ?", "answer": "L''accordéon garde tous les volets à la même largeur et se lit en séquence ; le pli roulé enroule les volets vers l''intérieur et crée un effet de découverte. Pour un contenu par étapes, préférez l''accordéon."}, {"question": "Comment préparer le fichier ?", "answer": "PDF au format ouvert avec traits de plis selon le gabarit, 3 mm de fonds perdus, textes à 5 mm des plis et des coupes."}, {"question": "Quel grammage recommandé ?", "answer": "130-170 g pour un dépliage souple sur les grands formats ; 250 g maximum conseillé au-delà de 4 volets pour un pliage net."}, {"question": "Combien de volets possibles ?", "answer": "De 3 à 6 volets en standard ; au-delà, une étude sur mesure garantit la faisabilité du pliage."}, {"question": "Est-il livré plié ?", "answer": "Oui, rainé si nécessaire et livré plié, prêt à distribuer."}]'::jsonb, '{"formats": ["fermé DL 100 × 210 mm", "fermé A5 148 × 210 mm", "fermé carré 148 × 148 mm", "ouvert jusqu''à 630 × 297 mm", "sur mesure"], "supports": ["couché demi-mat 130-250 g", "couché brillant 130-250 g", "offset 90-120 g", "recyclé 115-170 g"], "finitions": ["sans finition", "vernis sélectif", "rainage (grammages épais)"], "impression": "quadri recto/verso", "quantites": "50 → 100 000 ex., paliers 100/250/500/1000/2500", "delais": "standard 48-72 h, express possible", "options": ["2 à 5 plis parallèles", "pli décalé accordéon", "livré plié"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── depliant_plie_dl : Dépliant plié DL (3 volets) ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'depliant_plie_dl', '{}'::jsonb, 'fr', 'Dépliant 3 volets DL (A4 plié)', array['dépliant 3 volets','dépliant DL','A4 plié en 3','dépliant roulé','tri-fold','plaquette 3 volets','dépliant 10x21','dépliant 6 pages','brochure 3 volets','impression dépliant DL']::text[],
  'Dépliant 3 volets DL {{papier}} {{grammage}} — {{quantite}} ex.', 'Le grand classique : A4 (210 × 297 mm) plié en 3 volets, format fermé DL 100 × 210 mm. Six faces en quadri sur {{papier}} {{grammage}}, livré plié.',
  '## Présentation

C''est le dépliant le plus répandu de la communication d''entreprise : une feuille A4 pliée en trois volets, refermée au format DL (100 × 210 mm). Six faces pour dérouler une offre complète — couverture, argumentaire intérieur sur trois volets, dos avec coordonnées — dans un format qui entre dans une enveloppe DL standard et dans tous les présentoirs.

## Caractéristiques techniques

Format ouvert 210 × 297 mm (A4), fermé 100 × 210 mm. Deux pliages au choix : roulé (le volet droit se replie à l''intérieur, effet de découverte) ou accordéon (zigzag). Attention pli roulé : le volet rentrant est légèrement plus étroit (97 mm). Papiers 130 à 350 g, couché brillant ou demi-mat, offset, recyclé. Quadri recto/verso, livré plié.

## Avantages

Six faces organisées pour un coût proche du flyer A4 : le 3 volets DL structure un argumentaire complet sans assommer le lecteur. Compatible enveloppes DL et présentoirs à documents, c''est le couteau suisse de la plaquette commerciale.', 'Dépliant 3 volets DL {{papier}} {{grammage}} — A4 plié',
  'Dépliant 3 volets DL — A4 plié roulé ou accordéon', 'Dépliant 3 volets : A4 210×297 plié au format DL 100×210 mm, pli roulé ou accordéon, 6 faces quadri, 130-350 g. Livré plié, dès 50 exemplaires.', array['dépliant 3 volets','dépliant DL','A4 plié en 3','pli roulé','tri-fold','plaquette commerciale DL','dépliant 6 faces','impression dépliant']::text[], 'Product',
  'Le 3 volets DL est le standard absolu de la plaquette commerciale : six faces pour tout dire, un format qui entre dans une enveloppe DL et dans tous les présentoirs. Efficace, économique, universellement lisible.', '["6 faces pour un argumentaire complet et hiérarchisé", "Format fermé DL : compatible enveloppes et présentoirs", "Pli roulé : effet de découverte volet après volet", "Coût proche d''un simple flyer A4", "Livré plié, prêt pour mailing ou distribution", "Le format le plus attendu et le plus lisible en B2B"]'::jsonb, '["Plaquette commerciale de PME", "Présentation de services en salon", "Documentation en présentoir d''accueil", "Mailing postal sous enveloppe DL", "Menu ou carte de prestations"]'::jsonb,
  '[{"title": "Cabinet de services", "description": "Plaquette 3 volets : promesse en couverture, trois offres sur les trois volets intérieurs, équipe et contact au dos."}, {"title": "Salon professionnel", "description": "Distribué sur le stand, le DL se glisse dans les sacoches visiteurs et survit au tri de retour de salon."}, {"title": "Collectivité", "description": "Guide des démarches plié en 3 volets, disposé dans les présentoirs de la mairie et des maisons de services."}, {"title": "Mailing B2B", "description": "Envoi postal sous enveloppe DL à fenêtre : le dépliant sert de courrier ET de plaquette, un seul document, un seul coût."}]'::jsonb, '[{"question": "Pli roulé ou accordéon ?", "answer": "Roulé pour un effet de découverte progressive (attention : volet rentrant réduit à ~97 mm) ; accordéon pour trois volets égaux et une lecture en séquence."}, {"question": "Comment préparer le fichier ?", "answer": "PDF au format A4 ouvert recto/verso avec 3 mm de fonds perdus, monté selon le gabarit du pliage choisi — l''ordre des faces diffère entre roulé et accordéon."}, {"question": "Quel grammage choisir ?", "answer": "130-170 g pour la distribution et le mailing ; 250-350 g rainé pour une plaquette haut de gamme qui tient en présentoir."}, {"question": "Entre-t-il dans une enveloppe standard ?", "answer": "Oui, le format fermé 100 × 210 mm entre dans une enveloppe DL (110 × 220 mm), avec ou sans fenêtre."}, {"question": "Quantité minimale et paliers ?", "answer": "Dès 50 exemplaires ; les paliers 500, 1 000 et 2 500 offrent les meilleures économies d''échelle."}]'::jsonb, '{"formats": ["ouvert 210 × 297 mm (A4)", "fermé 100 × 210 mm (DL)", "volet rentrant ~97 mm en pli roulé"], "supports": ["couché demi-mat 130-350 g", "couché brillant 130-350 g", "offset 90-120 g", "recyclé 115-170 g"], "finitions": ["sans finition", "pelliculage (grammages épais)", "vernis sélectif", "rainage dès 170 g"], "impression": "quadri recto/verso (6 faces)", "quantites": "50 → 100 000 ex., paliers 100/250/500/1000/2500/5000", "delais": "standard 48-72 h, express possible", "options": ["pli roulé ou pli accordéon", "livré plié", "multi-visuels"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── affiche_40x60 : Affiche 40×60 cm ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'affiche_40x60', '{}'::jsonb, 'fr', 'Affiche 40 × 60 cm', array['affiche 40x60','poster 40x60','affiche vitrine','affiche point de vente','affiche commerce','affiche événement','poster commerce','affiche 400x600','impression affiche','affiche promotionnelle']::text[],
  'Affiche 40 × 60 cm {{papier}} {{grammage}} — {{quantite}} ex.', 'Affiche 40 × 60 cm imprimée en quadri sur {{papier}} {{grammage}}. Le format vitrine par excellence : visible de loin, facile à poser partout.',
  '## Présentation

Le 40 × 60 cm est le format d''affiche le plus polyvalent du point de vente : assez grand pour être lu à plusieurs mètres, assez compact pour trouver sa place en vitrine, sur une porte ou dans un cadre standard. C''est le format des promotions de commerce, des annonces d''événements locaux et de la décoration murale.

## Caractéristiques techniques

Format 400 × 600 mm, impression quadrichromie recto (recto/verso possible pour affichage suspendu). Papiers : couché demi-mat ou brillant 130-170 g pour l''usage courant, offset 90-120 g pour l''économie, papier fluo pour les promotions choc, recyclé pour l''image responsable. Vernis 2D possible pour intensifier les couleurs.

## Avantages

Compatible avec les cadres, porte-affiches et stop-trottoirs 40 × 60 du commerce, il se remplace en quelques secondes au rythme de vos opérations. Impression dès l''unité : testez un visuel, puis rééditez en série pour un réseau de points de vente.', 'Affiche 40 × 60 cm {{papier}} {{grammage}}',
  'Affiche 40x60 cm — impression poster vitrine', 'Affiches 40×60 cm pour vitrines, commerces et événements : couché 130-170 g, fluo ou recyclé, quadri HD. Impression dès 1 exemplaire, délais courts.', array['affiche 40x60','poster 40x60 cm','affiche vitrine','impression affiche','affiche commerce','affiche promotionnelle','affiche événement','porte-affiche 40x60']::text[], 'Product',
  'Le 40×60 est le format que tous les cadres, vitrines et stop-trottoirs attendent : changez d''affiche au rythme de vos promos, sans changer de support. Visible de loin, remplacé en dix secondes.', '["Compatible cadres, porte-affiches et stop-trottoirs standards", "Lisible à plusieurs mètres : idéal vitrine", "Impression dès 1 exemplaire pour tester un visuel", "Papier fluo disponible pour les promotions choc", "Coût maîtrisé pour un renouvellement fréquent", "Déclinable en série homogène pour un réseau de magasins"]'::jsonb, '["Promotion en vitrine de commerce", "Annonce de concert ou spectacle local", "Affichage en salle d''attente", "Décoration murale encadrée", "Signalétique temporaire d''événement"]'::jsonb,
  '[{"title": "Commerce de détail", "description": "Soldes, nouveautés, horaires exceptionnels : l''affiche 40×60 en vitrine se renouvelle à chaque opération commerciale."}, {"title": "Culture locale", "description": "Une salle de concert imprime 50 affiches par date, posées chez les commerçants partenaires de la ville."}, {"title": "Réseau de franchises", "description": "Campagne nationale déclinée en 40×60 : chaque point de vente reçoit son lot, l''image de marque reste homogène."}, {"title": "Décoration", "description": "Visuels photographiques imprimés en 40×60 sur papier mat, encadrés pour habiller un restaurant ou des bureaux."}]'::jsonb, '[{"question": "Quel fichier fournir ?", "answer": "PDF en CMJN à l''échelle 1 (400 × 600 mm) avec 3-5 mm de fonds perdus ; 150-300 dpi suffisent à cette taille de lecture."}, {"question": "Quel papier pour une vitrine ?", "answer": "Couché demi-mat 170 g : couleurs profondes sans reflets gênants derrière une vitre. Le brillant convient aux visuels photo très saturés."}, {"question": "L''affiche résiste-t-elle en extérieur ?", "answer": "Le papier standard convient à un affichage extérieur court et abrité ; pour l''extérieur durable, optez pour un support dédié (dos bleu, encapsulage)."}, {"question": "Puis-je commander une seule affiche ?", "answer": "Oui, l''impression démarre à l''unité — pratique pour valider un visuel avant la série."}, {"question": "Fonds perdus nécessaires ?", "answer": "Oui, 3 à 5 mm sur chaque bord, avec les textes à 10 mm minimum de la coupe."}]'::jsonb, '{"formats": ["400 × 600 mm"], "supports": ["couché demi-mat 130-170 g", "couché brillant 130-170 g", "offset 90-120 g", "recyclé satin 115 g", "papier fluo (jaune, orange, vert)"], "finitions": ["sans finition", "vernis 2D recto", "encapsulage en option"], "impression": "quadri recto (recto/verso possible)", "quantites": "1 → 20 000 ex., paliers 1/5/10/25/50/100/250", "delais": "standard 24-72 h, express possible", "options": ["qualité standard ou haute définition", "pli central optionnel pour expédition", "livraison roulée"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── affiche_abribus : Affiche abribus 120×176 cm ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'affiche_abribus', '{}'::jsonb, 'fr', 'Affiche abribus 120 × 176 cm', array['affiche abribus','affiche 120x176','affichage urbain','mobilier urbain','affiche sucette','affichage 2m2','campagne d''affichage','affiche grand format','affiche réseau','impression affiche abribus']::text[],
  'Affiche abribus 120 × 176 cm {{papier}} — {{quantite}} ex.', 'Affiche 120 × 176 cm au format normalisé des abribus et sucettes de mobilier urbain, imprimée en quadri HD sur {{papier}}. Prête pour vos campagnes d''affichage.',
  '## Présentation

Le 120 × 176 cm est le format normalisé du mobilier urbain français : abribus, sucettes de centre-ville, caissons de galeries commerçantes et de stations de transport. C''est le format des campagnes locales qui veulent exister dans la rue, face aux grandes enseignes, avec une surface d''expression d''environ 2 m².

## Caractéristiques techniques

Format 1200 × 1760 mm, orientation portrait, impression quadrichromie recto en qualité standard ou haute définition. Papiers dédiés à l''affichage : 120 g dos bleu (verso bleu opacifiant, indispensable en caisson rétroéclairé et en recouvrement d''affiches précédentes), couché demi-mat 135 g ou 150 g. Livraison roulée.

## Avantages

Un fichier, un réseau : la même création se décline sur toutes les faces d''une campagne locale. Le dos bleu garantit l''opacité exigée par les afficheurs, et la haute définition supporte la lecture rapprochée des piétons à l''arrêt de bus — là où l''affiche est réellement lue.', 'Affiche abribus 120 × 176 cm {{papier}}',
  'Affiche abribus 120x176 cm — affichage urbain', 'Affiches abribus 120×176 cm au format normalisé du mobilier urbain : dos bleu 120 g ou couché 135-150 g, quadri HD. Campagnes locales, livrées roulées.', array['affiche abribus','affiche 120x176','affichage urbain','sucette publicitaire','mobilier urbain','campagne affichage','affiche 2m2','dos bleu']::text[], 'Product',
  'L''abribus est le média des marques qui comptent dans leur ville : 2 m² de visibilité aux arrêts où votre public attend, regarde et lit. Au format normalisé 120×176, votre affiche entre dans tous les réseaux de mobilier urbain.', '["Format normalisé accepté par tous les réseaux d''affichage urbain", "≈2 m² de surface : impact publicitaire majeur", "Dos bleu opacifiant : conforme aux exigences des afficheurs", "Qualité HD pour la lecture rapprochée des piétons", "Audience captive aux arrêts de transport", "Petites séries possibles pour campagnes locales ciblées"]'::jsonb, '["Campagne d''affichage de centre-ville", "Lancement d''enseigne locale", "Promotion d''événement culturel ou sportif", "Communication de collectivité", "Caisson lumineux de galerie commerciale"]'::jsonb,
  '[{"title": "Ouverture de magasin", "description": "Dix faces d''abribus autour de la zone de chalandise annoncent l''ouverture : notoriété locale immédiate pendant deux semaines."}, {"title": "Festival", "description": "La programmation s''affiche en 120×176 dans les sucettes de la ville, relayée par les mêmes visuels en 40×60 chez les commerçants."}, {"title": "Collectivité", "description": "Campagne de sensibilisation municipale déployée sur le réseau d''abribus : le format du service public par excellence."}, {"title": "Promoteur immobilier", "description": "Le programme neuf s''affiche en caisson rétroéclairé face à la gare : dos bleu obligatoire pour une diffusion homogène de la lumière."}]'::jsonb, '[{"question": "Quel fichier fournir ?", "answer": "PDF en CMJN à l''échelle 1 (1200 × 1760 mm) ou à l''échelle 1/2 en 300 dpi, avec 5 mm de fonds perdus ; suivez le gabarit de l''afficheur pour les zones masquées par le cadre."}, {"question": "Pourquoi choisir le dos bleu ?", "answer": "Son verso bleu bloque la transparence : l''affiche précédente ne transparaît pas et la lumière des caissons diffuse uniformément. C''est le standard exigé par la plupart des réseaux."}, {"question": "Quelle quantité commander ?", "answer": "Comptez le nombre de faces réservées + 10-15 % de réserve pour remplacement en cas de dégradation pendant la campagne."}, {"question": "L''affiche résiste-t-elle à la pluie ?", "answer": "Posée en caisson d''abribus, elle est protégée ; les papiers d''affichage tolèrent l''humidité de pose (colle) mais ne sont pas prévus pour une exposition nue prolongée."}, {"question": "Comment est-elle livrée ?", "answer": "Roulée dans un emballage renforcé, jamais pliée, pour une pose sans marque."}]'::jsonb, '{"formats": ["1200 × 1760 mm (abribus normalisé)", "variantes mobilier urbain : 1200 × 1600 mm, 800 × 1200 mm"], "supports": ["papier dos bleu 120 g", "couché demi-mat 135 g", "couché demi-mat 150 g"], "finitions": ["sans finition (pose en caisson)"], "impression": "quadri recto, qualité standard ou haute définition", "quantites": "1 → 500 ex., paliers 1/5/10/25/50/100", "delais": "standard 48-96 h, express possible", "options": ["livraison roulée", "épreuve de validation sur demande"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── affiche_dos_bleu : Affiche dos bleu ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'affiche_dos_bleu', '{}'::jsonb, 'fr', 'Affiche dos bleu (affichage urbain)', array['affiche dos bleu','papier dos bleu','affichage extérieur','affiche colleur','affichage sauvage','affiche opaque','blue back','affiche 120g','campagne affichage','affiche panneau']::text[],
  'Affiche dos bleu 120 g — {{quantite}} ex. — format {{papier}}', 'Affiche sur papier dos bleu 120 g, le support professionnel de l''affichage extérieur : verso bleu opacifiant, encollage facile, aucune transparence sur les couches précédentes.',
  '## Présentation

Le papier dos bleu est le standard historique de l''affichage urbain : son verso teinté bleu rend l''affiche totalement opaque, même collée par-dessus d''anciennes affiches ou posée en caisson lumineux. C''est le support des colleurs professionnels, des panneaux de réseau et des campagnes d''affichage extérieur.

## Caractéristiques techniques

Papier 120 g spécialement conçu pour l''encollage : il se tend à la pose, résiste à l''humidité de la colle et ne gondole pas. Impression quadrichromie recto, qualité standard ou haute définition. Tous formats d''affichage : du 60 × 80 cm au 120 × 176 cm abribus, jusqu''aux grands panneaux en lés multiples (4 × 3 m et au-delà). Livraison roulée.

## Avantages

Opacité garantie quel que soit le support de pose, comportement maîtrisé à la colle, rendu homogène en caisson rétroéclairé : le dos bleu évite les mauvaises surprises des papiers standards en extérieur. C''est le choix par défaut de tout affichage confié à un réseau ou à un colleur.', 'Affiche dos bleu 120 g — affichage extérieur professionnel',
  'Affiche dos bleu 120 g — affichage extérieur pro', 'Affiches papier dos bleu 120 g : opacité totale, encollage facile, tous formats du 60×80 au panneau 4×3 m. Le standard de l''affichage urbain.', array['affiche dos bleu','papier dos bleu','blue back','affichage extérieur','affiche colleur','affiche panneau 4x3','campagne affichage urbain','affiche opaque']::text[], 'Product',
  'Une affiche collée sur une autre affiche ne doit rien laisser transparaître : c''est exactement ce que garantit le dos bleu. Le papier des professionnels de l''affichage, pour des campagnes extérieures nettes du premier au dernier jour.', '["Opacité totale : aucune transparence des couches précédentes", "Conçu pour l''encollage : se tend et ne gondole pas", "Compatible caissons rétroéclairés (diffusion homogène)", "Tous formats, du 60×80 aux panneaux en lés multiples", "Standard accepté par les réseaux et colleurs professionnels", "Bonne tenue en extérieur pendant la durée de campagne"]'::jsonb, '["Campagne sur panneaux d''affichage réseau", "Affichage culturel (concerts, spectacles)", "Panneaux de chantier immobilier", "Affichage en caisson lumineux", "Affichage événementiel grande diffusion"]'::jsonb,
  '[{"title": "Production de spectacles", "description": "Tournée annoncée ville par ville : les affiches dos bleu partent chez les colleurs locaux, la pose est propre même sur des panneaux saturés."}, {"title": "Réseau d''affichage", "description": "Campagne 4×3 en lés multiples : le dos bleu assure des raccords invisibles et une opacité constante sur toute la surface."}, {"title": "Promoteur", "description": "Palissade de chantier habillée d''affiches dos bleu grand format, remplacées à chaque phase de commercialisation."}, {"title": "Cinéma", "description": "Affiches de sortie posées en caissons lumineux de hall : la lumière diffuse sans zone claire ni ombre de l''affiche précédente."}]'::jsonb, '[{"question": "Pourquoi le verso est-il bleu ?", "answer": "La teinte bleue bloque la lumière et masque totalement ce qui se trouve derrière l''affiche : anciennes affiches, raccords de lés ou source lumineuse d''un caisson."}, {"question": "Quels formats sont disponibles ?", "answer": "Tous les formats d''affichage : 60×80, 80×120, 120×160, 120×176 cm, et les grands panneaux (320×240 cm, 4×3 m) livrés en plusieurs lés à raccorder."}, {"question": "Se pose-t-elle avec quelle colle ?", "answer": "Colle à papier peint ou colle d''affichage classique : le papier 120 g est étudié pour se tendre à l''encollage sans se déchirer."}, {"question": "Quelle durée de vie en extérieur ?", "answer": "La durée d''une campagne d''affichage classique (2 à 8 semaines selon exposition) ; ce n''est pas un support permanent."}, {"question": "Quel fichier fournir ?", "answer": "PDF CMJN à l''échelle 1 ou 1/2, 5 mm de fonds perdus ; pour les panneaux en lés, le découpage est réalisé en interne à partir de votre visuel complet."}]'::jsonb, '{"formats": ["600 × 800 mm", "800 × 1200 mm", "1200 × 1600 mm", "1200 × 1760 mm", "3200 × 2400 mm et 4 × 3 m en lés multiples", "sur mesure"], "supports": ["papier dos bleu (blue back) 120 g"], "finitions": ["sans finition (support d''encollage)"], "impression": "quadri recto, qualité standard ou haute définition", "quantites": "1 → 2 000 ex., paliers 1/5/10/25/50/100/250", "delais": "standard 48-96 h, express possible", "options": ["découpe en lés pour grands panneaux", "livraison roulée", "réserve de remplacement conseillée"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── papeterie : Papeterie commerciale ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'papeterie', '{}'::jsonb, 'fr', 'Papeterie commerciale et administrative', array['papeterie entreprise','papeterie commerciale','papier en-tête','enveloppe personnalisée','chemise à rabats','bloc-notes','carnet autocopiant','fournitures imprimées','identité visuelle','documents administratifs']::text[],
  'Papeterie commerciale personnalisée — {{quantite}} exemplaires', 'Toute la papeterie de votre entreprise à vos couleurs : têtes de lettre, enveloppes, chemises, blocs et carnets, imprimés sur {{papier}} {{grammage}}.',
  '## Une papeterie à l''image de votre entreprise

La papeterie commerciale regroupe tous les imprimés du quotidien administratif : papier à en-tête, enveloppes, chemises à rabats, blocs-notes, carnets autocopiants et sous-mains. Chaque document qui sort de vos bureaux porte votre identité visuelle et travaille pour votre image.

## Caractéristiques techniques

Chaque famille dispose de ses standards : offset 80 à 100 g pour les documents à écrire ou imprimer, couché 250 à 350 g pour les chemises et cartes, papier autocopiant 60 g pour les liasses. Formats normalisés A4, A5, DL, C4/C5/C6 selon l''usage. Impression quadri recto ou recto/verso, options recyclées disponibles sur l''ensemble de la gamme.

## Les avantages d''une gamme coordonnée

Commander l''ensemble de sa papeterie au même endroit garantit une cohérence parfaite : mêmes teintes, mêmes papiers, même niveau de finition. Vous gagnez du temps sur les réassorts et présentez une image professionnelle homogène, du courrier au dossier commercial remis en main propre.', 'Papeterie commerciale personnalisée pour votre entreprise',
  'Papeterie commerciale personnalisée | Imprimerie pro', 'Papier en-tête, enveloppes, chemises, blocs-notes et carnets à vos couleurs. Papeterie d''entreprise imprimée en qualité professionnelle, petites et grandes séries.', array['papeterie entreprise','papeterie commerciale personnalisée','imprimés administratifs','papier en-tête','enveloppe logo','chemise commerciale','identité visuelle papier']::text[], 'Product',
  'Chaque courrier, chaque dossier, chaque note manuscrite devient un support de votre marque. Une papeterie coordonnée crédibilise votre entreprise à moindre coût, document après document.', '["Image professionnelle cohérente sur tous vos documents", "Formats et papiers normalisés, compatibles avec vos usages bureau", "Petites séries possibles pour les TPE et artisans", "Options papiers recyclés sur toute la gamme", "Réassort simple : mêmes références, même rendu", "Un seul interlocuteur pour toute votre papeterie"]'::jsonb, '["Kit papeterie de création d''entreprise", "Réassort annuel des services administratifs", "Harmonisation après changement de logo", "Dotation papeterie multi-agences", "Dossiers commerciaux et courriers officiels"]'::jsonb,
  '[{"title": "Lancement d''activité", "description": "Un artisan qui s''installe commande en-têtes, enveloppes et carnets de devis assortis pour démarrer avec une image pro dès le premier client."}, {"title": "Refonte d''identité", "description": "Une PME qui change de logo renouvelle toute sa papeterie en une commande pour éviter la cohabitation d''anciens et nouveaux visuels."}, {"title": "Réseau multi-sites", "description": "Un groupe décline la même papeterie pour chaque agence, avec les coordonnées locales adaptées sur chaque référence."}, {"title": "Cabinet de conseil", "description": "Un cabinet équipe ses consultants de chemises, blocs et cartes coordonnés pour les rendez-vous clients et les soutenances."}]'::jsonb, '[{"question": "Puis-je commander plusieurs produits avec le même visuel ?", "answer": "Oui, c''est même recommandé : nous déclinons votre charte graphique sur chaque format en conservant couleurs et typographies pour un rendu homogène."}, {"question": "Quels fichiers fournir ?", "answer": "Un PDF haute définition (300 dpi) en CMJN avec 2 à 3 mm de fonds perdus par produit. Nous contrôlons chaque fichier avant impression."}, {"question": "Existe-t-il des versions écologiques ?", "answer": "Oui, chaque famille propose une variante en papier 100 % recyclé ou certifié issu de forêts gérées durablement."}, {"question": "Quel est le minimum de commande ?", "answer": "Les minimums varient selon le produit : dès quelques dizaines d''exemplaires pour les chemises ou blocs, quelques centaines pour les enveloppes et en-têtes."}, {"question": "Quels sont les délais de fabrication ?", "answer": "Comptez en standard 48 à 72 h pour les imprimés simples et jusqu''à une à deux semaines pour les produits façonnés (carnets, calendriers rigides). Des options express existent."}]'::jsonb, '{"formats": ["A4 210 × 297 mm", "A5 148 × 210 mm", "DL 110 × 220 mm", "C4 229 × 324 mm", "C5 162 × 229 mm", "C6 114 × 162 mm"], "supports": ["offset blanc 80-100 g", "offset recyclé 80-90 g", "couché demi-mat ou brillant 250-350 g", "autocopiant 60 g"], "finitions": ["pelliculage mat, brillant ou soft touch", "rainage", "encollage", "numérotation", "perforation"], "impression": "quadri recto ou recto/verso, Pantone possible selon produit", "quantites": "de 10 à 50 000 exemplaires selon la famille de produit", "delais": "standard 48-72 h pour les imprimés à plat, 5 à 10 jours ouvrés pour les produits façonnés, express possible", "options": ["papiers recyclés", "gabarits fournis", "contrôle de fichiers inclus", "déclinaisons multi-sites"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── tete_lettre : Tête de lettre / Papier en-tête ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'tete_lettre', '{}'::jsonb, 'fr', 'Tête de lettre - papier à en-tête personnalisé', array['tête de lettre','papier à en-tête','papier en-tête entreprise','papier à lettre personnalisé','courrier commercial','en-tête A4','papier filigrané','letterhead','papier offset 90g','papier courrier professionnel']::text[],
  'Tête de lettre A4 {{papier}} {{grammage}} — {{quantite}} exemplaires', 'Papier à en-tête A4 imprimé sur {{papier}} {{grammage}}, compatible avec vos imprimantes laser et jet d''encre. La base de toute correspondance professionnelle.',
  '## Votre identité sur chaque courrier

La tête de lettre est le premier support d''identité d''une entreprise : devis, factures, courriers officiels et attestations partent tous sur ce papier. Logo, coordonnées, mentions légales et éléments graphiques y sont imprimés une fois pour toutes — il ne reste qu''à imprimer ou écrire le contenu.

## Caractéristiques techniques

Format A4 (210 × 297 mm), imprimé en quadri recto ou recto/verso sur offset 90 g garanti compatible imprimantes laser et jet d''encre. Variantes disponibles : offset 100 % recyclé 80 g pour une démarche responsable, ou papier filigrané 100 g pour les documents à forte valeur (actes, attestations, cabinets réglementés). Impression en tons directs possible pour un respect strict de votre charte.

## Les avantages au quotidien

Un en-tête pré-imprimé offre un rendu bien supérieur à une impression bureautique du logo : couleurs fidèles, aplats nets, papier de meilleure tenue. Vous standardisez vos documents sortants, gagnez du temps à chaque courrier et donnez du poids à vos devis et factures.', 'Papier à en-tête A4 personnalisé {{papier}} {{grammage}}',
  'Papier à en-tête personnalisé A4 | Impression pro', 'Tête de lettre A4 imprimée à vos couleurs sur offset 80-100 g compatible laser. Devis, factures et courriers avec une vraie image professionnelle.', array['papier à en-tête','tête de lettre personnalisée','papier en-tête A4','en-tête entreprise','papier courrier professionnel','impression en-tête','papier filigrané entreprise']::text[], 'Product',
  'Un devis envoyé sur un vrai papier à en-tête inspire immédiatement confiance. Pour quelques centimes par feuille, chacun de vos courriers travaille votre crédibilité.', '["Compatible imprimantes laser et jet d''encre du bureau", "Couleurs fidèles à votre charte, bien au-delà d''une impression bureautique", "Version filigranée pour les documents officiels", "Option 100 % recyclé sans surcoût prohibitif", "Tarif unitaire dégressif dès quelques centaines de feuilles", "Uniformise devis, factures et courriers de toute l''équipe"]'::jsonb, '["Devis et factures d''artisans", "Courriers officiels de collectivités", "Attestations de cabinets réglementés", "Correspondance commerciale de PME", "Ordonnances et documents de praticiens"]'::jsonb,
  '[{"title": "Artisan du bâtiment", "description": "Ses devis partent sur en-tête imprimé avec logo, assurance décennale et SIRET : plus rien à ressaisir, une image nette face aux concurrents."}, {"title": "Cabinet comptable", "description": "Lettres de mission et attestations sur papier filigrané 100 g : la texture et le filigrane signalent un document authentique."}, {"title": "Mairie", "description": "Courriers administratifs sur en-tête aux armoiries de la commune, imprimés en grande série pour tous les services."}, {"title": "Start-up B2B", "description": "Propositions commerciales imprimées sur en-tête recyclé, aligné avec le discours RSE porté auprès des clients."}]'::jsonb, '[{"question": "Le papier passe-t-il dans mon imprimante laser ?", "answer": "Oui, l''offset 90 g est conçu pour supporter la chaleur des fours laser sans transfert d''encre. C''est le grammage recommandé pour un usage bureautique quotidien."}, {"question": "Quel grammage choisir ?", "answer": "90 g pour l''usage courant, 80 g recyclé pour les gros volumes économiques, 100 g filigrané pour les documents à valeur officielle ou l''image haut de gamme."}, {"question": "Puis-je imprimer le verso ?", "answer": "Oui : conditions générales de vente, mentions légales ou informations pratiques au verso évitent une seconde feuille dans vos envois."}, {"question": "Quel fichier fournir ?", "answer": "Un PDF 300 dpi en CMJN au format A4 avec 3 mm de fonds perdus si votre visuel touche les bords. Pensez à laisser la zone centrale libre pour le contenu."}, {"question": "Peut-on respecter un Pantone précis ?", "answer": "Oui, l''impression en tons directs est possible pour reproduire exactement la couleur de votre charte, notamment sur l''offset 90 g."}]'::jsonb, '{"formats": ["A4 210 × 297 mm", "sur-mesure possible"], "supports": ["offset blanc 90 g compatible laser", "offset 100 % recyclé 80 g", "papier filigrané blanc 100 g", "filigrané recyclé 100 g"], "finitions": ["pré-découpe optionnelle", "impression tons directs"], "impression": "quadri recto, quadri recto/verso, quadri + noir verso, 1 à 2 tons directs", "quantites": "de 250 à 500 000 exemplaires, paliers dégressifs", "delais": "standard 48-72 h, express possible", "options": ["verso CGV", "version recyclée", "version filigranée", "déclinaisons multi-entités"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── enveloppe : Enveloppe personnalisée ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'enveloppe', '{}'::jsonb, 'fr', 'Enveloppe personnalisée entreprise', array['enveloppe personnalisée','enveloppe DL','enveloppe C4','enveloppe C5','enveloppe C6','enveloppe à fenêtre','enveloppe logo','enveloppe mécanisable','enveloppe entreprise','enveloppe imprimée','enveloppe patte pointue']::text[],
  'Enveloppe {{papier}} {{grammage}} personnalisée — {{quantite}} exemplaires', 'Enveloppes DL, C6, C5 ou C4 imprimées à vos couleurs, avec ou sans fenêtre, sur {{papier}} {{grammage}}. Votre marque visible avant même l''ouverture du courrier.',
  '## L''enveloppe qui annonce l''expéditeur

Une enveloppe imprimée à votre logo identifie immédiatement votre courrier dans la pile du destinataire et augmente ses chances d''être ouvert en premier. C''est aussi la garantie de ne jamais être à court d''enveloppes correctes au bureau.

## Caractéristiques techniques

Cinq formats couvrent tous les usages : 90 × 140 mm (cartes), DL 110 × 220 mm (courrier plié en trois), C6 114 × 162 mm (A6), C5 162 × 229 mm (A5 ou A4 plié en deux) et C4 229 × 324 mm (A4 à plat). Fenêtre cristal d''origine végétale disponible en 35 × 100, 45 × 100 ou 50 × 100 mm selon le format. Fermeture par bande autocollante avec protection, ou patte gommée pointue sur le petit format. Papiers offset vélin 90 g, 100 % recyclé 90 g ou offset renforcé 100 g.

## Les avantages

Avec la fenêtre, l''adresse imprimée sur le document apparaît directement : plus d''étiquettes ni de double saisie. Les versions mécanisables passent en machine de mise sous pli pour vos campagnes volumineuses.', 'Enveloppes personnalisées {{papier}} {{grammage}} avec ou sans fenêtre',
  'Enveloppe personnalisée DL, C4, C5, C6 | Impression', 'Enveloppes imprimées à votre logo : DL, C6, C5, C4, avec ou sans fenêtre, papier blanc ou recyclé. Identifiez votre courrier dès la boîte aux lettres.', array['enveloppe personnalisée','enveloppe DL fenêtre','enveloppe C4 imprimée','enveloppe entreprise logo','enveloppe recyclée','impression enveloppe','enveloppe mécanisable']::text[], 'Product',
  'Votre courrier ne finit plus au fond de la pile : une enveloppe à votre logo est identifiée et ouverte en priorité. Un support publicitaire que le destinataire tient forcément entre les mains.', '["Courrier identifié dès la boîte aux lettres", "Fenêtre cristal : adresse imprimée sur le document, zéro étiquette", "Cinq formats normalisés pour tous les contenus", "Version 100 % recyclée avec fenêtre d''origine végétale", "Compatible machines de mise sous pli (mécanisable)", "Panachage avec/sans fenêtre possible sur une même commande"]'::jsonb, '["Facturation mensuelle en DL fenêtre", "Envoi de dossiers A4 en C4", "Courriers officiels de collectivités", "Mailings commerciaux identifiés", "Cartes de vœux en petit format"]'::jsonb,
  '[{"title": "Service facturation", "description": "Les factures partent en DL à fenêtre : l''adresse imprimée sur la facture apparaît dans la fenêtre, la mise sous pli prend quelques secondes."}, {"title": "Cabinet immobilier", "description": "Les dossiers de vente et diagnostics partent à plat en C4 personnalisé, sans pliure, avec une image soignée."}, {"title": "Collectivité", "description": "La mairie panache C5 avec et sans fenêtre dans la même commande pour couvrir convocations et courriers libres."}, {"title": "Campagne fidélité", "description": "Un commerce envoie ses offres dans une enveloppe colorée à son logo : le taux d''ouverture grimpe par rapport à une enveloppe blanche anonyme."}]'::jsonb, '[{"question": "Quel format pour un courrier A4 ?", "answer": "DL pour un A4 plié en trois, C5 pour un A4 plié en deux, C4 pour un A4 non plié. Le C6 convient aux cartes et petits formats."}, {"question": "Où se situe la fenêtre ?", "answer": "La fenêtre est positionnée à droite, aux dimensions normalisées (35, 45 ou 50 × 100 mm selon le format), compatible avec les zones d''adressage standard des documents."}, {"question": "Les enveloppes passent-elles en machine à affranchir et mise sous pli ?", "answer": "Oui, les versions mécanisables sont conçues pour les machines de mise sous pli et respectent les normes postales d''affranchissement."}, {"question": "La fenêtre est-elle recyclable ?", "answer": "Oui, la fenêtre cristal est fabriquée à partir d''amidon végétal et l''ensemble se recycle avec le papier."}, {"question": "Peut-on commander sans impression ?", "answer": "Oui, les enveloppes sont aussi disponibles vierges, utile pour compléter un stock ou tester un format avant personnalisation."}]'::jsonb, '{"formats": ["90 × 140 mm", "DL 110 × 220 mm", "C6 114 × 162 mm", "C5 162 × 229 mm", "C4 229 × 324 mm"], "supports": ["offset vélin blanc 90 g", "offset 100 % recyclé 90 g", "offset blanc renforcé 100 g"], "finitions": ["fenêtre cristal végétale 35/45/50 × 100 mm", "bande autocollante avec protection", "patte gommée pointue (90 × 140)"], "impression": "quadri recto, noir, 1-2 tons directs, recto/verso ou sans impression", "quantites": "de 100 à 50 000 exemplaires, nombreux paliers dégressifs", "delais": "standard 48-72 h, express possible", "options": ["avec ou sans fenêtre", "panachage fenêtre/sans fenêtre", "version mécanisable", "enveloppes couleur"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── chemise_rabats : Chemise à rabats ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'chemise_rabats', '{}'::jsonb, 'fr', 'Chemise à rabats personnalisée', array['chemise à rabats','pochette à rabats','porte-documents','chemise commerciale A4','pochette entreprise','chemise cartonnée','chemise encoche carte de visite','dossier commercial','pochette dossier','chemise 350g']::text[],
  'Chemise à rabats A4 {{papier}} {{grammage}} {{finition}} — {{quantite}} exemplaires', 'Chemise à rabats A4 en carte {{grammage}} avec rainage renforcé et encoche carte de visite. Le dossier commercial qui reste sur le bureau de vos prospects.',
  '## Le porte-documents de vos rendez-vous

La chemise à rabats habille tout ce que vous remettez en main propre : devis, contrats, plaquettes, dossiers de presse. Deux rabats intérieurs maintiennent les documents, une encoche accueille votre carte de visite — le prospect repart avec un dossier complet à votre image.

## Caractéristiques techniques

Format A4 fermé (existe en A5, 3 volets, version à fenêtre ou à l''italienne), imprimé en quadri sur carte couchée 350 g demi-mat, brillant ou recyclé satin. Rainage simple pour les dossiers fins, double rainage 5 mm pour les dossiers épais. Encoche carte de visite verticale ou horizontale. Livrée rainée à plat pour un stockage compact, montage en quelques secondes.

## Les avantages

Le pelliculage mat, brillant ou soft touch protège la chemise des manipulations et renforce la perception haut de gamme. Pour les grandes occasions, vernis sélectif et dorure à chaud transforment la pochette en objet premium. Disponible dès quelques dizaines d''exemplaires : chaque commercial peut avoir son stock.', 'Chemise à rabats personnalisée {{grammage}} {{finition}}',
  'Chemise à rabats A4 personnalisée 350 g | Imprimerie', 'Chemises à rabats A4 en carte 350 g, encoche carte de visite, dos 5 mm, pelliculage mat ou soft touch. Vos dossiers commerciaux à votre image dès 25 ex.', array['chemise à rabats personnalisée','pochette à rabats A4','porte-documents entreprise','chemise commerciale','pochette dossier 350g','chemise carte de visite','dossier commercial imprimé']::text[], 'Product',
  'Un devis remis dans une chemise à vos couleurs ne se perd pas dans une pile : il reste visible sur le bureau du décideur. C''est l''outil de closing le moins cher de votre panoplie commerciale.', '["Dossiers remis en main propre immédiatement identifiés", "Encoche intégrée : votre carte de visite toujours jointe", "Double rainage 5 mm pour les dossiers épais", "Carte 350 g rigide, tenue irréprochable en rendez-vous", "Livrée à plat : stockage compact, montage instantané", "Petites séries dès quelques dizaines d''exemplaires"]'::jsonb, '["Remise de devis et contrats", "Kits d''accueil salon professionnel", "Dossiers de presse et de candidature", "Pochettes d''accueil nouveaux clients", "Dossiers de location immobilière"]'::jsonb,
  '[{"title": "Concession automobile", "description": "Chaque acheteur repart avec carte grise provisoire, contrat et garanties dans une chemise pelliculée soft touch aux couleurs de la marque."}, {"title": "Agence web", "description": "Les propositions commerciales sont remises dans une chemise à vernis sélectif : le logo brille en relief, le dossier marque les esprits."}, {"title": "Salon professionnel", "description": "L''exposant prépare des chemises 3 volets avec plaquette, tarifs et carte de visite en encoche, distribuées aux visiteurs qualifiés."}, {"title": "Expert-comptable", "description": "Bilans et liasses fiscales remis en chemise double rainage 5 mm : le dossier épais tient parfaitement, l''image est soignée."}]'::jsonb, '[{"question": "Simple ou double rainage : comment choisir ?", "answer": "Le rainage simple convient jusqu''à une dizaine de feuilles. Au-delà, le double rainage crée un dos de 5 mm qui absorbe les dossiers épais sans déformer la chemise."}, {"question": "L''encoche carte de visite est-elle compatible avec tous les formats de carte ?", "answer": "Oui, l''encoche verticale ou horizontale est dimensionnée pour la carte de visite standard 85 × 54 mm."}, {"question": "La chemise arrive-t-elle montée ?", "answer": "Non, elle est livrée rainée à plat pour un transport et un stockage compacts. Le pliage se fait en quelques secondes, sans collage."}, {"question": "Quel fichier fournir ?", "answer": "Un PDF au gabarit de découpe fourni (tracé de découpe et rainage sur un calque dédié), 300 dpi CMJN, fonds perdus 3 mm. Nous vérifions le fichier avant impression."}, {"question": "Quelle finition pour un rendu haut de gamme ?", "answer": "Le pelliculage soft touch donne un toucher peau de pêche très premium ; ajoutez un vernis sélectif ou une dorure à chaud sur le logo pour un effet maximal."}]'::jsonb, '{"formats": ["A4 fermé 210 × 297 mm (2 ou 3 volets)", "A5 fermé 148 × 210 mm", "format à l''italienne (paysage)", "version avec fenêtre"], "supports": ["couché demi-mat 350 g", "couché brillant 350 g", "couché recyclé satin blanc 350 g"], "finitions": ["pelliculage mat, brillant ou soft touch (R ou R/V)", "vernis sélectif 2D/3D", "dorure à chaud", "encoche carte de visite verticale/horizontale"], "impression": "quadri recto ou recto/verso", "quantites": "de 25 à 2 000 exemplaires, tarifs fortement dégressifs", "delais": "standard 48-72 h, finitions spéciales sous quelques jours", "options": ["rainage simple ou double 5 mm", "2 ou 3 volets", "fenêtre de couverture", "livraison rainée à plat"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── bloc_note : Bloc-notes ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'bloc_note', '{}'::jsonb, 'fr', 'Bloc-notes personnalisé', array['bloc-notes personnalisé','bloc papier logo','bloc-notes entreprise','notepad publicitaire','bloc A5','bloc A4','bloc-notes détachable','cadeau d''affaires papeterie','bloc de bureau','bloc feuillets encollés']::text[],
  'Bloc-notes {{papier}} {{grammage}} — 50 feuillets — {{quantite}} exemplaires', 'Bloc-notes de 50 feuillets détachables sur {{papier}} {{grammage}}, dos cartonné, imprimé à vos couleurs. Votre marque sur chaque note manuscrite.',
  '## Votre logo sur chaque prise de note

Le bloc-notes personnalisé est l''un des supports publicitaires les plus utilisés au bureau : posé près du téléphone ou en salle de réunion, il expose votre marque des dizaines de fois par jour, chez vous comme chez vos clients.

## Caractéristiques techniques

Quatre formats du bloc de comptoir au bloc de bureau : 65 × 150 mm, A6 105 × 148 mm, A5 148 × 210 mm et A4 210 × 297 mm, en portrait ou paysage. 50 feuillets imprimés en quadri recto sur offset lisse 90 g ou offset recyclé 80 g, encollés en tête pour un détachement net, avec dos cartonné rigide pour écrire partout.

## Les avantages

C''est le cadeau d''affaires utile par excellence : contrairement au goodie gadget, un bloc s''utilise jusqu''à la dernière feuille. Prévoyez une trame discrète — logo, coordonnées, lignes ou cases — qui laisse la place à l''écriture tout en gardant votre marque visible sur chaque note transmise.', 'Bloc-notes personnalisé {{papier}} — 50 feuillets détachables',
  'Bloc-notes personnalisé entreprise | Impression logo', 'Blocs-notes 50 feuillets encollés en tête, dos cartonné, du A6 au A4. Imprimés à vos couleurs, le support publicitaire utile qui reste sur les bureaux.', array['bloc-notes personnalisé','bloc papier publicitaire','bloc-notes logo entreprise','notepad personnalisé','bloc A5 imprimé','cadeau d''affaires utile']::text[], 'Product',
  'Un bloc-notes vit des semaines sur le bureau de votre client et chaque feuille arrachée circule avec votre logo. Peu de supports publicitaires offrent autant d''expositions pour si peu.', '["Exposition quotidienne de la marque sur les bureaux", "Feuillets détachables proprement grâce à l''encollage en tête", "Dos cartonné : on écrit debout, en réunion, sur le terrain", "Quatre formats du comptoir au bureau", "Version recyclée pour une communication responsable", "Cadeau d''affaires réellement utilisé, jamais jeté"]'::jsonb, '["Goodies de salon et d''événement", "Dotation interne salles de réunion", "Cadeau client de fin d''année", "Bloc de comptoir pour messages", "Support de prise de commande simple"]'::jsonb,
  '[{"title": "Banque locale", "description": "Des blocs A5 offerts aux clients professionnels lors des rendez-vous annuels : le logo reste sur leur bureau toute l''année."}, {"title": "Salle de réunion", "description": "L''entreprise équipe ses salles de blocs A4 avec trame ligne et pied de page charté : les notes internes portent l''identité maison."}, {"title": "Pharmacie", "description": "Un petit bloc 65 × 150 mm au comptoir pour noter posologies et rappels, avec coordonnées et horaires imprimés en pied."}, {"title": "Agence immobilière", "description": "Blocs A6 distribués en boîte aux lettres lors des campagnes de prospection : plus durable qu''un simple flyer."}]'::jsonb, '[{"question": "Combien de feuillets par bloc ?", "answer": "50 feuillets par bloc, encollés en tête sur un dos cartonné. C''est le standard qui offre le meilleur rapport épaisseur/durée d''utilisation."}, {"question": "Peut-on imprimer une trame lignée ou des cases ?", "answer": "Oui, la trame fait partie de votre fichier : lignes, carreaux, cases à cocher ou zones datées, tout est imprimé en quadri sur chaque feuillet."}, {"question": "Les feuilles se détachent-elles proprement ?", "answer": "Oui, l''encollage en tête est dosé pour maintenir le bloc tout en permettant un arrachage net d''une seule main."}, {"question": "Quel format choisir ?", "answer": "A5 est le plus polyvalent (bureau et réunion), A4 pour la prise de notes intensive, A6 et 65 × 150 mm pour le comptoir et les goodies économiques."}, {"question": "Quel fichier fournir ?", "answer": "Un PDF du feuillet à son format final, 300 dpi CMJN, fonds perdus 3 mm. Gardez les éléments importants à 5 mm des bords et de la zone d''encollage."}]'::jsonb, '{"formats": ["65 × 150 mm", "A6 105 × 148 mm", "A5 148 × 210 mm", "A4 210 × 297 mm", "portrait ou paysage"], "supports": ["offset lisse blanc 90 g", "offset 100 % recyclé 80 g"], "finitions": ["encollage en tête", "dos cartonné rigide"], "impression": "quadri recto sur chaque feuillet", "quantites": "de 50 à 5 000 blocs", "delais": "5 à 8 jours ouvrés (produit façonné)", "options": ["trame lignée ou personnalisée", "orientation paysage", "version repositionnable type notes adhésives"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── carnet_autocopiant : Carnet autocopiant ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'carnet_autocopiant', '{}'::jsonb, 'fr', 'Carnet autocopiant duplicata / triplicata', array['carnet autocopiant','liasse autocopiante','duplicata','triplicata','carnet de factures','bon de livraison','bon de commande','carnet de devis','papier autocopiant NCR','carnet numéroté','bloc autocopiant']::text[],
  'Carnet autocopiant {{finition}} — 50 liasses — {{quantite}} carnets', 'Carnet de 50 liasses autocopiantes duplicata ou triplicata, avec numérotation en option. Devis, factures et bons de livraison écrits une fois, copiés instantanément.',
  '## Le document terrain à double exemplaire

Le carnet autocopiant reste l''outil le plus fiable pour établir devis, bons de livraison, factures ou rapports d''intervention sur le terrain, sans électricité ni imprimante : vous écrivez une fois, la copie se forme instantanément sur le feuillet suivant. L''original part chez le client, la copie reste au carnet.

## Caractéristiques techniques

Quatre formats : A6 100 × 150 mm, DL 100 × 210 mm, A5 150 × 210 mm et A4 210 × 297 mm, portrait ou paysage. 50 liasses par carnet en papier autocopiant 60 g, en duplicata (2 feuillets) ou triplicata (3 feuillets), premier feuillet blanc, copies blanches ou jaunes pour les distinguer d''un coup d''œil. Reliure dos carré collé ou dos agrafé toilé, encollage en tête ou à gauche, couverture carte 250 g.

## Les avantages

La numérotation séquentielle en option sécurise le suivi comptable et évite toute contestation. Disponible dès 10 carnets : chaque véhicule, chaque technicien peut avoir le sien.', 'Carnet autocopiant personnalisé duplicata ou triplicata',
  'Carnet autocopiant personnalisé | Duplicata triplicata', 'Carnets autocopiants 50 liasses, duplicata ou triplicata, numérotation en option. Devis, factures et bons de livraison personnalisés, dès 10 carnets.', array['carnet autocopiant personnalisé','carnet de factures','bon de livraison autocopiant','duplicata triplicata','carnet numéroté','carnet de devis artisan','liasse autocopiante']::text[], 'Product',
  'Un devis signé sur place vaut tous les e-mails : le client repart avec l''original, vous gardez la copie, l''affaire est actée. Le carnet autocopiant reste l''outil de vente terrain le plus efficace des artisans.', '["Copie instantanée sans carbone ni imprimante", "Original client + copie archivée dans le même geste", "Numérotation séquentielle pour un suivi comptable irréprochable", "Copies jaunes pour distinguer l''exemplaire archivé", "Formats du carnet de poche au A4 complet", "Petites séries dès 10 carnets, un par technicien"]'::jsonb, '["Devis signés sur chantier", "Bons de livraison tournées transporteur", "Rapports d''intervention SAV", "Reçus et bons de dépôt en boutique", "Bons de commande marchés et foires"]'::jsonb,
  '[{"title": "Plombier chauffagiste", "description": "Carnets A5 triplicata numérotés : un feuillet pour le client, un pour la comptabilité, un qui reste au carnet comme preuve d''intervention."}, {"title": "Transporteur", "description": "Bons de livraison DL duplicata dans chaque camion : signature du destinataire sur l''original, la copie jaune revient au dépôt."}, {"title": "Pressing", "description": "Bons de dépôt numérotés en duplicata : le ticket client correspond exactement à la souche, fin des litiges de restitution."}, {"title": "Marché forain", "description": "Le producteur établit factures et reçus au format A6 de poche, sans terminal ni électricité, avec ses mentions légales pré-imprimées."}]'::jsonb, '[{"question": "Duplicata ou triplicata : comment choisir ?", "answer": "Duplicata (2 feuillets) si un seul exemplaire doit circuler ; triplicata (3 feuillets) quand client, comptabilité et archives ont chacun besoin d''une copie."}, {"question": "Comment fonctionne la numérotation ?", "answer": "Chaque liasse reçoit un numéro séquentiel imprimé, reporté sur toutes les copies. Vous pouvez définir le numéro de départ pour poursuivre vos séries existantes."}, {"question": "L''écriture se reporte-t-elle bien sur toutes les copies ?", "answer": "Oui, le papier autocopiant 60 g est conçu pour transmettre l''écriture au stylo à bille jusqu''au troisième feuillet. Écrivez sur support rigide pour un report optimal."}, {"question": "Peut-on empêcher le report sur les liasses suivantes ?", "answer": "Oui, glissez le rabat cartonné de la couverture sous la liasse en cours : il isole les liasses suivantes pendant l''écriture."}, {"question": "Quelles mentions pré-imprimer ?", "answer": "Raison sociale, SIRET, TVA, colonnes et zones de signature : tout votre modèle de devis ou de bon est imprimé, il ne reste que le contenu à écrire."}]'::jsonb, '{"formats": ["A6 100 × 150 mm", "DL 100 × 210 mm", "A5 150 × 210 mm", "A4 210 × 297 mm", "portrait ou paysage"], "supports": ["papier autocopiant 60 g", "couverture carte 250 g"], "finitions": ["dos carré collé ou dos agrafé toilé", "encollage en tête ou à gauche", "numérotation séquentielle en option"], "impression": "noir, 1 ton direct ou quadri selon besoin ; copies blanches ou jaunes", "quantites": "de 10 à 100 carnets ; liasses libres de 50 à 20 000 exemplaires", "delais": "6 à 8 jours ouvrés (produit façonné)", "options": ["duplicata ou triplicata", "numérotation avec numéro de départ personnalisé", "rabat isolant", "existe en bloc et en liasses libres"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── marque_page : Marque-page ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'marque_page', '{}'::jsonb, 'fr', 'Marque-page personnalisé', array['marque-page personnalisé','marque-page publicitaire','signet','marque-page librairie','marque-page ensemencé','papier à graines','marque-page indéchirable','goodies culture','marque-page 50x210','signet imprimé']::text[],
  'Marque-page 50 × 210 mm {{papier}} {{finition}} — {{quantite}} exemplaires', 'Marque-page 50 × 210 mm imprimé recto/verso sur {{papier}}, du support indéchirable au papier ensemencé à planter. Le goodie qui accompagne chaque lecture.',
  '## Un support qui reste entre les pages

Le marque-page est un goodie discret et durable : glissé dans un livre, un agenda ou un dossier, il ressort à chaque lecture avec votre message. Librairies, éditeurs, musées, offices de tourisme et entreprises en font un support de fidélisation à faible coût.

## Caractéristiques techniques

Format classique 50 × 210 mm, imprimé en quadri recto/verso. Trois familles de supports : carte rigide pelliculée mat ou brillant pour l''usage courant, support synthétique indéchirable 450 g lavable pour une durée de vie maximale, ou papier ensemencé 250 g (basilic ou fleurs sauvages) qui se plante après usage et germe en quelques jours.

## Les avantages

Le papier ensemencé transforme un simple signet en geste mémorable : votre client plante votre message et le regarde pousser. Vernis sélectif, dorure or ou argent et découpes de forme personnalisées sont disponibles pour les éditions haut de gamme et les événements.', 'Marque-page personnalisé {{papier}} {{finition}}',
  'Marque-page personnalisé | Papier ensemencé, dorure', 'Marque-pages 50 × 210 mm quadri recto/verso : carte pelliculée, indéchirable lavable ou papier ensemencé à planter. Dès 50 exemplaires.', array['marque-page personnalisé','signet publicitaire','marque-page ensemencé','marque-page papier graines','marque-page indéchirable','goodies librairie','marque-page dorure']::text[], 'Product',
  'Un marque-page revient sous les yeux de son détenteur à chaque lecture, pendant des mois. En version ensemencée, il se plante et fait littéralement pousser votre marque.', '["Exposition répétée à chaque lecture, sur la durée", "Papier ensemencé : un goodie RSE qui germe réellement", "Version indéchirable et lavable quasi inusable", "Finitions dorure et vernis sélectif pour l''édition premium", "Coût unitaire très faible dès 50 exemplaires", "Recto/verso : message, agenda culturel ou offre au dos"]'::jsonb, '["Goodies librairie et maison d''édition", "Souvenir de musée ou d''exposition", "Cadeau événementiel mariage ou salon", "Support de campagne RSE ensemencé", "Carte de fidélité détournée en signet"]'::jsonb,
  '[{"title": "Librairie indépendante", "description": "Un marque-page glissé dans chaque achat, avec le programme des rencontres du trimestre au verso : le client le garde et revient."}, {"title": "Campagne RSE", "description": "Une mutuelle distribue des marque-pages ensemencés aux fleurs sauvages lors d''un salon : le stand le plus commenté, un message qui germe."}, {"title": "Musée", "description": "Signet indéchirable à dorure or vendu en boutique, reprenant l''œuvre phare de la collection permanente."}, {"title": "Auteur auto-édité", "description": "Marque-pages au visuel de la couverture offerts en dédicace, avec QR code vers la boutique en ligne au verso."}]'::jsonb, '[{"question": "Le papier ensemencé germe-t-il vraiment ?", "answer": "Oui : plantez-le sous quelques millimètres de terre, arrosez régulièrement, et le basilic ou les fleurs sauvages lèvent en une à trois semaines selon la saison."}, {"question": "Peut-on imprimer recto et verso ?", "answer": "Oui, l''impression quadri recto/verso est standard : visuel d''un côté, message, agenda ou QR code de l''autre."}, {"question": "Quelle est la différence entre les supports ?", "answer": "La carte pelliculée est le choix économique courant ; l''indéchirable 450 g résiste à l''eau et aux années ; l''ensemencé 250 g privilégie l''impact écologique et émotionnel."}, {"question": "Des formes personnalisées sont-elles possibles ?", "answer": "Oui, une découpe de forme (arrondi, silhouette, angle biseauté) est réalisable en option, ainsi que perforation et ruban."}, {"question": "Quel fichier fournir ?", "answer": "PDF 300 dpi CMJN au format 50 × 210 mm avec 3 mm de fonds perdus, textes à 5 mm des bords. Prévoir un fichier de forme si découpe personnalisée."}]'::jsonb, '{"formats": ["50 × 210 mm", "découpe de forme sur demande"], "supports": ["carte couchée pelliculée", "synthétique indéchirable 450 g lavable", "papier ensemencé 250 g basilic", "papier ensemencé 250 g fleurs sauvages"], "finitions": ["pelliculage mat ou brillant R/V", "vernis sélectif", "dorure or ou argent", "découpe personnalisée", "perforation"], "impression": "quadri recto/verso", "quantites": "de 50 à 5 000 exemplaires", "delais": "standard 48-72 h, express possible", "options": ["papier à graines", "QR code verso", "coins arrondis", "ruban"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── sous_main : Sous-main ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'sous_main', '{}'::jsonb, 'fr', 'Sous-main personnalisé', array['sous-main personnalisé','sous-main publicitaire','sous-main papier','sous-main bureau','sous-main calendrier','bloc sous-main','protège bureau','sous-main entreprise','sous-main 25 feuillets','sous-main A2']::text[],
  'Sous-main {{papier}} — 25 feuillets — {{quantite}} exemplaires', 'Sous-main papier de 25 feuillets détachables sur dos cartonné, en 420 × 300 mm ou 600 × 400 mm. La plus grande surface publicitaire d''un bureau.',
  '## La plus grande surface d''un bureau à vos couleurs

Le sous-main papier occupe le centre du poste de travail : impossible de ne pas le voir. Il protège le bureau, sert de zone de prise de notes géante et expose en continu votre marque, un plan, une grille calendrier ou des informations pratiques.

## Caractéristiques techniques

Deux formats : 420 × 300 mm (standard) et 600 × 400 mm (grand format A2). Bloc de 25 feuillets imprimés en quadri recto sur offset lisse 90 g ou offset recyclé 80 g, encollés en tête ou en pied, montés sur un dos cartonné rigide qui stabilise l''ensemble. Quand une feuille est remplie, on l''arrache : le sous-main redevient neuf.

## Les avantages

C''est un support publicitaire à durée de vie exceptionnelle : 25 feuillets représentent des mois de présence sur le bureau du destinataire. Intégrez calendrier annuel, plan d''atelier, tableau de conversion ou numéros utiles : plus le contenu sert, plus le sous-main reste.', 'Sous-main personnalisé {{papier}} — 25 feuillets détachables',
  'Sous-main personnalisé publicitaire | 25 feuillets', 'Sous-main papier 420 × 300 ou 600 × 400 mm, 25 feuillets détachables sur dos cartonné. La surface publicitaire la plus visible d''un bureau.', array['sous-main personnalisé','sous-main publicitaire papier','sous-main entreprise','sous-main calendrier','protège bureau personnalisé','sous-main bloc-notes']::text[], 'Product',
  'Aucun autre support n''occupe autant de place sur le bureau de votre client, aussi longtemps. Un sous-main utile — calendrier, notes, infos pratiques — reste en place toute l''année.', '["Visibilité permanente au centre du poste de travail", "25 feuillets : des mois d''utilisation avant épuisement", "Grande surface pour calendrier, plans et infos utiles", "Protège réellement le bureau, cadeau perçu comme utile", "Dos cartonné rigide, tenue parfaite", "Version recyclée disponible"]'::jsonb, '["Cadeau de fin d''année fournisseurs", "Équipement des postes en atelier", "Sous-main calendrier annuel client", "Support planning pour accueil et standard", "Zone de croquis pour bureaux d''études"]'::jsonb,
  '[{"title": "Négoce de matériaux", "description": "Sous-main calendrier offert aux artisans clients en janvier : la grille annuelle et les coordonnées du commercial restent sous leurs yeux toute l''année."}, {"title": "Atelier mécanique", "description": "Chaque poste reçoit un sous-main avec tableaux de couples de serrage et numéros internes : l''outil de travail devient support d''information."}, {"title": "Standard téléphonique", "description": "L''accueil note les messages directement sur le sous-main à zones pré-imprimées (appelant, heure, motif), arrache et transmet."}, {"title": "Agence d''architecture", "description": "Grand format 600 × 400 mm quadrillé pour croquis et annotations en réunion projet, logo de l''agence en pied."}]'::jsonb, '[{"question": "Combien de feuillets contient un sous-main ?", "answer": "25 feuillets encollés sur dos cartonné. Chaque feuille arrachée laisse place à une neuve, identique."}, {"question": "Encollage en tête ou en pied : quelle différence ?", "answer": "L''encollage en tête (bord supérieur) est le plus courant ; en pied, il facilite l''arrachage pour les compositions dont le contenu principal est en haut."}, {"question": "Peut-on intégrer un calendrier ?", "answer": "Oui, c''est l''usage le plus efficace : une grille annuelle imprimée sur chaque feuillet garde le sous-main en place douze mois."}, {"question": "Quel format choisir ?", "answer": "Le 420 × 300 mm convient à la plupart des bureaux ; le 600 × 400 mm couvre un poste complet et maximise la surface d''expression."}, {"question": "Quel fichier fournir ?", "answer": "PDF 300 dpi CMJN au format choisi, fonds perdus 3 mm, éléments importants éloignés de 10 mm de la zone d''encollage."}]'::jsonb, '{"formats": ["420 × 300 mm", "600 × 400 mm (A2)"], "supports": ["offset lisse blanc 90 g", "offset 100 % recyclé 80 g", "dos cartonné rigide"], "finitions": ["encollage en tête ou en pied"], "impression": "quadri recto", "quantites": "de 20 à 1 000 exemplaires", "delais": "5 à 8 jours ouvrés (produit façonné)", "options": ["grille calendrier intégrée", "zones de prise de message pré-imprimées", "version recyclée"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── calendrier : Calendriers ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'calendrier', '{}'::jsonb, 'fr', 'Calendriers publicitaires', array['calendrier publicitaire','calendrier entreprise','calendrier personnalisé','calendrier mural','calendrier bancaire','calendrier chevalet','calendrier spirale','calendrier 2027','calendrier photo entreprise','objet média annuel']::text[],
  'Calendrier publicitaire {{finition}} — {{quantite}} exemplaires', 'Calendriers muraux, chevalets, souples ou contrecollés rigides, imprimés à vos couleurs. Votre marque affichée 365 jours par an chez vos clients.',
  '## Le support publicitaire qui dure un an

Le calendrier est l''objet média par excellence : offert en fin d''année, il s''affiche douze mois durant dans les bureaux, ateliers, cuisines et commerces de vos clients. Chaque consultation de date est une exposition de votre marque.

## Caractéristiques techniques

La gamme couvre tous les usages : calendrier souple économique (A5 à A2, couché 300-350 g), calendrier mural à spirale 13 pages avec un visuel par mois, calendrier chevalet de bureau, et calendrier bancaire contrecollé sur carton rigide 1,8 mm pour un affichage annuel d''un seul tenant. Impression quadri, grilles calendaires prêtes à l''emploi disponibles pour composer votre fichier sans risque d''erreur de dates.

## Les avantages

Un calendrier utile n''est jamais jeté : c''est un des rares supports publicitaires que le destinataire accroche lui-même au mur. Choisissez le format selon la cible — spirale photo pour l''image, bancaire rigide pour l''atelier et le suivi de planning, souple pour les grandes diffusions.', 'Calendriers publicitaires personnalisés pour entreprise',
  'Calendrier publicitaire personnalisé | Mural, chevalet', 'Calendriers d''entreprise : souples, muraux à spirale, chevalets ou bancaires contrecollés. Votre marque visible chez vos clients 365 jours par an.', array['calendrier publicitaire personnalisé','calendrier entreprise','calendrier mural spirale','calendrier bancaire','calendrier chevalet bureau','impression calendrier','cadeau client fin d''année']::text[], 'Product',
  'Offert en décembre, consulté jusqu''au 31 décembre suivant : aucun autre support n''offre douze mois d''exposition garantie pour un coût unitaire aussi faible. Le calendrier est le cadeau client que personne ne jette.', '["Douze mois d''exposition continue de votre marque", "Quatre familles : souple, spirale, chevalet, contrecollé rigide", "Grilles calendaires fournies, zéro risque d''erreur de dates", "Formats du chevalet de bureau au grand mural A2", "Petites séries possibles pour cibler les meilleurs clients", "Cadeau de fin d''année attendu et réellement utilisé"]'::jsonb, '["Cadeau client de fin d''année", "Calendrier photo des réalisations", "Planning mural d''atelier", "Dotation réseau et partenaires", "Calendrier associatif ou communal"]'::jsonb,
  '[{"title": "Entreprise du bâtiment", "description": "Un calendrier bancaire rigide offert aux clients pros : accroché dans l''atelier, il sert au suivi de chantier avec le logo bien en vue."}, {"title": "Photographe / collectivité", "description": "Un mural à spirale met en scène douze photos de la commune ou du portfolio, une par mois, en couché 200 g brillant."}, {"title": "Garage automobile", "description": "Des calendriers souples A4 distribués au comptoir en décembre, avec les échéances d''entretien rappelées mois par mois."}, {"title": "Expert-comptable", "description": "Un chevalet de bureau avec les échéances fiscales de l''année : l''outil dont aucun client ne se sépare."}]'::jsonb, '[{"question": "Quel type de calendrier choisir ?", "answer": "Souple pour les grandes diffusions économiques, spirale pour valoriser des visuels mensuels, chevalet pour le bureau, contrecollé rigide pour un affichage annuel durable en atelier."}, {"question": "Fournissez-vous les grilles de dates ?", "answer": "Oui, des grilles calendaires prêtes à l''emploi (mensuelle ou annuelle, avec vacances scolaires) sont disponibles pour composer votre fichier sans erreur."}, {"question": "Quand commander pour la fin d''année ?", "answer": "Idéalement entre septembre et novembre : vous livrez vos clients début décembre, avant que les calendriers concurrents n''occupent les murs."}, {"question": "Peut-on mettre une photo différente chaque mois ?", "answer": "Oui, avec le calendrier à spirale 13 pages : une couverture plus douze visuels mensuels entièrement personnalisables."}, {"question": "Quels fichiers fournir ?", "answer": "PDF 300 dpi CMJN par page, fonds perdus 3 mm, en respectant les zones réservées à la spirale ou aux perforations selon le modèle."}]'::jsonb, '{"formats": ["A5 à A2 selon modèle", "chevalet 160 × 150 mm", "mural spirale jusqu''à 300 × 420 mm", "bancaire jusqu''à 530 × 400 mm"], "supports": ["couché brillant 150-300 g", "couché demi-mat 350 g", "recyclé satin 350 g", "carton contrecollé 1,8 mm"], "finitions": ["spirale métallique", "pelliculage mat/brillant/soft touch", "perforation avec ou sans œillet", "contrecollage rigide"], "impression": "quadri recto ou recto/verso selon modèle", "quantites": "de 5 à 10 000 exemplaires selon le modèle", "delais": "de 48-72 h (souple) à 2 semaines (contrecollé), anticiper pour la fin d''année", "options": ["grilles calendaires fournies", "vacances scolaires", "année à cheval", "format sur-mesure"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── calendrier_souple : Calendrier souple ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'calendrier_souple', '{}'::jsonb, 'fr', 'Calendrier souple personnalisé', array['calendrier souple','calendrier mural papier','calendrier annuel','calendrier A4 personnalisé','calendrier A3','calendrier économique','calendrier feuille','calendrier entreprise pas cher','calendrier mural simple','calendrier perforé']::text[],
  'Calendrier souple {{papier}} {{grammage}} {{finition}} — {{quantite}} exemplaires', 'Calendrier annuel une feuille en carte {{grammage}}, du A5 au A2, avec perforation d''accrochage en option. La solution la plus économique pour être présent toute l''année.',
  '## L''essentiel du calendrier, au meilleur coût

Le calendrier souple est un calendrier annuel d''une seule feuille en carte épaisse : la grille des douze mois et votre communication sur un même support, à accrocher au mur ou à poser. C''est la formule idéale pour les diffusions larges — comptoir, mailing, boîtes aux lettres.

## Caractéristiques techniques

Quatre formats standard : A5 148 × 210 mm, A4 210 × 297 mm, A3 297 × 420 mm et A2 420 × 594 mm, plus le sur-mesure. Impression quadri recto ou recto/verso (par exemple grille annuelle au recto, calendrier scolaire ou informations pratiques au verso) sur couché brillant 300 g, demi-mat 350 g ou recyclé satin 350 g. Perforation Ø 4 mm en option pour l''accrochage mural.

## Les avantages

Pelliculage mat, brillant ou soft touch pour renforcer tenue et perception. Son faible poids le glisse dans une enveloppe DL ou C4 : c''est le seul calendrier qui s''envoie par courrier au tarif lettre, parfait en accompagnement des vœux.', 'Calendrier souple personnalisé {{papier}} {{grammage}}',
  'Calendrier souple personnalisé A5 à A2 | Impression', 'Calendrier annuel une feuille en carte 300-350 g, perforation d''accrochage, du A5 au A2. La présence publicitaire à l''année la plus économique.', array['calendrier souple personnalisé','calendrier mural papier','calendrier annuel entreprise','calendrier A4 imprimé','calendrier économique','calendrier une feuille']::text[], 'Product',
  'Assez léger pour partir avec vos vœux dans une simple enveloppe, assez rigide pour tenir un an au mur. Le calendrier souple est la présence publicitaire annuelle la moins chère du marché.', '["Coût unitaire minimal pour une visibilité de douze mois", "S''expédie par courrier avec vos vœux de fin d''année", "Carte 300-350 g : tenue murale toute l''année", "Recto/verso : grille annuelle + infos pratiques", "Perforation d''accrochage prête à l''emploi", "Du A5 comptoir au A2 grand affichage"]'::jsonb, '["Encart calendrier dans les vœux", "Distribution comptoir en décembre", "Calendrier scolaire pour associations", "Affichage planning en atelier", "Mailing boîtes aux lettres de proximité"]'::jsonb,
  '[{"title": "Boulangerie", "description": "Un calendrier A5 avec les dates de fermeture annuelle offert à chaque client en décembre : il finit sur le frigo, la boutique reste en tête."}, {"title": "Club sportif", "description": "Le calendrier A3 de la saison avec les dates de matchs, financé par les encarts des sponsors locaux."}, {"title": "Vœux d''entreprise", "description": "La carte de vœux est accompagnée d''un calendrier A4 350 g glissé dans la même enveloppe : le message dure douze mois de plus."}, {"title": "Atelier de production", "description": "Un A2 recto/verso affiché au mur : grille annuelle côté planning, consignes et numéros utiles au verso pour l''année suivante."}]'::jsonb, '[{"question": "Quel grammage choisir ?", "answer": "300 g brillant pour les diffusions économiques, 350 g demi-mat pour une écriture facile sur la grille, 350 g recyclé pour l''axe responsable. Les trois tiennent au mur toute l''année."}, {"question": "La perforation est-elle incluse ?", "answer": "Elle est en option : un trou Ø 4 mm centré en haut pour l''accrochage. Sans perforation, le calendrier se pose ou s''aimante."}, {"question": "Peut-on imprimer le verso ?", "answer": "Oui : second semestre, calendrier scolaire, tableau de conversion ou informations pratiques — le verso double la valeur d''usage."}, {"question": "Disposez-vous de grilles de dates prêtes ?", "answer": "Oui, des grilles annuelles vérifiées (jours fériés, vacances scolaires) sont disponibles à intégrer directement dans votre maquette."}, {"question": "Quel délai prévoir pour une livraison avant les fêtes ?", "answer": "La fabrication est rapide (quelques jours), mais commandez avant fin novembre pour absorber le pic de fin d''année et livrer vos clients début décembre."}]'::jsonb, '{"formats": ["A5 148 × 210 mm", "A4 210 × 297 mm", "A3 297 × 420 mm", "A2 420 × 594 mm", "sur-mesure"], "supports": ["couché brillant 300 g", "couché demi-mat 350 g", "couché recyclé satin blanc 350 g"], "finitions": ["pelliculage brillant, mat ou soft touch recto", "perforation Ø 4 mm en option"], "impression": "quadri recto ou recto/verso", "quantites": "de 250 à 10 000 exemplaires", "delais": "fabrication rapide, standard 48-72 h, anticiper le pic de fin d''année", "options": ["grille annuelle fournie", "verso informatif", "version recyclée"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── calendrier_spirale : Calendrier mural spirale ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'calendrier_spirale', '{}'::jsonb, 'fr', 'Calendrier mural à spirale', array['calendrier mural spirale','calendrier 12 mois photo','calendrier wire-o','calendrier mensuel mural','calendrier photo entreprise','calendrier spirale personnalisé','calendrier 13 pages','calendrier mural A4','calendrier paysage','calendrier reliure métallique']::text[],
  'Calendrier mural à spirale {{papier}} {{grammage}} — 13 pages — {{quantite}} exemplaires', 'Calendrier mural 13 pages relié par spirale métallique : une couverture et un visuel par mois, imprimés sur couché {{grammage}}. Douze occasions de mettre en scène votre univers.',
  '## Un visuel différent chaque mois

Le calendrier mural à spirale raconte votre entreprise en douze images : réalisations, produits, équipes, paysages. Chaque mois tourné relance l''attention — c''est le format le plus valorisant pour les marques qui ont de belles images à montrer.

## Caractéristiques techniques

13 pages (couverture + 12 mois) imprimées en quadri sur couché brillant 200 g, reliées par spirale métallique noire positionnée sur le petit côté (portrait) ou le grand côté (paysage). Cinq formats : 210 × 300 mm, 300 × 300 mm carré, 300 × 420 mm grand mural, 160 × 150 mm compact et 300 × 100 mm panoramique. Impression recto ou recto/verso pour doubler le contenu.

## Les avantages

Disponible dès 5 exemplaires : il devient un produit photo à part entière — cadeau personnalisé, série limitée pour les meilleurs clients, calendrier interne d''équipe. Le couché 200 g garantit des pages qui tournent bien et un rendu photo éclatant.', 'Calendrier mural à spirale 13 pages {{papier}}',
  'Calendrier mural spirale 13 pages | Photo par mois', 'Calendrier mural à spirale métallique : couverture + 12 visuels mensuels sur couché 200 g, 5 formats dont carré et panoramique. Dès 5 exemplaires.', array['calendrier mural à spirale','calendrier photo 12 mois','calendrier wire-o personnalisé','calendrier mensuel entreprise','calendrier mural photo','calendrier spirale petite quantité']::text[], 'Product',
  'Douze pages tournées, douze fois votre univers remis sous les yeux de vos clients. Dès 5 exemplaires, offrez à vos meilleurs comptes un calendrier photo digne d''une édition d''art.', '["Un visuel dédié par mois : le format le plus valorisant", "Spirale métallique : pages qui tournent sans s''abîmer", "Cinq formats dont carré et panoramique originaux", "Couché 200 g au rendu photo éclatant", "Dès 5 exemplaires : séries limitées possibles", "Portrait ou paysage selon vos visuels"]'::jsonb, '["Calendrier photo des réalisations annuelles", "Cadeau premium meilleurs clients", "Calendrier d''équipe ou d''association", "Vitrine produits mois par mois", "Série limitée artiste ou photographe"]'::jsonb,
  '[{"title": "Paysagiste", "description": "Douze jardins réalisés, un par mois, au format 300 × 420 mm : le book de l''entreprise affiché chez les clients et prescripteurs."}, {"title": "Association communale", "description": "Le calendrier photo du village vendu au profit de l''association, en format carré 300 × 300 mm qui se démarque."}, {"title": "Marque alimentaire", "description": "Une recette de saison par mois avec le produit mis en scène : le calendrier devient un livre de cuisine mural."}, {"title": "Cabinet d''architectes", "description": "Édition limitée de 20 exemplaires panoramiques 300 × 100 mm pour les partenaires, avec les maquettes de l''année."}]'::jsonb, '[{"question": "Combien de pages comporte le calendrier ?", "answer": "13 pages : une couverture personnalisable et une page par mois, chacune avec son visuel et sa grille."}, {"question": "Où se place la spirale ?", "answer": "Sur le petit côté en portrait ou le grand côté en paysage — choisissez selon l''orientation de vos photos."}, {"question": "Peut-on commander une très petite quantité ?", "answer": "Oui, dès 5 exemplaires : idéal pour les cadeaux ciblés, les tests ou les éditions personnelles."}, {"question": "Le verso des pages est-il imprimable ?", "answer": "Oui, l''impression recto/verso permet d''ajouter au dos de chaque mois des contenus complémentaires : agenda, notes, photos supplémentaires."}, {"question": "Comment préparer le fichier ?", "answer": "Un PDF de 13 pages dans l''ordre (couverture puis janvier à décembre), 300 dpi CMJN, fonds perdus 3 mm, en réservant environ 15 mm côté spirale."}]'::jsonb, '{"formats": ["210 × 300 mm", "300 × 300 mm carré", "300 × 420 mm", "160 × 150 mm compact", "300 × 100 mm panoramique"], "supports": ["couché brillant 200 g (couverture et intérieur)"], "finitions": ["spirale métallique noire", "spirale petit ou grand côté"], "impression": "quadri recto ou recto/verso, 13 pages", "quantites": "de 5 à 2 000 exemplaires", "delais": "fabrication rapide, quelques jours ouvrés, anticiper la fin d''année", "options": ["orientation portrait ou paysage", "grilles mensuelles fournies", "version chevalet de bureau"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── calendrier_bancaire : Calendrier bancaire contrecollé ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'calendrier_bancaire', '{}'::jsonb, 'fr', 'Calendrier bancaire rigide contrecollé', array['calendrier bancaire','calendrier contrecollé','calendrier rigide','calendrier carton','calendrier mural rigide','calendrier annuel entreprise','calendrier atelier','calendrier banque personnalisé','calendrier publicitaire rigide','calendrier œillet']::text[],
  'Calendrier bancaire contrecollé carton 1,8 mm — {{quantite}} exemplaires', 'Calendrier annuel rigide : couché 150 g contrecollé sur carton compact 1,8 mm, perforation et œillet en option. L''année entière d''un seul regard, au mur pendant douze mois.',
  '## Le calendrier rigide qui traverse l''année

Le calendrier bancaire présente les douze mois sur une seule face rigide : accroché au mur du bureau, de l''atelier ou de la cuisine, il donne l''année entière d''un seul regard. Sa rigidité en fait un objet durable qui ne gondole pas et reste impeccable jusqu''au 31 décembre.

## Caractéristiques techniques

Quatre formats paysage : 210 × 155 mm compact, A4 210 × 297 mm, 530 × 400 mm grand format et A2 420 × 594 mm haute visibilité. Impression quadri recto/verso sur couché brillant 150 g, contrecollé sur un carton compact de 1,8 mm d''épaisseur. Perforation Ø 4 mm en haut, avec ou sans œillet métallique, pour un accrochage immédiat.

## Les avantages

Posé à plat, il sert aussi de sous-main d''appoint. C''est le format historique des banques, transporteurs et entreprises du bâtiment : planning de chantier, congés, échéances s''y suivent d''un trait de crayon. Sa durée de vie exceptionnelle en fait l''un des supports publicitaires au meilleur coût par jour d''exposition.', 'Calendrier bancaire contrecollé rigide personnalisé',
  'Calendrier bancaire contrecollé rigide | Carton 1,8 mm', 'Calendrier annuel rigide contrecollé sur carton 1,8 mm, 4 formats, perforation et œillet. L''année entière au mur, votre marque avec, pendant 12 mois.', array['calendrier bancaire personnalisé','calendrier contrecollé rigide','calendrier carton entreprise','calendrier mural annuel','calendrier rigide publicitaire','calendrier atelier chantier']::text[], 'Product',
  'Rigide, accroché en janvier, toujours impeccable en décembre : le calendrier bancaire est le doyen des supports publicitaires parce qu''il fonctionne. L''année de vos clients s''organise sous votre logo.', '["Vue annuelle complète sur une seule face", "Carton 1,8 mm : aucune déformation en douze mois", "Œillet métallique : accrochage immédiat et durable", "Recto/verso : année en cours et suivante possibles", "Sert aussi de sous-main rigide d''appoint", "Format historique apprécié des pros (BTP, transport, banque)"]'::jsonb, '["Cadeau client BTP et transport", "Planning mural d''atelier", "Suivi congés et présences d''équipe", "Dotation agences bancaires et assurances", "Calendrier d''échéances comptables"]'::jsonb,
  '[{"title": "Entreprise de transport", "description": "Chaque client reçoit le grand format 530 × 400 mm : les tournées et fermetures s''y planifient au feutre, le logo trône dans les bureaux d''exploitation."}, {"title": "Chef de chantier", "description": "Le calendrier A2 accroché dans la base vie sert au pointage des équipes et au suivi des phases, offert par le négoce de matériaux."}, {"title": "Cabinet comptable", "description": "Un A4 rigide avec les échéances fiscales surlignées, remis à chaque client en janvier avec la carte de vœux."}, {"title": "Boulangerie-pâtisserie", "description": "Le compact 210 × 155 mm posé près de la caisse rappelle les fermetures annuelles et les dates de commandes de fêtes."}]'::jsonb, '[{"question": "Quelle est l''épaisseur du support ?", "answer": "Le visuel couché 150 g est contrecollé sur un carton compact de 1,8 mm : l''ensemble est rigide, stable et ne gondole pas dans le temps."}, {"question": "Faut-il choisir l''œillet ?", "answer": "L''œillet métallique renforce la perforation et garantit un accrochage qui dure toute l''année ; sans œillet, la perforation Ø 4 mm suffit pour un clou ou une punaise."}, {"question": "Peut-on imprimer le verso ?", "answer": "Oui, l''impression est recto/verso : beaucoup y placent l''année suivante, un plan d''accès ou les coordonnées détaillées de l''entreprise."}, {"question": "Peut-on écrire dessus ?", "answer": "Oui, le couché accepte stylo et feutre fin : congés, chantiers et échéances s''annotent directement sur la grille."}, {"question": "Quel délai prévoir ?", "answer": "Le contrecollage demande environ deux semaines de fabrication : commandez en octobre-novembre pour distribuer début décembre."}]'::jsonb, '{"formats": ["210 × 155 mm", "A4 210 × 297 mm", "530 × 400 mm", "A2 420 × 594 mm", "orientation paysage"], "supports": ["couché brillant 150 g contrecollé sur carton compact 1,8 mm"], "finitions": ["sans perforation", "perforation Ø 4 mm", "perforation Ø 4 mm + œillet métallique"], "impression": "quadri recto/verso", "quantites": "de 50 à 10 000 exemplaires", "delais": "environ 2 semaines de fabrication, commander avant fin novembre pour les fêtes", "options": ["verso année suivante", "grille annuelle fournie", "annotation au feutre possible"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── restauration : Menus / Restauration ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'restauration', '{}'::jsonb, 'fr', 'Imprimés restauration et hôtellerie', array['imprimés restaurant','menu restaurant','set de table','carte des vins','supports restauration','impression CHR','papeterie restaurant','carte menu personnalisée','imprimerie hôtellerie','supports de table']::text[],
  'Imprimés restauration personnalisés — {{quantite}} exemplaires', 'Menus, cartes des vins, sets de table et supports de salle imprimés sur des papiers adaptés au service : classiques, lavables, kraft ou encapsulés.',
  '## L''expérience de table commence sur le papier

Dans un restaurant, les imprimés font partie du décor et du service : menu en main, set sous l''assiette, carte des vins, chevalets et signalétique. Des supports soignés et coordonnés prolongent votre positionnement — bistrot, gastronomique ou food truck — jusqu''au moindre détail.

## Caractéristiques techniques

La gamme couvre le menu simple ou à volets (A5, A4, formats allongés pour cartes des vins), le set de table A3 ou rond, et les accessoires de salle. Les supports répondent aux contraintes du service : couché 350 g rigide, kraft brut, recyclé, synthétique indéchirable et lavable 230-450 g, ou encapsulation sous film pour une étanchéité totale. Finitions dorure, gaufrage, vernis 3D et pelliculage mat antimicrobien.

## Les avantages

Coordonnez menu, set et accessoires pour une identité de table cohérente. Les supports lavables et encapsulés survivent aux services intensifs, tandis que le set papier consommable renouvelle votre communication à chaque couvert.', 'Imprimés pour restaurants, hôtels et traiteurs',
  'Imprimés restaurant : menus, sets, cartes | CHR', 'Menus, cartes des vins, sets de table et supports de salle personnalisés. Papiers classiques, kraft, lavables ou encapsulés, adaptés au service intensif.', array['imprimés restaurant','menu personnalisé restaurant','set de table imprimé','carte des vins','impression CHR','supports de table restaurant']::text[], 'Product',
  'Vos clients lisent le menu avant de goûter le premier plat : chaque support de table travaille votre image et vos ventes. Une gamme coordonnée menu-set-accessoires installe votre univers dès l''assise.', '["Identité de table cohérente du menu au set", "Supports lavables et encapsulés pour service intensif", "Kraft, recyclé, ensemencé : des matières qui racontent votre cuisine", "Finitions premium (dorure, gaufrage) pour la gastronomie", "Renouvellement facile à chaque carte saisonnière", "Petites séries adaptées aux changements de menu fréquents"]'::jsonb, '["Nouvelle carte de saison", "Ouverture de restaurant", "Carte des vins reliée", "Sets événementiels et menus de fêtes", "Supports terrasse et vente à emporter"]'::jsonb,
  '[{"title": "Bistrot de quartier", "description": "Menus A4 kraft assortis aux sets de table : l''esprit cuisine maison se lit avant même la commande."}, {"title": "Restaurant gastronomique", "description": "Carte à volets sur papier texturé avec dorure à chaud, changée à chaque saison, coordonnée à la carte des vins allongée."}, {"title": "Brasserie à fort débit", "description": "Menus encapsulés lavables qui résistent aux projections et se nettoient entre chaque service, sans réimpression mensuelle."}, {"title": "Traiteur événementiel", "description": "Menus de table individuels et sets personnalisés au nom des mariés pour chaque réception."}]'::jsonb, '[{"question": "Quel support pour un usage quotidien intensif ?", "answer": "Le synthétique indéchirable lavable ou l''encapsulation sous film : les deux se nettoient d''un coup d''éponge et supportent des mois de service."}, {"question": "Peut-on changer de carte souvent sans exploser le budget ?", "answer": "Oui, les petites séries sur couché 350 g permettent de réimprimer à chaque saison ; réservez les finitions premium aux supports permanents."}, {"question": "Le rainage est-il nécessaire pour les menus pliés ?", "answer": "Oui, au-delà de 170 g, le rainage évite que le pli casse le papier et blanchisse l''image. Il est réalisé systématiquement sur les cartes à volets."}, {"question": "Existe-t-il des finitions hygiéniques ?", "answer": "Oui, le pelliculage mat antimicrobien limite le développement bactérien sur les menus manipulés par de nombreux clients."}, {"question": "Quels fichiers fournir ?", "answer": "PDF 300 dpi CMJN avec 2-3 mm de fonds perdus par support ; pour les volets, respectez le gabarit de pliage fourni."}]'::jsonb, '{"formats": ["menus A5/A4/A3 et carrés", "cartes des vins format allongé", "sets A3 et ronds", "volets 2-3 plis"], "supports": ["couché demi-mat 350 g", "kraft", "recyclé", "synthétique indéchirable lavable 230-450 g", "encapsulé sous film", "ensemencé"], "finitions": ["dorure or/argent/cuivre", "vernis sélectif 3D", "pelliculage mat antimicrobien", "soft touch", "gaufrage", "rainage"], "impression": "quadri recto ou recto/verso", "quantites": "petites séries dès quelques dizaines, jusqu''à plusieurs milliers", "delais": "standard 48-72 h à quelques jours selon finitions", "options": ["kits coordonnés menu + set + accessoires", "chevalets de table", "signalétique de salle"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── menu : Menu restaurant ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'menu', '{}'::jsonb, 'fr', 'Menu restaurant personnalisé', array['menu restaurant personnalisé','carte restaurant','menu plié','carte des vins','menu plastifié lavable','menu encapsulé','menu A4','impression menu','menu kraft','carte menu volets','menu indéchirable']::text[],
  'Menu restaurant {{papier}} {{finition}} — {{quantite}} exemplaires', 'Menus simples ou à volets, du couché 350 g au support lavable indéchirable et à l''encapsulé étanche. La carte qui met en appétit et résiste au service.',
  '## La carte qui vend vos plats

Le menu est votre premier vendeur : c''est lui que le client lit, touche et juge avant le premier plat. Une carte propre, lisible et cohérente avec votre cuisine augmente le ticket moyen — les plats signatures mis en valeur se commandent davantage.

## Caractéristiques techniques

Formats A5, A4, carrés et formats allongés pour cartes des vins ; menus simples ou dépliants 2-3 volets en pli roulé ou accordéon, rainés systématiquement au-delà de 170 g. Supports au choix : couché demi-mat 350 g pour la rigidité, kraft pour l''esprit bistrot, recyclé, synthétique indéchirable lavable 230-450 g pour l''usage intensif, ou encapsulation sous film pour une étanchéité totale aux projections.

## Les avantages

Finitions au service de votre positionnement : dorure or, argent ou cuivre, gaufrage, vernis 3D en relief, pelliculage mat antimicrobien ou soft touch. Les petites séries permettent de réimprimer à chaque changement de carte sans immobiliser de budget.', 'Menu restaurant personnalisé {{papier}} {{finition}}',
  'Menu restaurant personnalisé | Lavable ou encapsulé', 'Menus et cartes des vins imprimés : couché 350 g, kraft, lavable indéchirable ou encapsulé. Simples ou à volets, finitions dorure et vernis 3D.', array['menu restaurant personnalisé','impression carte restaurant','menu plastifié lavable','menu encapsulé','carte des vins imprimée','menu à volets','menu kraft bistrot']::text[], 'Product',
  'Un menu se change en quelques jours, pas votre réputation : offrez à chaque carte de saison un support à la hauteur de votre cuisine. Du kraft bistrot à la dorure gastronomique, le bon papier vend le bon plat.', '["Supports lavables et encapsulés : des mois de service sans usure", "Rainage systématique : plis nets qui ne cassent pas", "Kraft, recyclé, texturé : la matière raconte votre cuisine", "Dorure et vernis 3D pour le positionnement gastronomique", "Pelliculage antimicrobien pour les cartes très manipulées", "Réimpression économique à chaque carte de saison"]'::jsonb, '["Carte de saison A4 rigide", "Carte des vins format allongé", "Menu du jour renouvelé chaque semaine", "Menu enfant plastifié", "Menus de fêtes et réveillons"]'::jsonb,
  '[{"title": "Brasserie", "description": "Menus A4 encapsulés : les projections s''essuient d''un geste, la carte reste impeccable des mois durant malgré 200 couverts par jour."}, {"title": "Table gastronomique", "description": "Carte 3 volets sur papier texturé, nom du restaurant en dorure cuivre : le support annonce le niveau de l''assiette."}, {"title": "Crêperie", "description": "Menu kraft 2 volets à l''esprit artisanal, réimprimé chaque saison en petite série pour suivre les produits du moment."}, {"title": "Bar à vins", "description": "Carte des vins au format allongé avec vernis sélectif sur les cuvées du mois, coordonnée aux sets de table."}]'::jsonb, '[{"question": "Quel support pour un nettoyage quotidien ?", "answer": "L''encapsulé (feuille scellée sous film étanche) ou le synthétique indéchirable lavable : les deux s''éponger sans dommage et résistent aux services intensifs."}, {"question": "Menu simple ou à volets ?", "answer": "Simple pour une carte courte lisible d''un regard ; 2-3 volets pour structurer entrées/plats/desserts ou intégrer la carte des boissons. Le pli roulé ou accordéon est rainé proprement."}, {"question": "Peut-on faire de petites quantités à chaque saison ?", "answer": "Oui, les petites séries sont prévues pour : beaucoup de restaurants réimpriment 30 à 100 menus par carte, quatre fois par an."}, {"question": "Le menu est-il assez rigide en main ?", "answer": "Le couché 350 g offre la bonne tenue en main. En dessous, préférez l''encapsulation qui rigidifie et protège à la fois."}, {"question": "Quel fichier fournir ?", "answer": "PDF 300 dpi CMJN, fonds perdus 2-3 mm, gabarit de pliage respecté pour les volets. Vérifiez la lisibilité des corps de texte à taille réelle (10 pt minimum conseillé)."}]'::jsonb, '{"formats": ["A5 148 × 210 mm", "A4 210 × 297 mm", "A3 297 × 420 mm", "formats carrés", "carte des vins allongée", "2-3 volets pli roulé ou accordéon"], "supports": ["couché demi-mat 350 g", "kraft", "recyclé", "synthétique indéchirable lavable 230-450 g", "encapsulé sous film"], "finitions": ["dorure à chaud or/argent/cuivre/rose", "vernis sélectif 3D", "pelliculage mat antimicrobien", "soft touch", "gaufrage", "rainage systématique > 170 g"], "impression": "quadri recto ou recto/verso", "quantites": "petites séries dès quelques dizaines, jusqu''à plusieurs milliers", "delais": "standard 48-72 h, quelques jours avec finitions spéciales", "options": ["livraison rainée à plat", "coordination avec sets et cartes des vins", "protège-menus"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── set_de_table : Set de table ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'set_de_table', '{}'::jsonb, 'fr', 'Set de table personnalisé', array['set de table personnalisé','set de table papier','set de table restaurant','set de table publicitaire','set de table A3','set de table kraft','set de table lavable','set de table rond','napperon imprimé','set de table jetable']::text[],
  'Set de table {{papier}} — format A3 — {{quantite}} exemplaires', 'Sets de table A3 ou ronds, en papier consommable, kraft, recyclé ou version lavable réutilisable. La surface publicitaire posée sous chaque assiette.',
  '## Sous chaque assiette, votre message

Le set de table occupe le regard du client pendant tout le repas : menu du jour, histoire de la maison, jeux pour enfants, offres à venir — c''est un espace d''expression unique qui protège la table et anime l''attente.

## Caractéristiques techniques

Format A3 297 × 420 mm, le standard qui cadre une assiette et ses couverts, ou format rond pour se démarquer. Deux logiques de support : le papier consommable (classique, recyclé ou kraft) changé à chaque couvert pour une hygiène irréprochable et un message renouvelé, ou le support lavable/PVC réutilisable et l''encapsulé pour les établissements qui veulent un set permanent.

## Les avantages

Le set papier est l''un des supports publicitaires au coût par contact le plus bas de la restauration : chaque service expose votre message à une table captive. En version kraft, il installe une ambiance bistrot ; coordonné au menu et aux ronds de serviette, il compose une table signature.', 'Set de table personnalisé {{papier}} pour restaurant',
  'Set de table personnalisé A3 | Papier, kraft, lavable', 'Sets de table A3 ou ronds imprimés à vos couleurs : papier consommable, kraft, recyclé ou lavable réutilisable. Votre message sous chaque assiette.', array['set de table personnalisé','set de table papier restaurant','set de table A3 imprimé','set de table kraft','set de table publicitaire','set de table lavable']::text[], 'Product',
  'Pendant vingt minutes d''attente, votre client n''a que le set de table sous les yeux : faites-en votre meilleure page de publicité. Renouvelé à chaque couvert, il annonce vos événements avant même le serveur.', '["Audience captive pendant toute la durée du repas", "Hygiène parfaite : un set neuf par couvert", "Coût par contact imbattable en restauration", "Kraft ou recyclé pour l''ambiance et l''axe responsable", "Version lavable réutilisable pour set permanent", "Support d''animation : jeux, anecdotes, promotions"]'::jsonb, '["Set quotidien de brasserie", "Set jeux pour espace enfants", "Set événementiel fêtes et menus spéciaux", "Support publicitaire partenaires locaux", "Table signature kraft coordonnée"]'::jsonb,
  '[{"title": "Pizzeria familiale", "description": "Set A3 avec jeux et coloriages côté enfants, carte des desserts côté parents : les tablées patientent, les desserts partent mieux."}, {"title": "Restaurant ouvrier", "description": "Set papier économique changé à chaque service, avec le menu de la semaine et les annonces du village imprimés en quadri."}, {"title": "Bistrot de marché", "description": "Set kraft assorti au menu, avec l''histoire des producteurs partenaires : la démarche locale se lit sur la table."}, {"title": "Réception traiteur", "description": "Sets ronds personnalisés au monogramme des mariés, coordonnés aux menus individuels et ronds de serviette."}]'::jsonb, '[{"question": "Quel format choisir ?", "answer": "L''A3 (297 × 420 mm) est le standard : il cadre l''assiette et les couverts. Le format rond apporte une touche différenciante pour les tables rondes et les événements."}, {"question": "Papier consommable ou lavable ?", "answer": "Le papier se change à chaque couvert : hygiène maximale et message renouvelable. Le lavable/PVC ou l''encapsulé se réutilise des mois : plus économique si votre visuel est permanent."}, {"question": "Peut-on imprimer le menu directement sur le set ?", "answer": "Oui, c''est un usage très efficace : le menu du jour ou la carte courte imprimée sur le set libère les mains du client et supprime des manipulations de cartes."}, {"question": "Quelle quantité prévoir ?", "answer": "Comptez votre nombre de couverts quotidiens multiplié par la période à couvrir ; les tarifs deviennent vite dégressifs sur les volumes de plusieurs milliers."}, {"question": "Quel fichier fournir ?", "answer": "PDF 300 dpi CMJN au format A3 avec 3 mm de fonds perdus, en gardant les informations importantes hors de la zone d''assiette centrale."}]'::jsonb, '{"formats": ["A3 297 × 420 mm", "format rond", "sur-mesure possible"], "supports": ["papier classique", "papier recyclé", "kraft", "synthétique lavable indéchirable", "PVC réutilisable", "encapsulé"], "finitions": ["impression quadri", "encapsulation pour version permanente"], "impression": "quadri recto (verso possible selon support)", "quantites": "de quelques centaines à plusieurs dizaines de milliers (consommable)", "delais": "standard 48-72 h à quelques jours", "options": ["kit coordonné set + menu + rond de serviette", "zone jeux enfants", "encarts partenaires"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── kakemono : Kakémonos / Roll-ups ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'kakemono', '{}'::jsonb, 'fr', 'Kakémonos et roll-ups publicitaires', array['kakémono','roll-up','enrouleur','banner stand','kakémono déroulant','stand enrouleur','support publicitaire portable','affichage salon','signalétique nomade','totem enrouleur']::text[],
  'Kakémono roll-up {{format}} — {{quantite}}', 'Kakémono enrouleur {{format}} avec structure aluminium et sac de transport : votre message déployé en moins d''une minute, partout.',
  '## Votre affichage mobile, prêt en 60 secondes

Le kakémono enrouleur — ou roll-up — est le support de communication nomade par excellence. La toile imprimée s''enroule dans une base en aluminium équipée d''une barre de lestage : vous la déployez d''un geste, vous la rangez aussi vite. Idéal pour les commerces, les salons professionnels, les halls d''accueil et toutes les opérations événementielles.

## Caractéristiques techniques

Nous proposons plusieurs largeurs standard, de 84 cm à 150 cm pour environ 200 cm de hauteur, ainsi que des versions XXL jusqu''à 200×300 cm pour les fonds de stand. Côté toiles : bâche PVC 450 g dos occultant classée M1, polyester 260 à 295 g dont des versions sans PVC plus responsables. Impression quadri haute définition, rendu net et couleurs fidèles.

## Les avantages de la gamme

Chaque roll-up est livré avec sa structure et son sac de transport : rien à acheter en plus. La toile enroulée reste protégée entre deux événements, ce qui garantit une durée de vie sur plusieurs saisons. Selon les modèles, le visuel peut être remplacé pour réutiliser la base — un vrai calcul économique pour vos campagnes récurrentes.', 'Kakémono roll-up {{format}} personnalisé',
  'Kakémono roll-up personnalisé — impression pro', 'Impression de kakémonos et roll-ups publicitaires : structure alu, toile M1, sac de transport inclus. Formats 84 à 200 cm. Montage en 1 minute.', array['kakémono personnalisé','roll-up publicitaire','impression roll-up','enrouleur publicitaire','kakémono salon','banner stand','roll-up pas cher','support enrouleur']::text[], 'Product',
  'Un stand qui tient dans une main : votre roll-up se monte en moins d''une minute, sans outil, et se réutilise événement après événement. Structure, impression et sac de transport compris — vous n''avez plus qu''à capter les regards.', '["Montage et démontage en moins d''une minute, sans outil", "Structure aluminium stable avec barre de lestage", "Sac de transport inclus pour protéger la toile", "Toiles classées M1, conformes aux exigences des salons", "Réutilisable sur plusieurs saisons d''événements", "Large choix de formats, du comptoir au fond de stand XXL"]'::jsonb, '["Stand de salon professionnel", "Accueil de boutique ou d''agence", "Lancement de produit en magasin", "Conférence et séminaire d''entreprise", "Animation commerciale itinérante"]'::jsonb,
  '[{"title": "Salon professionnel", "description": "Deux roll-ups encadrent votre comptoir d''accueil et présentent votre offre en un coup d''œil, même stand vu de loin."}, {"title": "Agence immobilière", "description": "Un kakémono en vitrine met en avant les biens du mois et se remplace en quelques secondes à chaque nouvelle campagne."}, {"title": "Événement itinérant", "description": "L''équipe commerciale transporte le roll-up dans son sac d''une ville à l''autre et monte le stand en arrivant, sans logistique."}, {"title": "Hall d''entreprise", "description": "Un roll-up signale un événement interne ou oriente les visiteurs vers la salle de réunion, sans percer les murs."}]'::jsonb, '[{"question": "Quel fichier fournir pour un kakémono ?", "answer": "Un PDF à l''échelle 1 (ou à l''échelle 1/10 en 300 dpi), en CMJN, avec les textes vectorisés. Prévoyez une zone tranquille en bas de visuel : les derniers centimètres restent dans l''enrouleur."}, {"question": "Un roll-up peut-il être utilisé en extérieur ?", "answer": "Les modèles standard sont conçus pour l''intérieur : leur voile prend le vent. Pour une terrasse ou un parvis, orientez-vous vers un modèle extérieur lesté ou vers un drapeau publicitaire."}, {"question": "Combien de temps dure la toile ?", "answer": "Rangée dans son sac entre deux utilisations, une toile de roll-up se réutilise plusieurs années. C''est l''enroulement dans la base qui la protège de la poussière et des plis."}, {"question": "Peut-on changer le visuel sans racheter la structure ?", "answer": "Oui sur plusieurs modèles de la gamme : la toile se remplace, la base se conserve. Une solution économique si vous renouvelez souvent vos campagnes."}, {"question": "Le classement feu M1 est-il obligatoire ?", "answer": "La plupart des parcs d''exposition et ERP l''exigent. Nos toiles M1 vous évitent tout refus d''installation le jour J — vérifiez le règlement de votre salon avant de commander."}]'::jsonb, '{"formats": ["84×204 cm", "100×207 cm", "120×207 cm", "150×207 cm", "XXL : 198×207, 200×250 et 200×300 cm"], "supports": ["Bâche PVC 450 g dos occultant M1", "Polyester 270 g M1", "Polyester 260 g sans PVC M1", "Polyester 295 g dos gris M1 (XXL)"], "finitions": ["Toile enroulable dans la base", "Visuel remplaçable selon modèle", "Vernis sélectif en option"], "impression": "Quadri recto haute définition", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Structure aluminium incluse", "Sac de transport inclus", "Barre de lestage", "Classement feu M1", "Mâts télescopiques sur formats XXL"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── roll_up_100x200 : Roll-up 100×200 cm ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'roll_up_100x200', '{}'::jsonb, 'fr', 'Roll-up 100×200 cm', array['roll-up 100x200','kakémono 100 cm','roll-up large','enrouleur 100x200','grand roll-up','kakémono enrouleur','roll-up salon','support publicitaire 100 cm','banner stand 100']::text[],
  'Roll-up 100×200 cm {{finition}} — {{quantite}}', 'Le roll-up 100×200 cm offre 20 % de surface visuelle en plus que le format classique : idéal quand votre message mérite de la place.',
  '## Le format généreux qui reste transportable

Avec son mètre de large, le roll-up 100×200 cm donne de l''air à votre visuel : un grand logo, une accroche lisible à distance et une photo pleine hauteur. Il reste pourtant aussi simple à transporter et à monter qu''un modèle standard — un seul geste et votre affichage est en place.

## Caractéristiques techniques

Toile imprimée en quadri haute définition sur bâche PVC 450 g dos occultant ou polyester 260-270 g, y compris en version sans PVC. Tous nos supports sont classés M1 pour un usage en salon et en établissement recevant du public. La structure aluminium à barre de lestage assure une excellente stabilité, et le sac de transport est fourni.

## Les avantages du 100×200

Ce format élargi capte mieux le regard dans les allées de salon très fréquentées, sans exiger plus de temps d''installation ni de logistique. La toile enroulée dans sa base reste protégée entre deux événements : vous amortissez votre support sur de nombreuses utilisations.', 'Roll-up 100×200 cm personnalisé',
  'Roll-up 100x200 cm personnalisé — impression HD', 'Roll-up 100×200 cm : toile M1 imprimée en quadri HD, structure alu et sac inclus. Plus de surface pour votre message, montage en 1 minute.', array['roll-up 100x200','kakémono 100x200','impression roll-up large','roll-up grand format','enrouleur publicitaire 100 cm','roll-up salon professionnel']::text[], 'Product',
  'Un mètre de large pour un message impossible à manquer : le 100×200 s''impose dans les allées de salon sans compliquer votre logistique. Structure et sac inclus, monté en une minute.', '["20 % de surface visuelle en plus qu''un roll-up standard", "Lisibilité renforcée à distance dans les espaces fréquentés", "Structure aluminium stable avec barre de lestage", "Sac de transport inclus", "Toiles classées M1 pour salons et ERP", "Toile protégée dans la base entre deux événements"]'::jsonb, '["Stand principal de salon", "Showroom et espace de démonstration", "Accueil d''événement d''entreprise", "Vitrine de concession ou d''agence", "Fond de scène de conférence"]'::jsonb,
  '[{"title": "Allée centrale de salon", "description": "Placé en angle de stand, le 100×200 rend votre marque visible depuis les deux allées adjacentes."}, {"title": "Showroom automobile", "description": "Un visuel pleine hauteur présente le nouveau modèle à côté du véhicule exposé, avec un vrai impact photo."}, {"title": "Forum de recrutement", "description": "Votre marque employeur s''affiche en grand : promesse, chiffres clés et QR code de candidature lisibles debout comme assis."}, {"title": "Espace conférence", "description": "Deux roll-ups 100×200 encadrent l''écran de projection et habillent la scène sans installation technique."}]'::jsonb, '[{"question": "Quelle résolution pour un visuel 100×200 cm ?", "answer": "Travaillez à l''échelle 1 en 150 dpi minimum, ou à l''échelle 1/2 en 300 dpi. En dessous, les photos risquent de pixelliser vues de près."}, {"question": "Le 100×200 est-il plus difficile à transporter ?", "answer": "Non : replié dans son sac, il ne mesure qu''une dizaine de centimètres de plus qu''un modèle classique et reste portable à une main."}, {"question": "Bâche PVC ou toile polyester : que choisir ?", "answer": "La bâche PVC 450 g dos occultant offre une opacité totale, même à contre-jour. Le polyester est plus léger et existe en version sans PVC, plus responsable."}, {"question": "Puis-je l''utiliser dehors ponctuellement ?", "answer": "Quelques heures à l''abri du vent, oui. Mais la voile de 2 m² prend le vent : pour un usage extérieur régulier, préférez un modèle dédié ou un drapeau."}, {"question": "La toile peut-elle être remplacée ?", "answer": "Selon le modèle choisi, oui : vous conservez la base aluminium et ne réimprimez que la toile lors de votre prochaine campagne."}]'::jsonb, '{"formats": ["100×207 cm (toile visible ~100×200 cm)"], "supports": ["Bâche PVC 450 g dos occultant M1", "Polyester 270 g M1", "Polyester 260 g sans PVC M1"], "finitions": ["Toile enroulable dans la base", "Visuel remplaçable selon modèle"], "impression": "Quadri recto haute définition", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Structure aluminium incluse", "Barre de lestage", "Sac de transport inclus", "Classement feu M1"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── roll_up_120x200 : Roll-up 120×200 cm ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'roll_up_120x200', '{}'::jsonb, 'fr', 'Roll-up 120×200 cm', array['roll-up 120x200','kakémono 120 cm','roll-up extra large','enrouleur 120x200','roll-up XXL','grand kakémono','mur d''image compact','roll-up fond de stand','banner stand 120']::text[],
  'Roll-up 120×200 cm {{finition}} — {{quantite}}', 'Avec 120 cm de large, ce roll-up joue le rôle de mini mur d''image : un impact maximal pour un encombrement de transport minimal.',
  '## Presque un fond de stand, toujours un roll-up

Le roll-up 120×200 cm est le plus large des formats courants avant le XXL. Il offre une surface d''expression proche d''un petit mur d''image tout en conservant la simplicité de l''enrouleur : un seul élément à transporter, un montage en une minute, aucune fixation nécessaire.

## Caractéristiques techniques

Impression quadri haute définition sur bâche PVC 450 g dos occultant classée M1, ou sur polyester 260-270 g M1 avec option sans PVC. La base aluminium, dotée d''une barre de lestage, assure la stabilité malgré la largeur de la voile. Sac de transport fourni. Pour aller encore plus loin, la gamme existe en 150×207 cm et en versions XXL jusqu''à 200×300 cm.

## Les avantages du 120×200

À deux ou trois exemplaires alignés, ce format compose un fond de stand continu à une fraction du prix d''une structure textile. Seul, il impose votre visuel dans un hall ou une vitrine. Et comme toute la gamme, il se réutilise saison après saison.', 'Roll-up 120×200 cm personnalisé',
  'Roll-up 120x200 cm — grand format publicitaire', 'Roll-up extra-large 120×200 cm : effet mur d''image, toile M1, structure alu et sac inclus. L''impact d''un fond de stand, la simplicité d''un enrouleur.', array['roll-up 120x200','kakémono 120x200','roll-up extra large','roll-up grand format','fond de stand économique','enrouleur 120 cm']::text[], 'Product',
  'L''impact d''un mur d''image, le prix et la simplicité d''un roll-up : le 120×200 habille un stand entier à lui seul. Alignez-en deux ou trois et votre fond de stand est prêt en cinq minutes.', '["La plus grande largeur avant le format XXL", "Effet mur d''image en alignant plusieurs unités", "Montage en une minute, sans outil ni fixation", "Structure aluminium lestée, stable malgré la largeur", "Sac de transport inclus", "Toiles classées M1 pour salons et ERP"]'::jsonb, '["Fond de stand modulaire", "Habillage de vitrine évènementielle", "Décor de conférence de presse", "Signalétique de hall d''exposition", "Point photo en magasin"]'::jsonb,
  '[{"title": "Fond de stand 3 panneaux", "description": "Trois roll-ups 120×200 juxtaposés forment un décor continu de 3,60 m, transporté dans trois sacs à main."}, {"title": "Conférence de presse", "description": "Le visuel répété de vos logos sert d''arrière-plan aux interviews et photos officielles."}, {"title": "Vitrine de lancement", "description": "Le roll-up occupe toute la hauteur de la vitrine et annonce la nouveauté aux passants, sans pose d''adhésif."}, {"title": "Entrée de séminaire", "description": "Un seul support suffit à marquer l''entrée de la plénière et orienter les participants."}]'::jsonb, '[{"question": "Comment aligner plusieurs roll-ups pour un fond continu ?", "answer": "Concevez un visuel unique découpé en lés de 120 cm en prévoyant quelques centimètres de tolérance aux jonctions : les bases se juxtaposent presque bord à bord."}, {"question": "Quelle résolution de fichier fournir ?", "answer": "Échelle 1 en 150 dpi ou échelle 1/2 en 300 dpi, en CMJN, textes vectorisés. Gardez les éléments importants loin des bords."}, {"question": "Est-il stable avec cette largeur ?", "answer": "Oui : la base aluminium intègre une barre de lestage dimensionnée pour la voile. Évitez simplement les courants d''air directs et l''extérieur."}, {"question": "Quel poids à transporter ?", "answer": "Environ 3 kg avec le sac : il se porte à une main et passe en soute ou dans un coffre de voiture sans difficulté."}, {"question": "Existe-t-il encore plus grand ?", "answer": "Oui : 150×207 cm, puis les XXL 198×207, 200×250 et 200×300 cm avec mâts télescopiques pour les fonds de scène."}]'::jsonb, '{"formats": ["120×207 cm (toile visible ~120×200 cm)"], "supports": ["Bâche PVC 450 g dos occultant M1", "Polyester 270 g M1", "Polyester 260 g sans PVC M1"], "finitions": ["Toile enroulable dans la base", "Visuel remplaçable selon modèle"], "impression": "Quadri recto haute définition", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Structure aluminium incluse", "Barre de lestage", "Sac de transport inclus", "Classement feu M1"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── x_banner : X-banner ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'x_banner', '{}'::jsonb, 'fr', 'X-banner publicitaire', array['x-banner','x banner','kakémono X','trépied publicitaire','bannière en X','support X','banner araignée','kakémono trépied','affichage léger salon']::text[],
  'X-banner {{format}} — {{quantite}}', 'Le X-banner tend votre toile sur une structure en X ultralégère : l''affichage vertical le plus économique et le plus simple à transporter.',
  '## L''affichage vertical le plus léger du marché

Le X-banner tend une toile imprimée entre les quatre branches d''une structure en croix. Résultat : un support vertical très stable visuellement, qui pèse une fraction du poids d''un roll-up et se glisse dans n''importe quel coffre. C''est la solution idéale pour multiplier les points d''affichage à petit budget.

## Caractéristiques techniques

Trois formats au choix : 60×160, 70×180 et 80×200 cm. La toile — polyester épais classé feu ou bâche PVC 330 g à dos gris occultant — reçoit quatre œillets d''angle renforcés qui s''accrochent en quelques secondes sur la structure. Les coins sont consolidés pour résister à la tension et aux montages répétés. Impression quadri haute définition. Une déclinaison extérieure existe pour les usages en terrasse ou devanture abritée.

## Les avantages du X-banner

Montage immédiat, poids plume, prix serré : le X-banner permet d''équiper plusieurs points de vente ou plusieurs salles d''un coup. La toile se démonte à plat pour un stockage minimal, et se remplace seule quand votre offre change.', 'X-banner {{format}} personnalisé',
  'X-banner personnalisé 60x160 à 80x200 cm', 'Impression X-banner : toile à œillets renforcés sur structure en X ultralégère. 3 formats, montage en 30 secondes, le support vertical le plus économique.', array['x-banner personnalisé','impression x banner','kakémono X','trépied publicitaire','bannière X 60x160','support publicitaire léger']::text[], 'Product',
  'Trente secondes de montage, un poids plume et un prix mini : le X-banner est le moyen le plus rapide de multiplier vos points d''affichage. La toile se remplace seule quand votre offre change — la structure, elle, dure des années.', '["Le support vertical le plus économique de la gamme", "Ultraléger : se transporte à une main, se range à plat", "Montage en 30 secondes par simple accrochage des œillets", "Coins renforcés pour des montages répétés", "Toile remplaçable indépendamment de la structure", "Version extérieure disponible"]'::jsonb, '["Promotion en point de vente", "Signalétique de salle de réunion", "Animation réseau multi-boutiques", "Affichage éphémère en pharmacie", "Menu ou offre du jour en CHR"]'::jsonb,
  '[{"title": "Réseau de magasins", "description": "Dix X-banners identiques déployés simultanément dans dix boutiques pour une opération nationale, à budget maîtrisé."}, {"title": "Pharmacie", "description": "Un X-banner près du comptoir met en avant la campagne de prévention du mois et se remplace à chaque saison."}, {"title": "Hôtel et restauration", "description": "À l''entrée du restaurant, la formule du midi s''affiche sur un support discret déplacé matin et soir."}, {"title": "Séminaire multi-salles", "description": "Un X-banner devant chaque salle indique l''atelier en cours ; le tout tient dans un seul carton de transport."}]'::jsonb, '[{"question": "Quelle différence entre X-banner et roll-up ?", "answer": "Le roll-up enroule la toile dans une base lestée ; le X-banner la tend sur un trépied en croix. Le X-banner est plus léger et moins cher, le roll-up plus premium et plus protecteur pour la toile."}, {"question": "La toile s''abîme-t-elle au montage ?", "answer": "Non : les quatre œillets d''angle sont renforcés précisément pour encaisser la tension à chaque installation. La toile supporte de nombreux cycles de montage."}, {"question": "Peut-on l''utiliser en extérieur ?", "answer": "Le modèle standard est prévu pour l''intérieur. Une déclinaison extérieure, avec toile plus résistante aux intempéries, couvre les usages en devanture abritée."}, {"question": "Quel fichier fournir ?", "answer": "Un PDF à l''échelle 1 en 150 dpi (CMJN, textes vectorisés), en gardant logos et accroches éloignés des angles où se placent les œillets."}, {"question": "Comment le stocker entre deux campagnes ?", "answer": "La structure se replie, la toile se roule visuel vers l''extérieur : l''ensemble tient dans un tube ou un carton plat, à l''abri de la chaleur."}]'::jsonb, '{"formats": ["60×160 cm", "70×180 cm", "80×200 cm"], "supports": ["Toile polyester ~500 g classée feu", "Bâche PVC 330 g dos gris occultant"], "finitions": ["4 œillets d''angle renforcés", "Coins consolidés anti-déchirure"], "impression": "Quadri recto haute définition", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Structure en X incluse", "Toile remplaçable seule", "Version extérieure", "Classement feu"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── drapeau : Drapeaux / Beach flags ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'drapeau', '{}'::jsonb, 'fr', 'Drapeaux publicitaires et beach flags', array['drapeau publicitaire','beach flag','oriflamme','drapeau personnalisé','wind flag','drapeau voile','drapeau entreprise','pavillon publicitaire','drapeau extérieur','drapeau événementiel']::text[],
  'Drapeau publicitaire {{format}} — {{quantite}}', 'Beach flags, oriflammes, drapeaux pour mât ou de table : toute la signalétique textile qui flotte et attire l''œil, en intérieur comme en extérieur.',
  '## Le mouvement qui attire le regard

Un drapeau bouge avec le vent — et l''œil humain est irrésistiblement attiré par le mouvement. C''est ce qui fait du drapeau publicitaire l''un des supports extérieurs les plus efficaces au mètre carré : devant un commerce, le long d''une route, à l''entrée d''un événement, il signale votre présence bien avant que le client n''arrive.

## Caractéristiques techniques

La gamme couvre tous les usages : beach flags en forme voile, goutte ou rectangle de 2 à 5 m de haut, drapeaux pour mât à potence ou à drisse, versions double face, arches, guirlandes de fanions, jusqu''aux mini-drapeaux de table et à ventouse. Impression par sublimation sur maille polyester 110 g classée M1 : le visuel traverse le tissu et reste lisible au verso par transparence. Structures aluminium ou fibre de verre selon modèles.

## Les avantages de la gamme

Mât, pied, fixations et housse de transport sont fournis avec les modèles autoportants. Le textile se lave et se réutilise plusieurs saisons ; le visuel se remplace seul quand votre communication évolue.', 'Drapeaux publicitaires personnalisés',
  'Drapeau publicitaire personnalisé — beach flag', 'Drapeaux publicitaires imprimés : beach flags 2 à 5 m, drapeaux pour mât, double face, fanions. Polyester M1, mât et pied inclus, lisible recto verso.', array['drapeau publicitaire','beach flag personnalisé','oriflamme publicitaire','drapeau pour mât','wind flag','drapeau double face','fanions personnalisés']::text[], 'Product',
  'Un drapeau travaille pour vous à chaque coup de vent : il signale votre commerce ou votre événement à des dizaines de mètres. Mât, pied et housse compris — plantez-le, il fait le reste.', '["Visibilité en mouvement, repérable de très loin", "Impression traversante : lisible des deux côtés", "Textile M1 lavable et réutilisable plusieurs saisons", "Mât, pied et housse fournis sur les modèles autoportants", "Formes et hauteurs pour chaque emplacement (2 à 5 m)", "Visuel remplaçable sans changer la structure"]'::jsonb, '["Devanture de commerce", "Entrée d''événement sportif", "Signalétique de parking ou d''accès", "Stand extérieur de foire", "Balisage de parcours"]'::jsonb,
  '[{"title": "Concession en bord de route", "description": "Une rangée de beach flags signale les portes ouvertes aux automobilistes plusieurs centaines de mètres en amont."}, {"title": "Course à pied", "description": "Des oriflammes balisent le départ, l''arrivée et les ravitaillements, visibles au-dessus de la foule."}, {"title": "Terrasse de restaurant", "description": "Un drapeau goutte marque l''entrée de la terrasse et affiche la carte estivale, lesté sur platine."}, {"title": "Siège d''entreprise", "description": "Les drapeaux pour mât pavoisent l''entrée du site aux couleurs de la marque, hissés à la drisse."}]'::jsonb, '[{"question": "Le visuel est-il lisible des deux côtés ?", "answer": "En impression standard, le motif traverse la maille polyester et se lit au verso en miroir par transparence. Pour une lecture correcte des deux côtés, choisissez l''option double face."}, {"question": "Quel pied choisir pour mon beach flag ?", "answer": "Piquet à visser pour la terre, le sable ou la pelouse ; platine ou réservoir lestable (eau ou sable) pour le bitume, les dalles et les terrasses."}, {"question": "Un drapeau résiste-t-il au vent fort ?", "answer": "Le mât pivote avec le vent, ce qui limite les contraintes. Par rafales importantes, il reste recommandé de rentrer le drapeau, comme toute signalétique textile."}, {"question": "Comment entretenir le textile ?", "answer": "Lavage à l''eau tiède avec un détergent doux, séchage à l''air libre. Bien entretenu, un drapeau se réutilise plusieurs saisons."}, {"question": "Quel fichier fournir ?", "answer": "Un PDF vectoriel ou à l''échelle 1 en 150 dpi, en CMJN. Anticipez la forme (voile, goutte) : nous fournissons les gabarits de chaque taille."}]'::jsonb, '{"formats": ["Beach flags : hauteurs 200, 300, 400 et 500 cm", "Drapeaux pour mât : sur-mesure selon hauteur de mât", "Mini-drapeaux de table et à ventouse"], "supports": ["Maille polyester 110 g classée M1, impression traversante"], "finitions": ["Liseré noir ou blanc", "Fourreau de mât", "Double face en option", "Orientation gauche ou droite"], "impression": "Sublimation quadri traversante", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 4 à 6 jours ouvrés, express possible", "options": ["Mât aluminium rotatif inclus", "Pied platine lestable ou piquet", "Housse de transport incluse", "Classement feu M1"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── beach_flag : Beach flag / Oriflamme ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'beach_flag', '{}'::jsonb, 'fr', 'Beach flag / Oriflamme personnalisée', array['beach flag','oriflamme','drapeau voile','drapeau plume','drapeau goutte','wind flag','beach flag personnalisé','voile publicitaire','drapeau publicitaire extérieur','oriflamme événement']::text[],
  'Beach flag {{format}} {{finition}} — {{quantite}}', 'Oriflamme voile, goutte ou rectangle de 2 à 5 m : le mât rotatif suit le vent et votre visuel reste toujours déployé, dedans comme dehors.',
  '## Votre enseigne qui flotte au vent

Le beach flag — ou oriflamme — est la signalétique extérieure la plus repérable qui soit : sa voile textile montée sur un mât courbe reste déployée même sans vent, et son mouvement attire l''œil à grande distance. Devant une boutique, sur un salon en plein air ou le long d''un parcours sportif, il fait office d''enseigne mobile.

## Caractéristiques techniques

Quatre hauteurs de structure : 200, 300, 400 et 500 cm, pour des visuels d''environ 170 à 448 cm de haut sur 70 cm de large. Trois formes au choix : voile (plume), goutte d''eau ou rectangle. La maille polyester 110 g classée M1 est imprimée par sublimation en quadri : le visuel traverse le tissu et se lit au verso par transparence. Le mât aluminium pivote sur rotule pour suivre le vent sans forcer.

## Les avantages du beach flag

Chaque kit comprend le mât, la housse de transport et le pied de votre choix : piquet pour sols meubles ou platine lestable pour surfaces dures. Montage en deux minutes, textile lavable, visuel remplaçable — un investissement qui ressert à chaque saison.', 'Beach flag {{format}} personnalisé',
  'Beach flag personnalisé 2 à 5 m — oriflamme', 'Impression beach flag : voile, goutte ou rectangle de 2 à 5 m, polyester M1 sublimé, mât rotatif, pied et housse inclus. Visible de très loin.', array['beach flag personnalisé','oriflamme publicitaire','drapeau voile','drapeau goutte d''eau','wind flag entreprise','beach flag 4m','voile publicitaire extérieure']::text[], 'Product',
  'Plantez-le devant votre porte et laissez le vent travailler : le beach flag signale votre activité à des centaines de mètres, jour après jour. Kit complet mât, pied et housse — opérationnel en deux minutes.', '["Repérable à très grande distance grâce au mouvement", "Voile toujours déployée, même sans vent", "Mât rotatif qui suit les rafales sans se déformer", "Kit complet : mât, pied au choix et housse inclus", "Textile M1 lavable, réutilisable plusieurs saisons", "4 hauteurs et 3 formes pour chaque emplacement"]'::jsonb, '["Entrée de magasin ou d''agence", "Village départ d''événement sportif", "Stand extérieur de foire", "Signalétique de drive ou parking", "Ouverture ou portes ouvertes"]'::jsonb,
  '[{"title": "Boulangerie de centre-ville", "description": "Une oriflamme goutte de 2,5 m sur platine lestée signale la boutique aux piétons des deux côtés de la rue."}, {"title": "Triathlon", "description": "Des beach flags de 4 m aux couleurs des sponsors balisent la zone de transition, plantés au piquet dans la pelouse."}, {"title": "Agence immobilière en salon", "description": "Deux voiles encadrent le stand extérieur et se lisent par transparence quel que soit le sens du vent."}, {"title": "Station de lavage", "description": "Un drapeau de 5 m capte les automobilistes depuis l''axe routier, à hauteur des enseignes voisines."}]'::jsonb, '[{"question": "Quelle hauteur choisir ?", "answer": "2-3 m pour une visibilité piétonne en centre-ville, 4-5 m pour capter des automobilistes ou émerger au-dessus d''une foule ou d''autres stands."}, {"question": "Piquet ou platine : comment trancher ?", "answer": "Piquet à visser pour la terre, le sable et l''herbe ; platine ou réservoir remplissable (eau/sable, environ 17 L) pour le bitume et les terrasses."}, {"question": "Le visuel se lit-il des deux côtés ?", "answer": "L''impression traversante rend le verso lisible en miroir par transparence — largement suffisant pour un logo. Un vrai double face existe pour les textes longs."}, {"question": "Que faire en cas de vent fort ?", "answer": "La rotule laisse le drapeau pivoter avec le vent en usage normal. Par tempête annoncée, démontez la voile : deux minutes suffisent et votre matériel dure plus longtemps."}, {"question": "Quel fichier fournir ?", "answer": "Utilisez le gabarit de la forme et de la taille choisies, en CMJN, échelle 1 à 150 dpi. Pensez à indiquer l''orientation gauche ou droite du visuel."}]'::jsonb, '{"formats": ["Structure 70×200 cm (visuel ~70×170)", "70×300 cm (visuel ~70×228)", "70×400 cm (visuel ~70×338)", "70×500 cm (visuel ~70×448)"], "supports": ["Maille polyester 110 g ignifugée M1"], "finitions": ["Formes voile, goutte ou rectangle", "Liseré noir ou blanc", "Orientation gauche/droite", "Double face en option"], "impression": "Sublimation quadri traversante, lecture verso par transparence", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 4 à 6 jours ouvrés, express possible", "options": ["Mât aluminium rotatif inclus", "Pied platine lestable 17 L ou piquet de sol", "Housse de transport incluse", "Classement feu M1"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── drapeau_mat : Drapeau pour mât ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'drapeau_mat', '{}'::jsonb, 'fr', 'Drapeau pour mât (potence ou drisse)', array['drapeau pour mât','drapeau à potence','drapeau à drisse','pavillon d''entreprise','drapeau de façade','pavoisement','drapeau siège social','drapeau institutionnel','drapeau vertical']::text[],
  'Drapeau pour mât {{format}} — {{quantite}}', 'Drapeau à hisser sur mât à potence ou à drisse : le pavoisement permanent qui affiche vos couleurs à l''entrée de votre site, par tous les temps.',
  '## Vos couleurs en haut du mât

Le drapeau pour mât est la signalétique institutionnelle par excellence : hissé devant un siège social, un hôtel, une mairie ou un site industriel, il affiche durablement votre identité. Sur mât à potence, le tissu reste déployé même sans vent ; sur mât à drisse classique, il flotte librement.

## Caractéristiques techniques

Fabrication sur mesure selon la hauteur de votre mât et le mode de fixation : fourreau pour potence, sangle et mousquetons pour drisse. La maille polyester 110 g classée M1 est imprimée par sublimation traversante — votre logo se lit des deux côtés par transparence, et une version double face cousue existe pour les visuels comportant du texte. Les finitions (ourlets renforcés, liseré) sont dimensionnées pour un usage extérieur permanent.

## Les avantages du drapeau pour mât

C''est un support qui travaille en continu, 365 jours par an, sans emprise au sol ni autorisation d''affichage dans la plupart des cas. Le textile se remplace seul lors des rotations saisonnières : vous conservez mât et accastillage.', 'Drapeau pour mât personnalisé',
  'Drapeau pour mât personnalisé — potence, drisse', 'Drapeaux d''entreprise pour mât à potence ou à drisse : polyester M1 sublimé, finitions renforcées extérieur, sur-mesure selon votre mât.', array['drapeau pour mât','drapeau à potence','pavillon entreprise','drapeau de façade','pavoisement société','drapeau siège social']::text[], 'Product',
  'Un mât pavoisé se voit avant votre enseigne : affichez vos couleurs en continu devant votre site, sans emprise au sol. Le tissu se remplace en cinq minutes — le mât, lui, dure des décennies.', '["Visibilité permanente en hauteur, de jour comme de nuit", "Compatible mâts à potence (tissu toujours déployé) et à drisse", "Sur-mesure adapté à la hauteur de votre mât", "Finitions renforcées pour l''exposition extérieure continue", "Impression traversante lisible des deux côtés", "Remplacement du seul textile lors des rotations"]'::jsonb, '["Pavoisement de siège social", "Entrée d''hôtel ou de camping", "Site industriel ou logistique", "Concession et retail park", "Collectivité et équipement public"]'::jsonb,
  '[{"title": "Siège d''entreprise", "description": "Trois mâts pavoisés à l''entrée du parking affichent la marque, la certification et le drapeau européen."}, {"title": "Hôtellerie de plein air", "description": "Les drapeaux à potence de l''accueil restent lisibles même par temps calme, ce qui garantit l''effet d''entrée toute la saison."}, {"title": "Retail park", "description": "Chaque enseigne du parc dispose de son pavillon le long de l''allée d''accès, visible depuis la rocade."}, {"title": "Événement institutionnel", "description": "Le parvis est pavoisé aux couleurs de la manifestation pendant un mois, puis les drapeaux d''origine sont rehissés."}]'::jsonb, '[{"question": "Potence ou drisse : quelle différence ?", "answer": "La potence est un bras horizontal qui maintient le drapeau déployé même sans vent — idéal pour la lisibilité permanente. La drisse est le cordage classique : le drapeau flotte librement."}, {"question": "Quelle taille de drapeau pour mon mât ?", "answer": "On recommande un drapeau d''environ un quart à un tiers de la hauteur du mât. Communiquez-nous la hauteur et le type de fixation : nous fabriquons sur mesure."}, {"question": "Combien de temps dure un drapeau hissé en permanence ?", "answer": "Exposé au vent et aux UV en continu, un drapeau se remplace généralement chaque année, davantage en site abrité. Prévoir un jeu de rechange permet une rotation sans interruption."}, {"question": "Le logo est-il lisible des deux côtés ?", "answer": "Oui, par transparence (en miroir au verso). Si votre visuel comporte du texte important, optez pour la confection double face."}, {"question": "Peut-on laver le drapeau ?", "answer": "Oui, à l''eau tiède avec un détergent doux, séchage à l''air libre. Un lavage régulier prolonge nettement la tenue des couleurs."}]'::jsonb, '{"formats": ["Sur-mesure selon la hauteur du mât et le mode de fixation"], "supports": ["Maille polyester 110 g classée M1"], "finitions": ["Fourreau pour potence", "Sangle et anneaux pour drisse", "Ourlets renforcés", "Confection double face en option"], "impression": "Sublimation quadri traversante", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 4 à 6 jours ouvrés, express possible", "options": ["Classement feu M1", "Jeu de rechange pour rotation", "Liseré de finition"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── banderole : Banderoles / Bâches ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'banderole', '{}'::jsonb, 'fr', 'Banderoles et bâches publicitaires', array['banderole','bâche publicitaire','banderole personnalisée','bâche imprimée','banderole avec œillets','bâche PVC','calicot','banderole extérieure','bâche de chantier','banderole événement']::text[],
  'Banderole {{format}} {{finition}} — {{quantite}}', 'Bâches PVC, mesh micro-perforé ou textile : la banderole sur mesure au centimètre, avec œillets et fourreaux positionnés selon votre pose.',
  '## Le grand format qui s''accroche partout

Barrière de chantier, façade, grille d''école, podium ou fond de scène : la banderole imprimée transforme n''importe quel support de fixation en espace publicitaire. Fabriquée au centimètre près, elle s''adapte exactement à votre emplacement — c''est vous qui donnez les dimensions.

## Caractéristiques techniques

La gamme couvre tous les besoins : bâche PVC de 340 à 510 g et plus pour l''extérieur durable, mesh micro-perforé pour les zones ventées, textile polyester classé M1 pour l''intérieur événementiel, polypropylène léger pour les opérations courtes, et options sans PVC plus responsables. Finitions au choix : ourlet, fourreaux, soudures renforcées et œillets métalliques dont vous définissez le nombre et l''espacement. Impression quadri haute définition résistante aux UV.

## Les avantages de la gamme

Une banderole se pose en quelques minutes avec des colliers ou des tendeurs, se démonte aussi vite et se stocke roulée pour resservir. Le rapport surface de communication / prix est imbattable parmi les supports grand format.', 'Banderole publicitaire {{format}} sur mesure',
  'Banderole publicitaire sur mesure — bâche imprimée', 'Impression de banderoles et bâches au cm : PVC 340-510 g, mesh anti-vent, textile M1. Œillets et fourreaux sur mesure, quadri résistante aux UV.', array['banderole personnalisée','bâche publicitaire','impression banderole','banderole avec œillets','bâche sur mesure','banderole extérieure','calicot publicitaire']::text[], 'Product',
  'Donnez-nous vos dimensions et votre message : votre banderole arrive prête à poser, œillets placés exactement où il faut. Le mètre carré de visibilité le plus économique du grand format.', '["Fabrication sur mesure au centimètre", "Œillets : nombre et espacement définis par vos soins", "Matières adaptées à chaque durée et exposition", "Impression quadri résistante aux UV et aux intempéries", "Pose et dépose en quelques minutes", "Se stocke roulée et se réutilise"]'::jsonb, '["Palissade et barrière de chantier", "Façade de magasin en promotion", "Grille d''école ou de club sportif", "Fond de podium événementiel", "Annonce de foire ou brocante"]'::jsonb,
  '[{"title": "Chantier immobilier", "description": "Une bâche au nom du programme couvre la palissade pendant toute la construction et affiche le contact commercial."}, {"title": "Soldes en façade", "description": "La banderole promotionnelle se fixe au-dessus de la vitrine en dix minutes et se retire à la fin de l''opération."}, {"title": "Club de sport", "description": "Les banderoles des sponsors habillent la main courante du terrain, œillets tous les 50 cm pour une pose tendue."}, {"title": "Événement municipal", "description": "Des calicots annoncent la fête locale aux entrées de ville trois semaines avant la date."}]'::jsonb, '[{"question": "Quel grammage de bâche choisir ?", "answer": "340 g pour l''intérieur et les opérations courtes, 450 g laminée pour un usage polyvalent, 510 g enduite pour l''extérieur longue durée. En zone ventée, préférez le mesh micro-perforé."}, {"question": "Combien d''œillets prévoir ?", "answer": "Comptez un œillet tous les 30 à 50 cm sur le périmètre pour une pose tendue et durable. Vous définissez le nombre et l''espacement à la commande."}, {"question": "Quel fichier pour une grande bâche ?", "answer": "Un PDF à l''échelle 1/10 en 300 dpi (soit 30 dpi à taille réelle, largement suffisant vu la distance de lecture), en CMJN, avec textes vectorisés."}, {"question": "Combien de temps tient une banderole dehors ?", "answer": "Une bâche 510 g correctement tendue tient plusieurs années en extérieur. Les grammages plus légers sont dimensionnés pour quelques semaines à quelques mois."}, {"question": "Que faire si l''emplacement est très exposé au vent ?", "answer": "Choisissez la version micro-perforée : ses micro-trous laissent passer l''air et réduisent fortement la prise au vent, notamment sur grilles et échafaudages."}]'::jsonb, '{"formats": ["Sur mesure au centimètre, du petit calicot aux très grands formats de façade"], "supports": ["Bâche PVC laminée 340 g", "Bâche PVC frontlit laminée 450 g M1", "Bâche PVC enduite 510 g", "Mesh micro-perforé", "Textile polyester M1", "Polypropylène léger 135 g", "Option sans PVC"], "finitions": ["Œillets métalliques (nombre et espacement au choix)", "Ourlet", "Fourreaux", "Soudures renforcées", "Traitement anti-tuilage"], "impression": "Quadri haute définition résistante aux UV", "quantites": "1 à 100 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Classement feu M1/B1 selon support", "Recto-verso à dos occultant", "Version écologique sans PVC"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── bache_pvc : Bâche PVC ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'bache_pvc', '{}'::jsonb, 'fr', 'Bâche PVC avec œillets', array['bâche PVC','bâche 510g','bâche extérieure','bâche avec œillets','bâche imprimée','bâche publicitaire PVC','bâche de façade','bâche chantier','banderole PVC']::text[],
  'Bâche PVC {{format}} {{finition}} — {{quantite}}', 'Bâche PVC 450 à 510 g imprimée en quadri anti-UV, œillets et ourlets sur mesure : le support extérieur robuste qui tient plusieurs saisons.',
  '## La référence de l''affichage extérieur durable

La bâche PVC est le support grand format le plus robuste de la gamme banderoles. Sa toile enduite ou laminée encaisse la pluie, le vent modéré et les UV sans se déformer ni pâlir : c''est le choix naturel pour les chantiers, les façades et toutes les communications extérieures qui doivent durer.

## Caractéristiques techniques

Deux qualités principales : la 450 g laminée, classée feu M1, polyvalente intérieur/extérieur, et la 510 g enduite pour les expositions prolongées. Fabrication sur mesure au centimètre, impression quadri haute définition traitée anti-UV et anti-tuilage. Finitions au choix : ourlets soudés, fourreaux pour passage de barre ou de tendeur, œillets métalliques dont vous définissez le nombre, la position et l''espacement.

## Les avantages de la bâche PVC

Une pose simple aux colliers ou sandows, une résistance mécanique qui autorise une tension franche, et une durée de vie de plusieurs saisons en extérieur. Roulée entre deux campagnes, elle ressert autant de fois que nécessaire.', 'Bâche PVC {{format}} avec œillets',
  'Bâche PVC imprimée 450-510 g avec œillets', 'Bâche PVC sur mesure : 450 g laminée M1 ou 510 g enduite longue durée. Œillets, ourlets, fourreaux au choix. Quadri anti-UV, tient des saisons.', array['bâche PVC imprimée','bâche 510g','bâche extérieure personnalisée','bâche avec œillets','bâche de chantier','bâche façade sur mesure']::text[], 'Product',
  'Une bâche 510 g bien tendue affiche votre message des saisons entières, sous la pluie comme en plein soleil. Sur mesure au centimètre, œillets où vous les voulez : elle arrive prête à poser.', '["Résistance mécanique élevée : tension franche sans déchirure", "Encres anti-UV : couleurs stables dans la durée", "Sur mesure au centimètre, adaptée à votre emplacement", "Œillets, ourlets et fourreaux configurables", "Classement feu M1 disponible (version laminée 450 g)", "Réutilisable : se roule et se stocke entre deux campagnes"]'::jsonb, '["Bâche de chantier longue durée", "Habillage de façade commerciale", "Clôture de terrain de sport", "Signalétique d''entrepôt", "Communication saisonnière récurrente"]'::jsonb,
  '[{"title": "Palissade de chantier", "description": "Une bâche 510 g de 6 m annonce le futur programme immobilier et reste impeccable jusqu''à la livraison."}, {"title": "Façade de zone commerciale", "description": "La bâche promotionnelle fixée sur la structure du bâtiment se voit depuis le parking et l''axe routier."}, {"title": "Stade municipal", "description": "Les bâches des partenaires tendues sur la main courante résistent aux ballons comme aux intempéries."}, {"title": "Marché de Noël", "description": "La même bâche d''enseigne ressort chaque année : roulée et stockée au sec, elle est comme neuve."}]'::jsonb, '[{"question": "450 g ou 510 g : comment choisir ?", "answer": "La 450 g laminée M1 convient à la majorité des usages, y compris en intérieur réglementé. La 510 g enduite est plus dense et plus résistante : privilégiez-la pour l''extérieur longue durée et les grandes dimensions."}, {"question": "Combien de temps tient-elle en extérieur ?", "answer": "Correctement tendue et fixée, une bâche PVC 510 g reste en place plusieurs années. Le point critique n''est pas la toile mais la qualité de la pose et des fixations."}, {"question": "Comment bien la poser ?", "answer": "Tendez progressivement en croix, en partant des angles, avec colliers ou sandows sur chaque œillet. Une bâche flottante s''use prématurément aux points de fixation."}, {"question": "Quel fichier fournir ?", "answer": "PDF à l''échelle 1/10 en 300 dpi, CMJN, textes vectorisés. Gardez 5 cm de marge de sécurité le long des bords où passent ourlets et œillets."}, {"question": "Et si mon emplacement est très venté ?", "answer": "Au-delà d''une exposition modérée, basculez sur la bâche micro-perforée : elle laisse passer l''air et soulage fixations et structure."}]'::jsonb, '{"formats": ["Sur mesure au centimètre, jusqu''aux très grands formats de façade"], "supports": ["Bâche PVC frontlit laminée 450 g M1", "Bâche PVC enduite 510 g"], "finitions": ["Œillets métalliques (nombre, position, espacement au choix)", "Ourlets soudés", "Fourreaux", "Soudures renforcées"], "impression": "Quadri haute définition anti-UV, traitement anti-tuilage", "quantites": "1 à 100 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Classement feu M1 (450 g laminée)", "Version recto-verso à dos occultant"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── banderole_microperforee : Bâche micro-perforée ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'banderole_microperforee', '{}'::jsonb, 'fr', 'Bâche micro-perforée (mesh anti-vent)', array['bâche micro-perforée','mesh publicitaire','bâche anti-vent','banderole ajourée','bâche échafaudage','bâche grille','toile mesh','bâche clôture','banderole zone ventée']::text[],
  'Bâche micro-perforée {{format}} — {{quantite}}', 'Le mesh micro-perforé laisse passer le vent : la bâche qui reste en place sur grilles, clôtures et échafaudages, même en site exposé.',
  '## La bâche qui laisse passer le vent

Sur une grille de chantier, un échafaudage ou une clôture de stade, une bâche pleine se transforme en voile : elle tire sur ses fixations et finit par céder. La bâche micro-perforée résout le problème à la source : ses milliers de micro-trous laissent l''air circuler et réduisent drastiquement la prise au vent, tout en conservant un visuel parfaitement lisible à distance de lecture.

## Caractéristiques techniques

Toile PVC ajourée fabriquée sur mesure au centimètre, imprimée en quadri haute définition anti-UV. Finitions identiques aux bâches pleines : ourlets, fourreaux et œillets métalliques positionnés selon votre plan de pose. La structure ajourée allège aussi la toile, ce qui facilite la manutention des très grands formats.

## Les avantages du mesh

C''est la seule solution sérieuse pour les emplacements exposés : bord de mer, hauteur, grandes surfaces suspendues. Elle préserve vos fixations et votre support d''accroche, laisse filtrer la lumière derrière elle et se réutilise comme n''importe quelle bâche.', 'Bâche micro-perforée {{format}} anti-vent',
  'Bâche micro-perforée sur mesure — mesh anti-vent', 'Bâche mesh micro-perforée : la toile ajourée qui laisse passer le vent. Idéale grilles, clôtures, échafaudages. Sur mesure, œillets au choix.', array['bâche micro-perforée','mesh publicitaire','bâche anti-vent','bâche échafaudage','toile ajourée imprimée','banderole grille de chantier']::text[], 'Product',
  'En site venté, la question n''est pas si une bâche pleine va céder, mais quand : le mesh micro-perforé laisse passer l''air et reste en place. Grande surface, grand vent, zéro souci.', '["Prise au vent réduite de façon drastique", "Préserve fixations et supports d''accroche", "Lisibilité intacte à distance de lecture", "Plus légère qu''une bâche pleine à surface égale", "Laisse filtrer lumière et visibilité résiduelle derrière la toile", "Sur mesure au centimètre avec œillets configurables"]'::jsonb, '["Habillage d''échafaudage", "Grille de chantier exposée", "Clôture de stade ou de festival", "Signalétique en bord de mer", "Très grands formats suspendus"]'::jsonb,
  '[{"title": "Échafaudage de ravalement", "description": "Le mesh couvre 100 m² de façade en travaux avec le visuel du maître d''ouvrage, sans transformer la structure en voile."}, {"title": "Festival en plein air", "description": "Les clôtures du site sont habillées de mesh aux couleurs de l''événement : l''air circule, les barrières restent stables."}, {"title": "Port de plaisance", "description": "Face aux vents marins, la banderole du chantier naval reste tendue là où une toile pleine ne tenait pas une saison."}, {"title": "Chantier en hauteur", "description": "La bâche du programme immobilier posée au 5e niveau supporte les rafales sans arracher ses œillets."}]'::jsonb, '[{"question": "Le visuel est-il moins lisible avec les perforations ?", "answer": "À distance normale de lecture (quelques mètres et au-delà), l''œil reconstitue le visuel : les micro-trous sont invisibles. Seule la lecture à moins d''un mètre révèle la trame."}, {"question": "Quelle réduction de prise au vent ?", "answer": "La structure ajourée laisse passer une part importante du flux d''air, ce qui réduit très fortement l''effort sur les fixations par rapport à une toile pleine de même surface."}, {"question": "Peut-on l''utiliser en intérieur ?", "answer": "Oui, notamment suspendue dans les grands volumes : sa légèreté simplifie l''accroche. Mais son terrain de jeu naturel reste l''extérieur exposé."}, {"question": "Quelles finitions sont possibles ?", "answer": "Les mêmes que sur bâche pleine : ourlets, fourreaux, œillets dont vous choisissez le nombre et l''espacement selon votre plan de fixation."}, {"question": "Quel fichier fournir ?", "answer": "PDF échelle 1/10 en 300 dpi, CMJN. Privilégiez les visuels contrastés à gros éléments : ils traversent mieux la trame ajourée."}]'::jsonb, '{"formats": ["Sur mesure au centimètre, adaptée aux très grandes surfaces"], "supports": ["Toile PVC mesh micro-perforée"], "finitions": ["Œillets métalliques (nombre et espacement au choix)", "Ourlets", "Fourreaux", "Soudures renforcées"], "impression": "Quadri haute définition anti-UV", "quantites": "1 à 100 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Adaptée grilles, clôtures et échafaudages", "Grands formats en plusieurs lés soudés"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── banderole_textile : Banderole textile ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'banderole_textile', '{}'::jsonb, 'fr', 'Banderole textile polyester M1', array['banderole textile','banderole tissu','toile polyester imprimée','banderole M1','banderole intérieure','toile événementielle','banderole sans PVC','tissu publicitaire','banderole salon']::text[],
  'Banderole textile {{format}} — {{quantite}}', 'La banderole en polyester M1 : rendu mat sans reflet, toucher tissu et classement feu — le choix élégant pour l''intérieur événementiel.',
  '## L''élégance du tissu pour vos événements

Là où la bâche PVC brille et claque, la banderole textile tombe avec souplesse et offre un rendu mat, sans reflet sous les éclairages de salon ou de scène. C''est le support privilégié des événements en intérieur : congrès, remises de prix, retail haut de gamme, habillage de scène.

## Caractéristiques techniques

Toile polyester classée feu M1 — un prérequis dans la plupart des parcs d''exposition et établissements recevant du public. Impression par sublimation : les encres pénètrent la fibre pour des couleurs profondes qui ne craquellent pas au pliage. Fabrication sur mesure au centimètre, finitions ourlets, fourreaux et œillets selon votre mode d''accroche. Nettement plus légère qu''une bâche équivalente, elle se plie dans un carton au lieu de se rouler.

## Les avantages du textile

Transport compact, pose facile, repassage possible à basse température : la banderole tissu se réutilise d''événement en événement sans marque de pli durable. Une alternative sans PVC, appréciée aussi pour les démarches RSE.', 'Banderole textile {{format}} classée M1',
  'Banderole textile M1 — toile polyester sublimée', 'Banderole tissu polyester M1 : rendu mat sans reflet, sublimation haute qualité, pliable et réutilisable. La référence de l''intérieur événementiel.', array['banderole textile','banderole tissu personnalisée','toile polyester M1','banderole intérieure salon','banderole sans PVC','toile sublimée événement']::text[], 'Product',
  'Sous les projecteurs d''un salon, une bâche brille — un textile, non. La banderole tissu M1 combine rendu premium, conformité feu et transport plié dans un simple carton.', '["Rendu mat premium, aucun reflet sous éclairage", "Classement feu M1 exigé en salon et ERP", "Sublimation : couleurs profondes, résistantes au pliage", "Légère : transport plié, volume minimal", "Alternative sans PVC pour vos engagements RSE", "Réutilisable de nombreux événements"]'::jsonb, '["Habillage de stand de salon", "Fond de scène de conférence", "Remise de prix et gala", "Décor de boutique premium", "Signalétique suspendue en hall"]'::jsonb,
  '[{"title": "Plénière de congrès", "description": "La toile textile de 6 m tendue derrière la scène reste parfaitement mate face aux projecteurs et aux photos."}, {"title": "Stand haut de gamme", "description": "Les banderoles tissu de l''enseigne remplacent la bâche PVC et alignent le stand sur les codes premium de la marque."}, {"title": "Boutique éphémère", "description": "Suspendue au plafond, la banderole légère annonce le pop-up store sans structure lourde."}, {"title": "Tournée événementielle", "description": "Le kit de banderoles voyage plié dans une valise et ressort impeccable à chaque étape après un passage à la vapeur."}]'::jsonb, '[{"question": "Le textile se froisse-t-il au transport ?", "answer": "Les plis légers disparaissent d''eux-mêmes une fois la toile tendue. Pour un rendu parfait immédiat, un repassage à basse température ou un défroisseur vapeur suffit."}, {"question": "Le M1 est-il vraiment nécessaire ?", "answer": "Dans la quasi-totalité des parcs d''exposition et des ERP, oui : la commission de sécurité peut exiger le procès-verbal de classement. Nos toiles M1 vous couvrent."}, {"question": "Textile ou bâche PVC pour l''intérieur ?", "answer": "Textile pour le rendu (mat, tombé souple, pas de reflet) et la légèreté ; bâche pour l''opacité totale et les usages mixtes intérieur/extérieur."}, {"question": "Peut-on la laver ?", "answer": "Oui, lavage doux à basse température : la sublimation teint la fibre dans la masse, les couleurs ne partent pas au lavage."}, {"question": "Quelles finitions choisir ?", "answer": "Œillets pour une pose tendue sur structure, fourreau pour un passage de barre ou une suspension, ourlet simple pour un tombé libre."}]'::jsonb, '{"formats": ["Sur mesure au centimètre"], "supports": ["Toile polyester classée feu M1, option sans PVC"], "finitions": ["Ourlets", "Fourreaux", "Œillets (nombre et espacement au choix)"], "impression": "Sublimation quadri haute définition", "quantites": "1 à 100 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Classement feu M1", "Transport plié", "Lavable à basse température"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── panneau : Panneaux rigides ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'panneau', '{}'::jsonb, 'fr', 'Panneaux rigides imprimés', array['panneau rigide','panneau publicitaire','panneau imprimé','panneau personnalisé','impression sur panneau','panneau signalétique','panneau extérieur','enseigne rigide','panneau événement','support rigide']::text[],
  'Panneau rigide {{format}} {{finition}} — {{quantite}}', 'Akylux, Dibond, Forex, plexiglass, carton plume : le bon support rigide pour chaque usage, imprimé en direct et découpé à vos dimensions ou à la forme.',
  '## Un support rigide pour chaque usage

Du panneau immobilier posé une saison à l''enseigne qui doit durer dix ans, la famille des panneaux rigides couvre toute la signalétique plane : plaques professionnelles, panneaux de chantier, PLV, décoration murale, signalétique directionnelle. Le secret d''un bon panneau, c''est le bon matériau — et nous les proposons tous.

## Caractéristiques techniques

Au catalogue : Akylux (polypropylène alvéolaire léger et économique, 3 à 5 mm), Forex (PVC expansé polyvalent, 3 à 5 mm), Dibond (composite aluminium premium 3 mm), plexiglass 4 mm pour les plaques haut de gamme, carton plume et supports cartonnés recyclables pour l''intérieur. Formats standard de 20×30 à 80×120 cm et sur-mesure jusqu''à 150×200 cm selon matière. Impression quadri directe haute définition, recto ou recto-verso selon support.

## Les avantages de la gamme

Découpe droite ou à la forme, perçage, œillets, pelliculages mat, brillant ou texturés : chaque panneau sort de production prêt à poser. Dès l''exemplaire unique, avec tarif dégressif en série.', 'Panneaux rigides imprimés sur mesure',
  'Panneau rigide imprimé — Akylux, Dibond, Forex', 'Impression sur panneaux rigides : Akylux, Forex, Dibond, plexiglass, carton plume. Sur mesure jusqu''à 150×200 cm, découpe à la forme, dès 1 exemplaire.', array['panneau rigide imprimé','impression panneau','panneau publicitaire personnalisé','panneau akilux','panneau dibond','panneau forex','enseigne rigide']::text[], 'Product',
  'Un panneau pour chaque besoin : l''Akylux léger pour une saison, le Dibond premium pour dix ans. Dites-nous l''usage, nous vous orientons vers la bonne matière — imprimée, découpée, prête à poser.', '["Cinq familles de matériaux pour couvrir tous les usages", "Sur-mesure au centimètre jusqu''à 150×200 cm", "Découpe à la forme, perçage et œillets en option", "Impression directe quadri, recto ou recto-verso", "Dès 1 exemplaire, tarif dégressif en série", "Pelliculages de protection et de finition"]'::jsonb, '["Panneau immobilier ou de chantier", "Enseigne et plaque professionnelle", "Signalétique directionnelle de site", "PLV rigide en point de vente", "Décoration murale d''entreprise"]'::jsonb,
  '[{"title": "Agence immobilière", "description": "Des panneaux Akylux « à vendre » en série, légers à poser sur piquet et assez durables pour toute la commercialisation."}, {"title": "Cabinet médical", "description": "Une plaque plexiglass sur entretoises affiche les praticiens à l''entrée avec un rendu haut de gamme."}, {"title": "Site industriel", "description": "La signalétique directionnelle en Dibond guide visiteurs et livreurs, insensible aux intempéries pendant des années."}, {"title": "Salon professionnel", "description": "Des panneaux Forex découpés à la forme du logo animent le stand et se réutilisent à chaque édition."}]'::jsonb, '[{"question": "Quel matériau pour quel usage ?", "answer": "Akylux pour le temporaire extérieur économique, Forex pour le polyvalent intérieur/extérieur, Dibond pour le durable premium, plexiglass pour les plaques élégantes, carton plume pour l''intérieur léger et l''événementiel."}, {"question": "Quelle est la taille maximale d''un panneau ?", "answer": "Jusqu''à 150×200 cm en Akylux, 145×200 cm en Forex 4 mm, 115×200 cm en plexiglass — en une seule pièce. Au-delà, on assemble plusieurs panneaux."}, {"question": "Peut-on découper le panneau à la forme de mon logo ?", "answer": "Oui, la découpe de forme libre est disponible sur la plupart des matières : fournissez le tracé vectoriel de découpe dans votre fichier."}, {"question": "Comment fixer un panneau rigide ?", "answer": "Perçage et œillets pour colliers ou vis, adhésif structural pour pose murale, entretoises pour les plaques, systèmes de fixation invisibles selon matière."}, {"question": "Quel fichier fournir ?", "answer": "PDF à l''échelle 1 en 150 dpi minimum (300 dpi pour les plaques lues de près), CMJN, avec 3 mm de fond perdu et le tracé de découpe en ton direct si forme spéciale."}]'::jsonb, '{"formats": ["Standards de 20×30 à 80×120 cm", "Sur-mesure jusqu''à 150×200 cm selon matière"], "supports": ["Akylux polypropylène alvéolaire 3 à 5 mm", "Forex PVC expansé 3 à 5 mm", "Dibond composite aluminium 3 mm", "Plexiglass 4 mm", "Carton plume et carton recyclable"], "finitions": ["Découpe droite ou à la forme", "Perçage et œillets", "Pelliculage mat, brillant ou texturé", "Vernis sélectif", "Rainage"], "impression": "Quadri directe haute définition, recto ou recto-verso", "quantites": "1 à 100+ exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Usage intérieur et extérieur selon matière", "Systèmes de fixation", "Versions écologiques recyclables"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── panneau_akylux : Panneau Akylux ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'panneau_akylux', '{}'::jsonb, 'fr', 'Panneau Akylux (polypropylène alvéolaire)', array['panneau akilux','panneau akylux','polypropylène alvéolaire','panneau immobilier','panneau à vendre','panneau de chantier','panneau alvéolaire','panneau léger extérieur','panneau élection','panneau temporaire']::text[],
  'Panneau Akylux {{format}} {{finition}} — {{quantite}}', 'Le panneau Akylux en polypropylène alvéolaire : ultraléger, insensible à la pluie et économique — la référence de l''immobilier et du chantier.',
  '## Le champion du panneau temporaire extérieur

L''Akylux est un polypropylène à structure alvéolaire : une âme en cannelures qui lui donne de la rigidité pour un poids plume. Insensible à l''eau, il ne gondole pas sous la pluie comme le ferait un carton — c''est ce qui en a fait le standard absolu du panneau immobilier, du panneau de chantier et de la signalétique événementielle extérieure.

## Caractéristiques techniques

Épaisseurs de 3, 3,5 et 5 mm selon la durée d''exposition, plus une version 3 mm intégrant 50 % de matière recyclée, elle-même 100 % recyclable. Formats standard de 20×30 à 80×120 cm et sur-mesure jusqu''à 150×200 cm en une pièce. Impression quadri directe haute définition, recto ou recto-verso, avec œillets en option aux quatre coins ou en tête.

## Les avantages de l''Akylux

Son poids réduit simplifie la pose sur piquet, grille ou collier et divise les frais de transport en série. Sa tenue extérieure va de quelques mois à plus d''un an selon l''épaisseur — exactement la durée de vie d''une commercialisation ou d''un chantier.', 'Panneau Akylux {{format}} imprimé',
  'Panneau Akylux imprimé — immobilier, chantier', 'Panneau Akylux polypropylène alvéolaire 3 à 5 mm : ultraléger, résiste à la pluie, recto-verso, œillets. Le standard immobilier et chantier.', array['panneau akilux personnalisé','panneau immobilier akilux','panneau à vendre à louer','panneau de chantier léger','polypropylène alvéolaire imprimé','panneau akilux recto verso']::text[], 'Product',
  'Le panneau qui a fait ses preuves sur des millions de façades : léger à poser, insensible à la pluie, imbattable en prix dès la petite série. Vos « à vendre » et panneaux de chantier, prêts à visser.', '["Ultraléger : pose rapide sur piquet, grille ou collier", "Insensible à l''eau, ne gondole pas", "Recto-verso pour lecture des deux côtés", "Œillets en option, prêt à fixer", "Version 50 % recyclée, 100 % recyclable", "Le meilleur rapport visibilité/prix en extérieur temporaire"]'::jsonb, '["Panneau immobilier à vendre / à louer", "Signalétique de chantier", "Fléchage d''événement extérieur", "Panneau électoral ou associatif", "Promotion saisonnière en devanture"]'::jsonb,
  '[{"title": "Réseau d''agences immobilières", "description": "Une série de panneaux 60×80 recto-verso à la charte de l''enseigne, posés en quelques minutes sur les biens en mandat."}, {"title": "Entreprise du BTP", "description": "Les panneaux de chantier 80×120 affichent permis et coordonnées sur toute la durée des travaux, sans broncher sous la pluie."}, {"title": "Course nature", "description": "Le fléchage du parcours en panneaux 3 mm se fixe aux barrières le matin et se recycle après l''événement."}, {"title": "Promoteur", "description": "Le panneau 150×200 grand format annonce le programme neuf en bordure de terrain pendant toute la commercialisation."}]'::jsonb, '[{"question": "Quelle épaisseur choisir ?", "answer": "3 mm pour quelques semaines à quelques mois (fléchage, opérations courtes), 3,5 mm pour la saison immobilière classique, 5 mm pour une exposition prolongée au-delà d''un an ou les grands formats."}, {"question": "Combien de temps tient un Akylux dehors ?", "answer": "De plusieurs mois à plus d''un an selon l''épaisseur et l''exposition. Le matériau ne craint pas l''eau ; ce sont les UV et le vent qui fixent la limite."}, {"question": "Comment le fixer ?", "answer": "Vis ou clous sur piquet bois, colliers sur grille via les œillets, rilsans sur barrière. Sa légèreté autorise des fixations simples."}, {"question": "Recto-verso : dans quels cas ?", "answer": "Dès que le panneau est lu des deux côtés : perpendiculaire à une façade, sur piquet en bord de route, suspendu. Le surcoût est faible par rapport à deux panneaux."}, {"question": "Quel fichier fournir ?", "answer": "PDF échelle 1 en 150 dpi, CMJN, 3 mm de fond perdu. Sur les petites épaisseurs, orientez les textes dans le sens des cannelures pour une rigidité optimale à la pose."}]'::jsonb, '{"formats": ["Standards de 20×30 à 80×120 cm", "Sur-mesure jusqu''à 150×200 cm en une pièce"], "supports": ["Polypropylène alvéolaire 3, 3,5 et 5 mm", "Version 3 mm 50 % recyclée, 100 % recyclable", "Variante alvéolaire blanche fine ~3 mm"], "finitions": ["Découpe rectangulaire", "Œillets aux 4 coins ou en tête"], "impression": "Quadri directe haute définition, recto ou recto-verso", "quantites": "1 à 200+ exemplaires, tarif fortement dégressif en série", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Usage extérieur temporaire à moyenne durée", "Ultraléger pour pose et transport", "Recyclable"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── panneau_dibond : Panneau Dibond ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'panneau_dibond', '{}'::jsonb, 'fr', 'Panneau Dibond (aluminium composite)', array['panneau dibond','aluminium composite','panneau alu','enseigne dibond','plaque aluminium imprimée','panneau extérieur durable','signalétique alu','panneau premium','dibond imprimé']::text[],
  'Panneau Dibond {{format}} {{finition}} — {{quantite}}', 'Le Dibond associe deux faces aluminium à une âme polyéthylène : rigidité parfaite, planéité totale et tenue extérieure de longue durée.',
  '## Le panneau premium qui dure des années

Le Dibond est un sandwich composite : deux fines plaques d''aluminium laqué enserrant une âme en polyéthylène. Cette construction lui donne une planéité parfaite, une grande rigidité pour seulement 3 mm d''épaisseur et une résistance aux intempéries qui en fait le support de référence des enseignes, plaques et signalétiques permanentes.

## Caractéristiques techniques

Épaisseur 3 mm, formats standard de 20×30 à 80×120 cm et sur-mesure au-delà (jusqu''à environ 94×136 cm avec pelliculage). Trois faces au choix : blanc laqué, aluminium brossé ou effet miroir. Impression quadri directe sans reflet, avec protection UV. Finitions : découpe personnalisée, perçage, pelliculages mat, brillant, ultra-brillant ou texturés (bois, cuir), vernis sélectif pour les effets de relief.

## Les avantages du Dibond

Il ne rouille pas, ne gondole pas, ne se déforme ni au soleil ni au gel : posé une fois, il communique pendant des années. Sa surface rigide accepte les systèmes de fixation murale invisibles pour un rendu d''enseigne professionnel.', 'Panneau Dibond {{format}} aluminium',
  'Panneau Dibond imprimé — alu composite 3 mm', 'Panneau Dibond aluminium composite 3 mm : planéité parfaite, tenue extérieure longue durée, finitions blanc, brossé ou miroir. L''enseigne rigide premium.', array['panneau dibond personnalisé','impression dibond','panneau aluminium composite','enseigne dibond extérieur','plaque alu imprimée','signalétique durable']::text[], 'Product',
  'Posez-le et oubliez-le : le Dibond affiche votre marque pendant des années sans rouiller ni se déformer. La qualité d''enseigne professionnelle, accessible dès l''exemplaire unique.', '["Tenue extérieure de longue durée, insensible aux intempéries", "Planéité parfaite, rendu d''enseigne professionnel", "Rigide et pourtant léger : 3 mm suffisent", "Faces blanc laqué, alu brossé ou miroir", "Pelliculages et vernis sélectif pour finitions premium", "Compatible fixations murales invisibles"]'::jsonb, '["Enseigne de façade", "Plaque professionnelle extérieure", "Signalétique permanente de site", "Décoration murale premium", "Panneau directionnel durable"]'::jsonb,
  '[{"title": "Devanture de cabinet", "description": "L''enseigne Dibond blanc laqué remplace l''ancienne plaque défraîchie et reste impeccable saison après saison."}, {"title": "Parc d''activités", "description": "Le totem d''entrée liste les entreprises du site sur panneaux Dibond interchangeables, résistants au climat."}, {"title": "Hôtel", "description": "Des tirages photo sur alu brossé habillent le lobby avec un rendu galerie, fixés sur entretoises."}, {"title": "Réseau de franchise", "description": "La même enseigne Dibond est déployée sur trente points de vente : rendu identique, durabilité garantie partout."}]'::jsonb, '[{"question": "Dibond ou Forex pour l''extérieur ?", "answer": "Les deux tiennent dehors, mais le Dibond reste parfaitement plan et stable sur de longues années : pour une enseigne ou une plaque permanente, c''est lui. Le Forex est l''option polyvalente plus économique."}, {"question": "Combien de temps dure un panneau Dibond ?", "answer": "Plusieurs années en extérieur sans altération notable : l''aluminium ne rouille pas et l''impression bénéficie d''une protection UV."}, {"question": "Comment le fixer au mur ?", "answer": "Perçage et vis, entretoises décoratives, adhésif structural ou systèmes de fixation invisibles : la rigidité du composite autorise toutes les méthodes."}, {"question": "Peut-on le découper à une forme spéciale ?", "answer": "Oui, la découpe personnalisée est disponible : fournissez le tracé vectoriel. Logos, flèches, silhouettes — le composite se prête très bien aux formes."}, {"question": "Quel fichier fournir ?", "answer": "PDF échelle 1 en 150 dpi (300 dpi si lecture de près), CMJN, 3 mm de fond perdu. Pour l''effet brossé ou miroir, indiquez les zones sans blanc de soutien qui laisseront apparaître l''aluminium."}]'::jsonb, '{"formats": ["Standards de 20×30 à 80×120 cm", "Sur-mesure, jusqu''à ~94×136 cm avec pelliculage"], "supports": ["Composite aluminium/polyéthylène/aluminium 3 mm, faces blanc laqué, brossé ou miroir"], "finitions": ["Découpe personnalisée", "Perçage", "Pelliculage mat, brillant, ultra-brillant ou texturé", "Vernis sélectif"], "impression": "Quadri directe haute définition anti-UV, sans reflet", "quantites": "1 à 100 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Usage intérieur et extérieur longue durée", "Fixations murales invisibles compatibles", "Protection UV"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── panneau_forex : Panneau Forex ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'panneau_forex', '{}'::jsonb, 'fr', 'Panneau Forex (PVC expansé)', array['panneau forex','PVC expansé','panneau PVC','forex imprimé','panneau intérieur extérieur','PLV rigide','panneau découpe forme','support PVC léger','panneau forex 5mm']::text[],
  'Panneau Forex {{format}} {{finition}} — {{quantite}}', 'Le Forex en PVC expansé, léger et robuste : le panneau polyvalent par excellence, en 3 à 5 mm, avec découpe à la forme et pelliculages.',
  '## Le polyvalent de la signalétique rigide

Le Forex est un PVC expansé : une mousse rigide à surface parfaitement lisse qui offre un rendu d''impression haute définition remarquable. Léger, facile à découper et à fixer, résistant aux intempéries et aux UV, il couvre à lui seul la majorité des besoins en signalétique intérieure et extérieure de moyenne durée.

## Caractéristiques techniques

Trois épaisseurs : 3, 4 et 5 mm. Formats standard de 20×30 à 80×120 cm, sur-mesure dès 20×20 cm et jusqu''à 120×200 cm en une pièce (145×200 cm en 4 mm). Disponible en blanc ou teinté dans la masse (noir, bleu, gris, vert, rouge, jaune). Finitions : découpe droite ou de forme libre, perçage, œillets, pelliculages mat, brillant, ultra-brillant ou texturés.

## Les avantages du Forex

Sa surface lisse sublime photos et aplats de couleur ; sa légèreté simplifie l''accroche murale ; sa découpe à la forme ouvre le champ aux silhouettes, logos XXL et PLV créatives. Le compromis idéal entre coût, rendu et durabilité.', 'Panneau Forex {{format}} PVC expansé',
  'Panneau Forex imprimé — PVC expansé 3 à 5 mm', 'Panneau Forex PVC expansé 3/4/5 mm : surface lisse haute définition, découpe à la forme, intérieur et extérieur. Sur-mesure jusqu''à 145×200 cm.', array['panneau forex personnalisé','impression forex','PVC expansé imprimé','panneau PVC léger','découpe forex à la forme','signalétique PVC']::text[], 'Product',
  'Un rendu photo impeccable, une découpe à la forme de votre logo et une tenue en extérieur : le Forex fait tout, à un prix qui permet d''en mettre partout. Le couteau suisse de votre signalétique.', '["Surface lisse : rendu d''impression haute définition", "Léger et rigide, facile à poser", "Découpe de forme libre pour silhouettes et logos", "Intérieur et extérieur, bonne tenue UV", "Blanc ou teinté masse en 6 coloris", "Excellent rapport rendu/prix"]'::jsonb, '["PLV rigide en point de vente", "Signalétique intérieure d''entreprise", "Silhouette découpée pour vitrine", "Panneau publicitaire moyenne durée", "Décor événementiel réutilisable"]'::jsonb,
  '[{"title": "Vitrine de parfumerie", "description": "Le flacon vedette découpé à la forme en Forex 5 mm trône en vitrine pendant le lancement."}, {"title": "Signalétique de bureaux", "description": "Panneaux d''étage et plaques de porte en Forex 3 mm, homogènes sur tout le siège et remplaçables à moindre coût."}, {"title": "Franchise de restauration", "description": "Les visuels menus en Forex pelliculé mat s''accrochent au mur et se remplacent à chaque nouvelle carte."}, {"title": "Stand photo", "description": "Un décor découpé grandeur nature en Forex fait office de photobooth aux couleurs de la marque."}]'::jsonb, '[{"question": "Quelle épaisseur de Forex choisir ?", "answer": "3 mm pour l''affichage mural intérieur, 4-5 mm dès qu''il y a manipulation, grand format ou usage extérieur : la rigidité augmente sensiblement avec l''épaisseur."}, {"question": "Le Forex tient-il en extérieur ?", "answer": "Oui, il résiste aux intempéries et aux UV pour un usage de moyenne durée. Pour une enseigne permanente de plusieurs années, le Dibond reste préférable."}, {"question": "Comment préparer une découpe à la forme ?", "answer": "Ajoutez dans votre PDF un tracé vectoriel de découpe en ton direct, avec des courbes simples et sans angles trop fins qui fragiliseraient la pièce."}, {"question": "Comment le fixer ?", "answer": "Adhésif double face haute performance, vis avec perçage, œillets ou profilés : sa légèreté tolère les fixations simples, même sur cloison légère."}, {"question": "Quel fichier fournir ?", "answer": "PDF échelle 1 en 150 dpi (300 dpi pour une lecture rapprochée), CMJN, 3 mm de fond perdu, tracé de découpe séparé si forme spéciale."}]'::jsonb, '{"formats": ["Standards de 20×30 à 80×120 cm", "Sur-mesure dès 20×20 cm", "Maximum une pièce : 120×200 cm (3 et 5 mm), 145×200 cm (4 mm)"], "supports": ["PVC expansé 3, 4 et 5 mm, blanc ou teinté masse (noir, bleu, gris, vert, rouge, jaune)"], "finitions": ["Découpe droite ou de forme libre", "Perçage et œillets", "Pelliculage mat, brillant, ultra-brillant, texturé", "Vernis sélectif"], "impression": "Quadri directe haute définition", "quantites": "1 à 100 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Usage intérieur et extérieur moyenne durée", "Compatible systèmes de fixation murale", "Bonne tenue UV"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── panneau_plexi : Plaque plexiglass ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'panneau_plexi', '{}'::jsonb, 'fr', 'Plaque plexiglass imprimée', array['plaque plexiglass','plexi imprimé','plaque professionnelle plexiglas','plaque transparente','plexiglass personnalisé','plaque entretoises','signalétique plexi','plaque cabinet','méthacrylate imprimé']::text[],
  'Plaque plexiglass {{format}} {{finition}} — {{quantite}}', 'Plaque plexiglass 4 mm imprimée avec blanc de soutien : la transparence et l''élégance du verre, sans sa fragilité — montée sur entretoises.',
  '## L''élégance du verre, la sécurité en plus

La plaque plexiglass est le support signalétique haut de gamme par excellence : sa transparence et sa profondeur évoquent le verre, avec une résistance aux chocs incomparable et sans risque d''éclats. C''est le choix naturel des plaques professionnelles, des enseignes de standing et de la décoration murale premium.

## Caractéristiques techniques

Méthacrylate transparent extrudé de 4 mm, imprimé en quadri directe avec blanc de soutien intégral pour un contraste parfait des couleurs sur fond transparent. Formats de 20×30 à 100×140 cm et sur-mesure jusqu''à 115×200 cm en une pièce. Options de façonnage : découpe laser, perçage, coins arrondis et pose sur entretoises métalliques qui décollent la plaque du mur pour un effet de profondeur très valorisant.

## Les avantages du plexiglass

Résistant aux UV et aux chocs, il convient en intérieur comme en extérieur abrité. Disponible dès l''exemplaire unique, il permet à un cabinet, une étude ou un commerce de s''offrir une entrée à l''image de ses prestations.', 'Plaque plexiglass {{format}} imprimée',
  'Plaque plexiglass imprimée 4 mm — sur mesure', 'Plaque plexiglass 4 mm avec blanc de soutien : rendu verre premium, découpe laser, coins arrondis, entretoises. Dès 1 exemplaire, jusqu''à 115×200 cm.', array['plaque plexiglass personnalisée','plaque professionnelle plexi','impression sur plexiglas','plaque transparente imprimée','plaque entretoises','enseigne plexiglass']::text[], 'Product',
  'Votre plaque professionnelle mérite mieux qu''un rectangle de PVC : le plexiglass sur entretoises donne à votre entrée l''allure d''une maison établie. Dès un exemplaire, façonné à vos dimensions.', '["Rendu verre premium avec effet de profondeur", "Blanc de soutien : couleurs éclatantes sur fond transparent", "Résistant aux chocs, sans risque d''éclats coupants", "Tenue UV pour l''extérieur abrité", "Découpe laser, coins arrondis, perçage de précision", "Disponible dès 1 exemplaire"]'::jsonb, '["Plaque professionnelle de cabinet", "Enseigne intérieure de standing", "Signalétique d''accueil d''entreprise", "Décoration murale photo premium", "Plaque commémorative ou de mécénat"]'::jsonb,
  '[{"title": "Étude notariale", "description": "La plaque plexiglass sur entretoises laiton affiche l''étude à l''entrée de l''immeuble avec la sobriété attendue de la profession."}, {"title": "Cabinet paramédical", "description": "Chaque praticien dispose de sa plaque normalisée ; l''ensemble reste homogène et se complète à chaque arrivée."}, {"title": "Agence de communication", "description": "Le logo imprimé en réserve, sans blanc de soutien par endroits, joue avec la transparence sur le mur de brique de l''accueil."}, {"title": "Hall d''hôtel", "description": "Des tirages photo grand format sous plexi habillent le lobby avec un rendu galerie d''art."}]'::jsonb, '[{"question": "Le plexiglass jaunit-il avec le temps ?", "answer": "Le méthacrylate que nous utilisons offre une bonne tenue aux UV et conserve sa transparence durablement, y compris en extérieur abrité."}, {"question": "Comment fixer la plaque au mur ?", "answer": "La pose sur entretoises métalliques est la plus valorisante : quatre perçages en angles, la plaque flotte à quelques centimètres du mur. Fixation adhésive possible sur petites dimensions."}, {"question": "Peut-on jouer avec la transparence ?", "answer": "Oui : les zones imprimées sans blanc de soutien restent translucides. Précisez dans votre fichier les zones en réserve pour cet effet vitrail très élégant."}, {"question": "Quelle taille maximum en une pièce ?", "answer": "Jusqu''à 115×200 cm en une seule plaque de 4 mm. Au-delà, on compose un ensemble de plusieurs plaques alignées."}, {"question": "Quel fichier fournir ?", "answer": "PDF échelle 1 en 300 dpi (lecture de près), CMJN, avec un calque dédié aux zones de blanc de soutien et l''emplacement des perçages si pose sur entretoises."}]'::jsonb, '{"formats": ["Standards de 20×30 à 100×140 cm", "Sur-mesure jusqu''à 115×200 cm en une pièce"], "supports": ["Méthacrylate transparent extrudé 4 mm"], "finitions": ["Découpe laser", "Perçage", "Coins arrondis", "Pose sur entretoises"], "impression": "Quadri directe avec blanc de soutien intégral ou en réserve", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Entretoises métalliques", "Usage intérieur et extérieur abrité", "Tenue UV", "Zones transparentes en réserve"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── adhesif : Adhésifs / Vitrophanie ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'adhesif', '{}'::jsonb, 'fr', 'Adhésifs et vinyles imprimés', array['vinyle adhésif','adhésif personnalisé','sticker grand format','vitrophanie','adhésif vitrine','vinyle découpé','covering','adhésif mural','film adhésif imprimé','lettrage adhésif']::text[],
  'Adhésif {{format}} {{finition}} — {{quantite}}', 'Vitrines, murs, sols, véhicules : le vinyle adhésif imprimé transforme chaque surface en support de communication, en découpe droite ou à la forme.',
  '## Chaque surface devient un média

Le vinyle adhésif est l''outil le plus souple de la signalétique : il épouse une vitrine, un mur, un sol, une carrosserie ou un mobilier et y installe votre message sans travaux. Pose rapide, dépose propre avec les colles adaptées : c''est la communication qui s''adapte à vos murs, pas l''inverse.

## Caractéristiques techniques

La gamme couvre tous les usages : vinyle monomère pour les surfaces planes et les campagnes courtes, polymère pour l''extérieur durable, coulé pour les surfaces courbes et les véhicules. S''y ajoutent les spécialités : transparent, dépoli, micro-perforé pour vitrines, repositionnable sans colle, magnétique, antidérapant pour le sol et versions sans PVC. Impression quadri haute définition, découpe droite ou au contour du visuel, laminations mate, brillante ou texturée.

## Les avantages de la gamme

Colles au choix — renforcée, pose facile, enlevable sans résidu — pour maîtriser la dépose autant que la pose. Du sticker de 4 cm au covering de vitrine complet, chaque projet trouve son film.', 'Adhésifs et vinyles imprimés sur mesure',
  'Vinyle adhésif imprimé — vitrine, mur, sol', 'Impression de vinyles adhésifs : monomère, polymère, coulé, dépoli, micro-perforé, sol antidérapant. Découpe à la forme, colles adaptées à chaque surface.', array['vinyle adhésif personnalisé','impression adhésif grand format','sticker vitrine','adhésif mural imprimé','vinyle découpé à la forme','film adhésif publicitaire']::text[], 'Product',
  'Vitrine, mur, sol ou véhicule : collez votre message là où passent vos clients, sans travaux ni perceuse. Et quand la campagne change, l''adhésif s''enlève proprement — la surface, elle, reste intacte.', '["S''applique sur vitrine, mur, sol, véhicule, mobilier", "Trois familles de films selon durée et surface", "Découpe droite ou au contour exact du visuel", "Colles au choix : renforcée, pose facile, enlevable", "Laminations de protection mate, brillante ou texturée", "Du sticker unitaire au covering complet"]'::jsonb, '["Habillage de vitrine commerciale", "Décor mural de bureaux", "Marquage promotionnel au sol", "Signalétique de véhicule utilitaire", "Personnalisation de mobilier et PLV"]'::jsonb,
  '[{"title": "Réseau de boutiques", "description": "La campagne saisonnière est déclinée en kits adhésifs identiques posés en vitrine dans tout le réseau, puis déposés sans trace."}, {"title": "Open space", "description": "Un décor mural adhésif installe l''univers de la marque dans les bureaux sans peinture ni chantier."}, {"title": "Flotte d''utilitaires", "description": "Logos et coordonnées en vinyle coulé habillent les véhicules : chaque trajet devient de la publicité."}, {"title": "Supermarché", "description": "Des stickers de sol antidérapants guident les clients vers l''opération promotionnelle du mois."}]'::jsonb, '[{"question": "Monomère, polymère ou coulé : comment choisir ?", "answer": "Monomère pour les surfaces planes et les durées courtes à moyennes, polymère pour l''extérieur de plusieurs années, coulé pour les surfaces courbes et le covering véhicule."}, {"question": "L''adhésif s''enlève-t-il proprement ?", "answer": "Avec une colle enlevable, oui : la dépose ne laisse pas de résidu sur la période prévue. Sur les colles standard, un décollage à chaud reste possible mais plus long."}, {"question": "Puis-je poser moi-même ?", "answer": "Sur surface plane et propre, oui : films à pose facile, raclette et patience suffisent. Pour les grandes vitrines, les surfaces courbes et les véhicules, un poseur professionnel est recommandé."}, {"question": "Quelle durée de vie en extérieur ?", "answer": "De un à deux ans pour un monomère à plusieurs années pour un polymère ou un coulé laminé, selon exposition. La lamination prolonge nettement la tenue."}, {"question": "Quel fichier pour une découpe à la forme ?", "answer": "PDF vectoriel avec un tracé de découpe en ton direct, à l''échelle 1. Évitez les détails inférieurs à quelques millimètres, fragiles à l''écheniillage et à la pose."}]'::jsonb, '{"formats": ["Sur mesure, du sticker 4×4 cm aux lés grand format pour vitrines et murs"], "supports": ["Vinyle monomère", "Vinyle polymère", "Vinyle coulé", "Transparent, dépoli, micro-perforé", "Repositionnable sans colle", "Magnétique", "Textile antidérapant sol", "Option sans PVC"], "finitions": ["Découpe droite ou au contour (mi-chair)", "Lamination mate, brillante, texturée", "Effets spéciaux (effaçable à sec, textures)"], "impression": "Quadri haute définition, encres extérieures", "quantites": "1 à 500+ exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Colle renforcée, pose facile ou enlevable", "Usage intérieur et extérieur selon film", "Pose par professionnel possible"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── vitrophanie : Vitrophanie ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'vitrophanie', '{}'::jsonb, 'fr', 'Vitrophanie (adhésif vitrine)', array['vitrophanie','adhésif vitrine','sticker vitrine','film dépoli','micro-perforé vitrine','one way vision','habillage vitrine','vitrine magasin personnalisée','film vitrage','lettrage vitrine']::text[],
  'Vitrophanie {{format}} {{finition}} — {{quantite}}', 'Transformez votre vitrine en affiche : vitrophanie transparente, dépolie ou micro-perforée one-way, posée côté intérieur et protégée des intempéries.',
  '## Votre vitrine travaille pour vous

La vitrophanie transforme la plus belle surface de votre commerce — sa vitrine — en support de communication permanent ou saisonnier. Posée côté intérieur du vitrage, elle reste lisible depuis la rue tout en étant protégée de la pluie, des UV directs et des dégradations.

## Caractéristiques techniques

Plusieurs films selon l''effet recherché : vinyle transparent pour un visuel flottant sur le verre (y compris en version ultra-transparente sans voile laiteux), dépoli effet sablé pour l''intimité des bureaux et cabinets, micro-perforé « one-way » qui affiche un visuel plein côté rue tout en préservant la vue et la lumière depuis l''intérieur. Fabrication sur mesure dès 4×4 cm, découpe droite ou au contour exact du visuel, colles repositionnables ou enlevables.

## Les avantages de la vitrophanie

Pas de travaux, pas de store ni de panneau : le message est dans le verre. La dépose se fait proprement en fin de campagne, et le vitrage retrouve son état d''origine.', 'Vitrophanie {{format}} pour vitrine',
  'Vitrophanie sur mesure — adhésif vitrine', 'Vitrophanie personnalisée : transparent, dépoli sablé ou micro-perforé one-way. Pose intérieure protégée, découpe au contour, dépose propre. Dès 4×4 cm.', array['vitrophanie personnalisée','adhésif vitrine magasin','film dépoli sur mesure','micro-perforé one way','habillage vitrine commerce','sticker vitrine sur mesure']::text[], 'Product',
  'Votre vitrine est votre meilleur emplacement publicitaire — et vous l''avez déjà. La vitrophanie y installe horaires, offres ou décor complet, posée de l''intérieur, à l''abri des intempéries et des rayures.', '["Pose côté intérieur : visuel protégé des intempéries et du vandalisme", "Trois effets : transparent, dépoli intimité, micro-perforé one-way", "Le one-way préserve lumière et vue depuis l''intérieur", "Découpe au contour pour lettrages et logos", "Dépose propre en fin de campagne", "Sur mesure dès 4×4 cm jusqu''à la vitrine complète"]'::jsonb, '["Habillage de vitrine commerciale", "Horaires et informations en porte", "Confidentialité de bureaux vitrés", "Campagne saisonnière en réseau", "Vitrine de local en travaux"]'::jsonb,
  '[{"title": "Opticien", "description": "Le visuel de la collection couvre la vitrine en micro-perforé : plein écran côté rue, luminosité intacte côté boutique."}, {"title": "Cabinet comptable", "description": "Des bandes dépolies à hauteur de regard préservent la confidentialité des bureaux tout en habillant la façade vitrée."}, {"title": "Agence bancaire", "description": "Horaires, services et logo en lettrage découpé, posés côté intérieur et donc impossibles à arracher."}, {"title": "Local en cours d''aménagement", "description": "Une vitrophanie pleine annonce l''ouverture prochaine et masque le chantier pendant les travaux."}]'::jsonb, '[{"question": "Comment le visuel reste-t-il lisible s''il est posé à l''intérieur ?", "answer": "L''impression est réalisée en miroir sur la face adhésive : collé côté intérieur du vitrage, le visuel se lit à l''endroit depuis la rue, protégé par le verre."}, {"question": "Le micro-perforé bloque-t-il la lumière ?", "answer": "Non : ses perforations laissent passer une bonne part de la lumière et préservent la vue de l''intérieur vers l''extérieur, tout en affichant un visuel plein côté rue."}, {"question": "La dépose abîme-t-elle le vitrage ?", "answer": "Avec les colles enlevables, l''adhésif se retire sans résidu sur la durée prévue. Le verre retrouve son état d''origine, prêt pour la campagne suivante."}, {"question": "Puis-je poser la vitrophanie moi-même ?", "answer": "Sur des surfaces modestes, oui, avec un vitrage propre, de l''eau savonneuse et une raclette. Pour une vitrine complète, un poseur garantit un résultat sans bulles."}, {"question": "Quel fichier fournir ?", "answer": "PDF échelle 1 en 150 dpi, CMJN, tracé de découpe vectoriel si contour spécial. Indiquez le sens de pose (intérieur ou extérieur) : nous adaptons le miroir d''impression."}]'::jsonb, '{"formats": ["Sur mesure de 4×4 cm à la vitrine complète en plusieurs lés"], "supports": ["Vinyle transparent (option ultra-transparent)", "Vinyle dépoli effet sablé", "Micro-perforé one-way vision"], "finitions": ["Découpe droite ou au contour du visuel", "Pose intérieure ou extérieure", "Colles repositionnables ou enlevables"], "impression": "Quadri haute définition, impression miroir pour pose intérieure", "quantites": "1 à 100 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Protection intempéries par pose intérieure", "Dépose sans résidu", "Kits multi-vitrines pour réseaux"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── adhesif_sol : Adhésif de sol ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'adhesif_sol', '{}'::jsonb, 'fr', 'Adhésif de sol antidérapant', array['adhésif sol','sticker sol','marquage au sol','vinyle sol antidérapant','signalétique sol','adhésif sol magasin','stickers directionnels','marquage sol événement','adhésif sol normé']::text[],
  'Adhésif de sol {{format}} — {{quantite}}', 'Le sol est le seul média que 100 % de vos clients regardent : nos adhésifs antidérapants normés y installent guidage, promotions et sécurité.',
  '## Le média que tout le monde regarde

En marchant, chacun regarde où il met les pieds : le marquage au sol bénéficie d''un taux d''exposition unique. Guidage vers un rayon, promotion devant un linéaire, distanciation, sécurité ou simple créativité : l''adhésif de sol installe votre message exactement sur le parcours client.

## Caractéristiques techniques

Deux constructions au choix : vinyle imprimé protégé par une lamination antidérapante spéciale sol, résistante à l''abrasion et aux rayures, ou support textile antidérapant intrinsèque conforme aux normes françaises, y compris au feu. Les deux répondent aux exigences de glissance applicables aux établissements recevant du public. Découpe droite ou à la forme (flèches, pas, ronds, logos), sur mesure au centimètre.

## Les avantages de l''adhésif de sol

Pose en quelques minutes sur sol lisse, propre et sec ; dépose sans résidu en fin d''opération. Une solution éphémère ou semi-permanente qui ne nécessite ni peinture ni traçage, et se renouvelle au rythme de vos campagnes.', 'Adhésif de sol {{format}} antidérapant',
  'Adhésif de sol antidérapant — marquage normé', 'Stickers de sol antidérapants conformes aux normes : guidage, promotion, sécurité. Lamination anti-abrasion, découpe à la forme, dépose propre.', array['adhésif de sol personnalisé','sticker sol antidérapant','marquage au sol magasin','signalétique sol normée','vinyle sol imprimé','flèches adhésives sol']::text[], 'Product',
  'Chaque client regarde le sol plusieurs fois par visite : mettez-y votre message. Antidérapant certifié, posé en cinq minutes, retiré sans trace — le média le plus direct du point de vente.', '["Exposition maximale : sur le parcours exact du client", "Antidérapant conforme aux normes de glissance ERP", "Lamination anti-abrasion : résiste au passage intensif", "Découpe à la forme : flèches, pas, ronds, logos", "Pose rapide, dépose sans résidu", "Version textile classée feu disponible"]'::jsonb, '["Guidage vers un rayon ou une caisse", "Promotion devant un linéaire", "Parcours événementiel ou salon", "Consignes de sécurité en entrepôt", "Animation de galerie commerciale"]'::jsonb,
  '[{"title": "Grande surface", "description": "Des pas adhésifs mènent de l''entrée au corner promotionnel : le trafic sur l''opération augmente sensiblement."}, {"title": "Salon professionnel", "description": "La signalétique au sol guide les visiteurs vers les halls et sponsors, sans encombrer les allées."}, {"title": "Entrepôt logistique", "description": "Zones de circulation piétonne et consignes matérialisées par adhésifs normés, renouvelés lors des audits sécurité."}, {"title": "Boutique de centre-ville", "description": "Un sticker de sol en terrasse de la boutique attire les passants vers l''entrée avec une accroche décalée."}]'::jsonb, '[{"question": "L''adhésif de sol est-il vraiment antidérapant ?", "answer": "Oui : la lamination spéciale sol ou le support textile répondent aux normes de glissance en vigueur pour les ERP. C''est indispensable — n''utilisez jamais un adhésif standard au sol."}, {"question": "Sur quels sols peut-on le poser ?", "answer": "Sols lisses, propres et secs : carrelage, béton lissé, résine, parquet vitrifié. Les moquettes et sols poreux relèvent du support textile spécifique."}, {"question": "Combien de temps tient-il ?", "answer": "Plusieurs semaines à plusieurs mois selon l''intensité du passage. La lamination anti-abrasion encaisse le trafic piéton intensif d''un point de vente."}, {"question": "La dépose laisse-t-elle des traces ?", "answer": "Non sur la durée d''usage prévue : l''adhésif se retire d''un tenant. Au-delà, un décollage à chaud et un nettoyant doux suffisent."}, {"question": "Quel fichier fournir ?", "answer": "PDF échelle 1 en 150 dpi, CMJN, tracé de découpe vectoriel pour les formes. Prévoyez des visuels contrastés : au sol, la lisibilité prime sur la finesse."}]'::jsonb, '{"formats": ["Sur mesure au centimètre, formes libres (flèches, pas, ronds, logos)"], "supports": ["Vinyle imprimé + lamination antidérapante spéciale sol", "Textile adhésif antidérapant classé feu"], "finitions": ["Lamination anti-abrasion et anti-rayures", "Découpe droite ou à la forme"], "impression": "Quadri haute définition", "quantites": "1 à 500 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Conformité normes de glissance ERP", "Dépose sans résidu", "Kits multi-magasins"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── plv : PLV / Displays ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'plv', '{}'::jsonb, 'fr', 'PLV et displays publicitaires', array['PLV','display publicitaire','présentoir','PLV carton','PLV comptoir','PLV de sol','totem publicitaire','stop-rayon','display point de vente','présentoir personnalisé']::text[],
  'PLV {{format}} {{finition}} — {{quantite}}', 'Présentoirs comptoir, totems, PLV de sol, chevalets : toute la publicité sur le lieu de vente, en carton recyclable ou supports rigides, montée sans outil.',
  '## Vendre plus, là où tout se décide

La majorité des décisions d''achat se prennent en magasin : la PLV — publicité sur le lieu de vente — est l''outil qui transforme cette réalité en chiffre d''affaires. Présentoirs de comptoir, totems, displays de sol, chevalets et cubes : chaque implantation trouve son support.

## Caractéristiques techniques

Le cœur de gamme est le carton — compact, micro-cannelure ou alvéolaire — imprimé en quadri directe ou contrecollé offset pour un rendu premium. Léger, recyclable, il se livre à plat et se monte sans outil en quelques gestes. Pour les usages durables ou humides, les mêmes formes existent en PVC, Forex ou bois. Du chevalet de table de 20 cm au totem de 180 cm, la gamme couvre le comptoir, le linéaire et le sol.

## Les avantages de la gamme

Des petites séries accessibles pour tester un concept, des séries plus larges à tarif dégressif pour équiper un réseau, et des délais courts qui collent au rythme des opérations commerciales. La PLV carton se recycle après l''opération : le message change, pas les déchets.', 'PLV et displays personnalisés',
  'PLV personnalisée — présentoirs, totems, displays', 'PLV sur mesure : présentoirs comptoir, totems carton 180 cm, displays de sol, chevalets. Livrés à plat, montés sans outil, recyclables. Petites séries OK.', array['PLV personnalisée','présentoir carton','display publicitaire','PLV comptoir','totem carton','PLV point de vente','présentoir sur mesure']::text[], 'Product',
  'L''achat se décide en rayon : soyez-y. Nos PLV carton se livrent à plat, se montent sans outil et mettent votre produit sous les yeux du client au moment exact où il choisit.', '["Couvre comptoir, linéaire et sol", "Carton léger, livré à plat, monté sans outil", "Impression directe ou contrecollé offset premium", "Recyclable après l''opération", "Petites séries possibles pour tester", "Variantes durables en PVC, Forex ou bois"]'::jsonb, '["Lancement produit en pharmacie", "Mise en avant promotionnelle en GMS", "Présentoir de caisse en boutique", "Théâtralisation saisonnière de vitrine", "Animation de salon ou showroom"]'::jsonb,
  '[{"title": "Laboratoire pharmaceutique", "description": "Un présentoir de comptoir garni de leaflets équipe 200 pharmacies pour le lancement de la gamme hiver."}, {"title": "Marque de cosmétiques", "description": "Le display de sol théâtralise la nouveauté en tête de gondole pendant le temps fort promotionnel."}, {"title": "Cave à vins", "description": "Un totem carton présente la sélection du mois à l''entrée, remplacé à chaque nouvel arrivage."}, {"title": "Éditeur", "description": "Les présentoirs à étagères mettent la nouveauté en avant chez les libraires partenaires."}]'::jsonb, '[{"question": "Le carton est-il assez solide pour le point de vente ?", "answer": "Oui : les cannelures et structures alvéolaires sont dimensionnées pour supporter produits et manipulations pendant toute une opération commerciale. Les charges lourdes relèvent des versions renforcées ou rigides."}, {"question": "Le montage nécessite-t-il des outils ?", "answer": "Non : les PLV se livrent à plat, prédécoupées et rainées, et se montent par pliage et emboîtage en quelques minutes, notice fournie."}, {"question": "Quelle quantité minimum ?", "answer": "Les petites séries sont possibles dès quelques exemplaires — idéal pour tester un concept avant un déploiement réseau à tarif dégressif."}, {"question": "Impression directe ou contrecollage : quelle différence ?", "answer": "L''impression directe sur carton est économique et rapide ; le contrecollage d''une feuille offset apporte un rendu premium (couleurs denses, pelliculage) pour les marques exigeantes."}, {"question": "Quel fichier fournir ?", "answer": "Nous fournissons le gabarit à plat de chaque modèle : placez-y votre création en CMJN, 300 dpi, en respectant zones de pli et fonds perdus."}]'::jsonb, '{"formats": ["Du chevalet de table (~20 cm) au totem de sol (~180 cm)"], "supports": ["Carton compact", "Carton micro-cannelure", "Carton alvéolaire kraft", "Contrecollé offset", "Variantes PVC, Forex, bois"], "finitions": ["Prédécoupe et rainage", "Pliage et emboîtage sans outil", "Pelliculage sur contrecollé", "Découpe à la forme"], "impression": "Quadri directe ou offset contrecollé", "quantites": "1 à 500 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Livraison à plat", "Recyclable", "Gabarits fournis", "Usage intérieur"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── presentoir_comptoir : Présentoir comptoir ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'presentoir_comptoir', '{}'::jsonb, 'fr', 'Présentoir de comptoir porte-flyers', array['présentoir comptoir','porte-flyers','présentoir carton','porte-brochures','présentoir cartes de visite','PLV comptoir','présentoir dépliants','chevalet de comptoir','display comptoir']::text[],
  'Présentoir comptoir {{format}} — {{quantite}}', 'Le présentoir de comptoir en carton contrecollé met vos flyers et cartes à portée de main de chaque client encaissé : le rebond commercial le plus simple.',
  '## Le dernier mot avant la sortie

Le comptoir est le point de passage obligé de tous vos clients : un présentoir bien conçu y distribue vos flyers, cartes et dépliants au moment où l''attention est acquise. C''est l''outil de rebond commercial le plus économique qui soit — chaque document emporté prolonge la visite.

## Caractéristiques techniques

Structure en carton rigide, imprimée en direct ou contrecollée d''une feuille offset pour un rendu premium, avec fronton personnalisable pour porter votre message au-dessus des documents. Cases dimensionnées pour les formats courants de dépliants et cartes commerciales ; versions à grand fronton pour maximiser la visibilité, et déclinaisons transparentes ou en Forex pour les usages durables. Livré à plat, monté par pliage en quelques secondes.

## Les avantages du présentoir comptoir

Un coût unitaire minime, une personnalisation totale à vos couleurs, et un déploiement facile en réseau : chaque point de vente, salon ou partenaire reçoit son présentoir plié dans une enveloppe. Recyclable en fin de campagne.', 'Présentoir de comptoir {{format}} personnalisé',
  'Présentoir comptoir personnalisé — porte-flyers', 'Présentoir de comptoir carton avec fronton personnalisé : flyers, dépliants et cartes au point d''encaissement. Livré à plat, monté en 10 s.', array['présentoir comptoir carton','porte-flyers personnalisé','présentoir dépliants','porte-brochures comptoir','PLV comptoir personnalisée','présentoir cartes commerciales']::text[], 'Product',
  'Chaque client qui paie passe devant votre comptoir : posez-y un présentoir qui prolonge la conversation. Pour le prix de quelques cafés, vos flyers trouvent preneur toute l''année.', '["Positionné au point de contact universel : l''encaissement", "Fronton personnalisé pour porter votre accroche", "Cases adaptées aux formats dépliants et cartes", "Livré à plat, monté par pliage en secondes", "Coût unitaire minime, idéal en déploiement réseau", "Carton recyclable, versions durables disponibles"]'::jsonb, '["Comptoir de commerce de proximité", "Accueil d''hôtel ou d''office de tourisme", "Caisse de pharmacie ou parapharmacie", "Stand de salon professionnel", "Banque d''accueil d''entreprise"]'::jsonb,
  '[{"title": "Office de tourisme", "description": "Les présentoirs répartis chez les commerçants partenaires diffusent le programme des animations estivales."}, {"title": "Garage automobile", "description": "Au comptoir, le présentoir propose la carte fidélité entretien à chaque restitution de véhicule."}, {"title": "Institut de beauté", "description": "Le porte-cartes contrecollé pelliculé assorti à la charte diffuse les cartes de rendez-vous et les offres parrainage."}, {"title": "Salon B2B", "description": "Chaque hôtesse dispose d''un présentoir plié dans sa valise, monté en dix secondes à l''ouverture du stand."}]'::jsonb, '[{"question": "Quels formats de documents peut-il recevoir ?", "answer": "Les cases standard accueillent les formats courants de dépliants (tiers de page, A5) et de cartes commerciales. Indiquez votre format : nous orientons vers le bon modèle."}, {"question": "Le carton tient-il dans la durée ?", "answer": "Plusieurs mois d''usage en comptoir sans problème. Pour un usage permanent ou en environnement humide, les versions Forex ou transparentes prennent le relais."}, {"question": "Comment se monte-t-il ?", "answer": "Livré à plat, prédécoupé et rainé : quelques plis et emboîtages suffisent, sans colle ni outil. Une notice illustrée accompagne chaque modèle."}, {"question": "Quelle quantité commander pour un réseau ?", "answer": "Dès quelques exemplaires pour un test, avec un tarif dégressif rapide dès quelques dizaines : équiper 50 ou 100 points de vente reste très accessible."}, {"question": "Quel fichier fournir ?", "answer": "Votre création aux couleurs de la marque sur le gabarit à plat fourni, en CMJN 300 dpi, avec fonds perdus. Le fronton est la zone la plus visible : soignez l''accroche."}]'::jsonb, '{"formats": ["Modèles comptoir pour dépliants tiers de page, A5 et cartes commerciales", "Versions à grand fronton"], "supports": ["Carton rigide impression directe", "Carton contrecollé offset", "Variantes Forex et transparentes"], "finitions": ["Prédécoupe et rainage", "Montage par pliage sans colle", "Pelliculage sur contrecollé", "Fronton personnalisé"], "impression": "Quadri directe ou offset contrecollé", "quantites": "1 à 500 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Livraison à plat", "Recyclable", "Usage intérieur comptoir"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── totem_carton : Totem carton ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'totem_carton', '{}'::jsonb, 'fr', 'Totem publicitaire en carton', array['totem carton','totem publicitaire','totem PLV','colonne publicitaire carton','totem 180 cm','totem alvéolaire','totem 3 faces','display vertical carton','totem événementiel']::text[],
  'Totem carton {{format}} — {{quantite}}', 'Un totem carton de 1,60 à 1,80 m qui se monte sans outil : la présence verticale d''une colonne publicitaire, le poids et le prix du carton en moins.',
  '## La stature d''une colonne, la légèreté du carton

À hauteur d''homme, le totem carton impose votre message dans un hall, une allée de magasin ou un salon. C''est l''alternative maligne aux totems rigides : quelques kilos, un montage par pliage sans le moindre outil, et un coût qui autorise le déploiement en réseau ou le renouvellement à chaque campagne.

## Caractéristiques techniques

Trois architectures au choix : le totem compact (environ 50×180 cm) pour une silhouette fine, le totem alvéolaire (environ 60×176 cm avec base de 26 cm) dont l''âme kraft en nid d''abeille apporte rigidité et stabilité — découpe à la forme possible —, et le totem 3 faces (environ 36×158 cm) lisible sous tous les angles. Impression quadri sur carton blanc ou contrecollage offset brillant pour un rendu premium.

## Les avantages du totem carton

Livré à plat, il voyage dans un colis standard et se stocke sans encombre entre deux événements. En fin d''opération, il se recycle intégralement : votre communication verticale sans bilan matière.', 'Totem carton {{format}} personnalisé',
  'Totem carton personnalisé 180 cm — PLV verticale', 'Totem publicitaire carton : compact, alvéolaire ou 3 faces, ~160-180 cm de haut. Monté sans outil, livré à plat, 100 % recyclable. Impact vertical maxi.', array['totem carton personnalisé','totem publicitaire 180 cm','totem alvéolaire','totem 3 faces carton','colonne publicitaire carton','PLV verticale salon']::text[], 'Product',
  'Un totem à hauteur d''homme qui arrive à plat dans un colis et se dresse en deux minutes : l''impact d''une colonne publicitaire sans la logistique. Et après l''opération, direction le bac de tri.', '["Hauteur d''homme : visible par-dessus les rayonnages", "Montage par pliage, sans outil ni notice complexe", "Livré à plat : transport et stockage minimaux", "Version 3 faces lisible sous tous les angles", "Alvéolaire rigide avec découpe à la forme possible", "100 % recyclable après l''opération"]'::jsonb, '["Entrée de magasin ou de galerie", "Allée de salon professionnel", "Lancement produit en réseau", "Signalétique de hall d''accueil", "Animation de cinéma ou de spectacle"]'::jsonb,
  '[{"title": "Réseau bancaire", "description": "Un totem 3 faces dans chaque agence annonce la nouvelle offre, expédié à plat par simple colis."}, {"title": "Sortie cinéma", "description": "Le totem alvéolaire découpé à la silhouette du héros anime le hall pendant l''exploitation du film."}, {"title": "Salon RH", "description": "Deux totems compacts encadrent l''entrée du stand et guident les candidats vers l''espace entretien."}, {"title": "Galerie commerciale", "description": "Les totems du programme d''animations jalonnent le mail et se remplacent à chaque saison."}]'::jsonb, '[{"question": "Un totem carton est-il stable ?", "answer": "Oui, en intérieur : la base large et, sur la version alvéolaire, l''âme en nid d''abeille assurent l''aplomb. Évitez simplement les courants d''air et l''extérieur."}, {"question": "Combien de temps dure-t-il ?", "answer": "Toute la durée d''une opération commerciale, soit plusieurs semaines à plusieurs mois en intérieur. Manipulé avec soin et stocké à plat au sec, il ressert."}, {"question": "Quelle version choisir ?", "answer": "Compact pour le budget et la finesse, alvéolaire pour la rigidité et la découpe à la forme, 3 faces pour les emplacements traversants vus sous plusieurs angles."}, {"question": "Comment se passe le montage ?", "answer": "Le totem arrive à plat, prédécoupé et rainé : dépliage, emboîtage de la base, et il tient debout en une à deux minutes, sans outil."}, {"question": "Quel fichier fournir ?", "answer": "Votre création sur le gabarit à plat du modèle choisi, CMJN 300 dpi, fonds perdus inclus. Sur le 3 faces, pensez chaque face comme un message autonome."}]'::jsonb, '{"formats": ["Totem compact ~50×180 cm", "Totem alvéolaire ~60×176 cm (base ~26 cm)", "Totem 3 faces ~36×158 cm (base ~32 cm)"], "supports": ["Carton compact", "Carton alvéolaire à âme kraft nid d''abeille", "Carton blanc contrecollé sur cannelure kraft", "Contrecollage offset brillant"], "finitions": ["Prédécoupe et rainage", "Montage par pliage sans outil", "Découpe à la forme (version alvéolaire)"], "impression": "Quadri directe ou offset contrecollé", "quantites": "1 à 200 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Livraison à plat", "100 % recyclable", "Usage intérieur"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── stop_trottoir : Stop-trottoir / Chevalet ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'stop_trottoir', '{}'::jsonb, 'fr', 'Stop-trottoir et chevalet publicitaire', array['stop-trottoir','chevalet publicitaire','chevalet de trottoir','porte-affiche A1','cadre clic-clac','panneau trottoir','chevalet extérieur','stop trottoir lesté','chevalet double face']::text[],
  'Stop-trottoir {{format}} — {{quantite}}', 'Le stop-trottoir à cadre clic-clac arrête les passants devant votre porte : affiche A1 changée en 30 secondes, double face, stable dehors.',
  '## Arrêtez les passants devant votre porte

Posé sur le trottoir, le chevalet publicitaire intercepte le flux piéton au moment décisif : à deux mètres de votre entrée. Menu du jour, promotion, nouvelle collection — son double affichage travaille dans les deux sens de circulation, toute la journée.

## Caractéristiques techniques

Le modèle à cadres clic-clac reçoit une affiche standard (format A1 courant) sous film de protection : on relève les quatre profils du cadre, on positionne l''affiche, on referme — trente secondes sans outil, des deux côtés. Le chevalet pliant classique (environ 65×117 cm) se range à plat chaque soir. Pour les emplacements exposés, la version étanche à réservoir lestable (environ 25 L d''eau ou de sable) et joints d''étanchéité affronte pluie et rafales.

## Les avantages du stop-trottoir

Un seul investissement, des centaines de messages : seule l''affiche change, au rythme de vos offres. Nous imprimons vos affiches en série pour planifier toute la saison de communication.', 'Stop-trottoir {{format}} double face',
  'Stop-trottoir personnalisé — chevalet A1 clic-clac', 'Stop-trottoir et chevalet publicitaire : cadre clic-clac A1 double face, affiche changée en 30 s, version étanche lestée pour l''extérieur exposé.', array['stop-trottoir A1','chevalet publicitaire extérieur','porte-affiche trottoir','cadre clic-clac','chevalet double face commerce','stop trottoir lesté']::text[], 'Product',
  'Votre meilleur vendeur reste dehors par tous les temps : le stop-trottoir capte les passants dans les deux sens et change d''argumentaire en trente secondes. Achetez la structure une fois, renouvelez l''affiche à volonté.', '["Intercepte le flux piéton devant votre porte", "Double face : lisible dans les deux sens de circulation", "Changement d''affiche en 30 secondes, sans outil", "Film de protection anti-pluie et anti-UV sur l''affiche", "Version lestée à réservoir pour sites exposés", "Structure réutilisable des années, affiches en série"]'::jsonb, '["Menu du jour de restaurant", "Promotion de commerce de proximité", "Signalement d''entrée en retrait", "Animation de pharmacie", "Fléchage ponctuel d''événement"]'::jsonb,
  '[{"title": "Restaurant", "description": "Le menu du midi s''affiche à 11 h 30 en trente secondes ; le soir, l''affiche carte des vins prend le relais."}, {"title": "Boutique en retrait de rue", "description": "Posé à l''angle passant, le chevalet redirige le flux piéton vers l''entrée située dans la cour."}, {"title": "Pharmacie", "description": "Les campagnes santé saisonnières se succèdent sur le même stop-trottoir, affiches imprimées en lot en début d''année."}, {"title": "Agence événementielle", "description": "Le modèle lesté résiste au vent du parvis et signale l''accueil du séminaire toute la journée."}]'::jsonb, '[{"question": "Quel format d''affiche utiliser ?", "answer": "Le format A1 (59,4×84,1 cm) est le standard des cadres clic-clac. Nous imprimons vos affiches à l''unité ou en série pour planifier vos campagnes."}, {"question": "L''affiche craint-elle la pluie ?", "answer": "Le film de protection du cadre couvre l''affiche ; sur la version étanche, joints et plaques renforcées protègent durablement. Pour l''extérieur permanent, une affiche sur papier résistant ou synthétique est recommandée."}, {"question": "Tient-il debout par grand vent ?", "answer": "Le modèle standard convient aux emplacements abrités ; en site exposé, choisissez la version à réservoir lestable rempli d''eau ou de sable."}, {"question": "Le changement d''affiche est-il vraiment rapide ?", "answer": "Oui : les quatre profils du cadre se relèvent à la main, l''affiche se positionne, les profils se rabattent. Trente secondes par face, sans outil."}, {"question": "Faut-il une autorisation pour le trottoir ?", "answer": "Dans la plupart des communes, l''occupation du domaine public est soumise à autorisation ou redevance : renseignez-vous en mairie avant l''installation."}]'::jsonb, '{"formats": ["Cadre clic-clac pour affiche A1", "Chevalet pliant ~65×117 cm", "Version étanche à réservoir ~25 L"], "supports": ["Structure cadre aluminium ou PVC renforcé", "Affiches papier ou synthétiques imprimées en série"], "finitions": ["Cadres clic-clac double face", "Film de protection d''affiche", "Joints d''étanchéité (version étanche)"], "impression": "Affiches quadri, renouvelables à volonté", "quantites": "Structures à l''unité, affiches de 1 à 100+", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Réservoir lestable eau/sable", "Pliable pour rangement quotidien", "Usage intérieur et extérieur"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── stand_parapluie : Stand parapluie ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'stand_parapluie', '{}'::jsonb, 'fr', 'Stand parapluie textile (mur d''image)', array['stand parapluie','mur d''image','fond de stand','stand pop-up','photocall','stand salon pliable','mur textile','stand parapluie 3x3','fond de scène','stand exposition']::text[],
  'Stand parapluie {{format}} {{finition}} — {{quantite}}', 'Le mur d''image qui tient dans un sac : structure parapluie alu dépliée en 5 minutes, toile textile sublimée infroissable qui reste fixée en permanence.',
  '## Un fond de stand professionnel en cinq minutes

Le stand parapluie déploie un mur d''image complet aussi simplement qu''on ouvre un parapluie : la structure en croisillons d''aluminium s''étire, la toile imprimée — qui reste fixée en permanence — se tend d''elle-même. En cinq à dix minutes, sans outil, votre stand affiche un visuel continu du sol au plafond.

## Caractéristiques techniques

Le format de référence 3×3 couvre environ 227×227 cm, et la gamme s''étend du 2×3 aux très grandes largeurs pour les fonds de scène. Versions droites (pose murale) ou courbes (angles, retour formant réserve de rangement). La toile en polyester stretch 240 g classée M1 est imprimée par sublimation : infroissable, elle se replie avec la structure sans marquer. L''ensemble pèse une dizaine de kilos en 3×3, housse de transport comprise.

## Les avantages du stand parapluie

Un seul bagage, aucune compétence de montage, un rendu mur d''image continu sans raccords visibles : c''est l''équipement salon le plus rentable pour les exposants réguliers. La toile se remplace seule quand la communication évolue.', 'Stand parapluie {{format}} personnalisé',
  'Stand parapluie personnalisé — mur d''image 3x3', 'Stand parapluie textile : mur d''image 227×227 cm monté en 5 min, toile 240 g M1 sublimée infroissable fixée à demeure, housse incluse. Droit ou courbe.', array['stand parapluie personnalisé','mur d''image salon','stand pop-up textile','fond de stand 3x3','photocall entreprise','stand pliable exposition']::text[], 'Product',
  'Arrivez sur le salon avec un sac, exposez cinq minutes plus tard devant un mur d''image professionnel. La toile reste fixée à la structure : au prochain salon, vous ne faites que déplier.', '["Mur d''image continu, sans raccords visibles", "Montage en 5 à 10 minutes, sans outil", "Toile infroissable fixée à demeure sur la structure", "Polyester 240 g M1 conforme aux exigences des salons", "Une dizaine de kilos en 3×3, housse incluse", "Toile remplaçable indépendamment de la structure"]'::jsonb, '["Fond de stand de salon", "Photocall d''événement d''entreprise", "Fond de scène de conférence", "Mur presse et partenaires", "Décor de showroom itinérant"]'::jsonb,
  '[{"title": "Exposant multi-salons", "description": "Le même stand parapluie fait cinq salons par an : déplié, replié, toujours impeccable grâce à la toile infroissable."}, {"title": "Soirée d''entreprise", "description": "Le mur logotypé sert de photocall : chaque photo partagée diffuse la marque sur les réseaux."}, {"title": "Conférence de presse", "description": "Le fond aux logos répétés cadre les interviews vidéo avec un rendu net, sans reflet de flash."}, {"title": "Stand en angle", "description": "La version courbe habille l''angle du stand et ménage derrière elle une réserve pour les cartons et manteaux."}]'::jsonb, '[{"question": "Faut-il démonter la toile pour replier le stand ?", "answer": "Non : c''est tout l''intérêt du système. La toile stretch reste fixée à la structure, se replie avec elle sans se froisser et ressort tendue au déploiement suivant."}, {"question": "Combien de temps pour le montage ?", "answer": "Cinq à dix minutes seul ou à deux : on déplie la structure en croisillons, on verrouille, on lisse la toile. Aucun outil, aucune compétence particulière."}, {"question": "Droit ou courbe : que choisir ?", "answer": "Droit pour un mur d''image plaqué au fond du stand ; courbe pour habiller un angle ou créer une réserve de rangement derrière la toile."}, {"question": "Le transport est-il vraiment facile ?", "answer": "Le 3×3 pèse environ 10 kg, housse comprise : il voyage en coffre de voiture, en train ou en soute, porté par une seule personne."}, {"question": "Quel fichier fournir ?", "answer": "Votre visuel sur le gabarit du format choisi, échelle 1 en 150 dpi, CMJN. Anticipez le retour des côtés et gardez textes et logos dans la zone frontale."}]'::jsonb, '{"formats": ["3×3 : ~227×227 cm", "Gamme de 2×3 aux grandes largeurs (structures ~150 à ~740 cm)", "Versions droites ou courbes"], "supports": ["Polyester stretch 240 g classé M1, impression sublimation"], "finitions": ["Toile fixée à demeure, infroissable", "Retours latéraux imprimés", "Visuel remplaçable"], "impression": "Sublimation quadri haute définition", "quantites": "1 à 20 exemplaires, tarif dégressif", "delais": "Standard 5 à 7 jours ouvrés, express possible", "options": ["Structure aluminium et fibre de verre incluse", "Housse de transport incluse", "Classement feu M1", "Poids ~10 kg en 3×3"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── etiquette : Étiquettes / Stickers ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'etiquette', '{}'::jsonb, 'fr', 'Étiquettes et stickers adhésifs personnalisés', array['étiquette personnalisée','sticker adhésif','autocollant sur mesure','étiquette produit','étiquette en rouleau','planche d''étiquettes','sticker vinyle','étiquette bouteille','adhésif imprimé','étiquette résistante à l''eau','kiss-cut','découpe à la forme']::text[],
  'Étiquettes et stickers {{matiere}} {{format}} — impression {{finition}}', 'Étiquettes et stickers adhésifs imprimés sur mesure : en planche, en rouleau ou découpés à la forme, sur {{matiere}}, dès {{quantite}} exemplaires.',
  '## Une famille complète pour tout votre étiquetage

De la planche A4 économique à la bobine prête pour votre étiqueteuse, en passant par le sticker découpé à la forme, cette famille couvre l''ensemble de vos besoins d''identification produit et de communication adhésive. Chaque déclinaison se configure en {{format}}, sur le support {{matiere}} adapté à votre usage, avec la finition {{finition}} de votre choix.

## Caractéristiques techniques

Supports papier (couché, non couché, texturé, doré, noir) ou synthétiques (polypropylène blanc ou transparent, vinyle, holographique), en grammages de 73 à 222 g ou films de 50 à 150 µ. Découpe rectangulaire, ronde, ovale ou entièrement libre, à pleine chair ou mi-chair (kiss-cut). Finitions au choix : vernis anti-rayure, pelliculage mat, brillant ou soft-touch, vernis sélectif, dorure or ou argent. Des supports barrière résistants à l''humidité et des adhésifs aptes au contact indirect avec les denrées sont disponibles.

## Vos avantages

Vous étiquetez vos produits avec un rendu professionnel, quelle que soit la série : petites quantités pour tester un lancement, bobines multivisuels pour industrialiser toute une gamme. Un seul interlocuteur, un contrôle systématique de vos fichiers, et des délais de fabrication courts pour suivre le rythme de vos mises en marché.', 'Étiquettes et stickers personnalisés {{format}}',
  'Étiquettes et stickers personnalisés — impression pro', 'Impression d''étiquettes et stickers sur mesure : planche, rouleau, découpe à la forme. Papier ou synthétique, dorure, vernis. Petites et grandes séries.', array['étiquette personnalisée','sticker sur mesure','autocollant imprimé','étiquette rouleau','étiquette produit','sticker vinyle','impression étiquettes','adhésif personnalisé']::text[], 'Product',
  'Vos produits méritent une identité qui se remarque en rayon comme au déballage. Choisissez le format, la matière et la finition : nous imprimons des étiquettes qui tiennent, du frigo du caviste au fond du panier e-commerce.', '["Trois modes au choix : planche, rouleau ou découpe à la forme", "Large éventail de supports papier et synthétiques", "Finitions premium : dorure, vernis sélectif, soft-touch", "Supports résistants à l''eau et à l''humidité disponibles", "Petites séries acceptées pour tester avant d''industrialiser", "Fichiers vérifiés avant impression, zéro mauvaise surprise"]'::jsonb, '["Étiquetage de gamme cosmétique", "Identification de bocaux et conserves", "Habillage de bouteilles artisanales", "Stickers promotionnels de marque", "Scellés et fermetures de sachets"]'::jsonb,
  '[{"title": "Lancement d''une gamme cosmétique", "description": "Une marque de soins fait imprimer ses étiquettes en rouleau sur film blanc avec vernis sélectif pour habiller flacons et pots avec un rendu haut de gamme."}, {"title": "Conserverie artisanale", "description": "Un producteur étiquette ses bocaux avec un papier barrière résistant à l''humidité, qui supporte la chaîne du froid sans gondoler."}, {"title": "Boutique e-commerce", "description": "Un e-commerçant scelle ses colis avec des stickers logo découpés à la forme, transformant chaque ouverture de paquet en moment de marque."}, {"title": "Événement ou salon", "description": "Une entreprise distribue des planches de stickers mixant plusieurs visuels pour animer son stand et fidéliser ses visiteurs."}]'::jsonb, '[{"question": "Quelle différence entre planche, rouleau et découpe à la forme ?", "answer": "La planche convient aux petites quantités et aux visuels multiples ; le rouleau est fait pour l''étiquetage en série, manuel ou à l''étiqueteuse ; la découpe à la forme donne un sticker unitaire au contour exact de votre visuel."}, {"question": "Mes étiquettes résisteront-elles à l''eau ?", "answer": "Oui, à condition de choisir un support adapté : polypropylène, vinyle ou papier barrière traité contre l''humidité, complété d''un vernis ou d''un pelliculage protecteur."}, {"question": "Comment préparer un fichier avec découpe personnalisée ?", "answer": "Fournissez votre visuel avec un tracé de coupe vectoriel sur un calque dédié, plus un fond perdu de 2 à 3 mm au-delà du tracé. Nos équipes contrôlent le fichier avant fabrication."}, {"question": "Puis-je commander une petite quantité pour tester ?", "answer": "Oui, les planches et stickers démarrent à quelques dizaines d''exemplaires, ce qui permet de valider un packaging avant de passer en bobine grande série."}, {"question": "Les adhésifs conviennent-ils aux produits alimentaires ?", "answer": "Des supports adaptés au contact indirect avec les denrées sont proposés, ainsi que des papiers anti-tache pour les produits gras. Précisez l''usage alimentaire lors de votre demande."}]'::jsonb, '{"formats": ["Planche A4 210×297 mm", "Rouleau : étiquettes de 10×10 à 300×300 mm", "Découpe forme : 40×40 à 500×500 mm", "Formes : rectangle, carré, cercle, ovale, coins ronds, libre"], "supports": ["Papier couché brillant 80 g", "Papier non couché 73 g", "Papier doré 74 g / noir 95 g", "Papier coton texturé 222 g", "PP transparent 50 µ / PP blanc 60 µ", "Film holographique 150 µ", "Papier barrière résistant à l''humidité"], "finitions": ["Vernis brillant anti-rayure", "Pelliculage mat / brillant / soft-touch", "Vernis sélectif", "Dorure or ou argent", "Découpe pleine chair ou mi-chair (kiss-cut)"], "impression": "Quadrichromie recto, blanc de soutien possible sur supports transparents", "quantites": "Dès 50 exemplaires (stickers) ou 100 étiquettes (rouleau pose manuelle), paliers dégressifs jusqu''à 10 000 et plus", "delais": "Fabrication express possible sur les gammes standard, délais affichés à la configuration", "options": ["Mandrin 40 ou 76 mm (rouleau)", "Sens de déroulement au choix", "Multivisuels sur une même commande", "Supports aptes au contact alimentaire indirect", "Adhésif repositionnable sans colle"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── etiquette_planche : Étiquettes en planche A4 ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'etiquette_planche', '{}'::jsonb, 'fr', 'Étiquettes adhésives en planche A4', array['étiquettes en planche','planche A4 autocollante','planche de stickers','étiquettes à détacher','feuille d''étiquettes','étiquettes multi-formats','kiss-cut planche','étiquettes adhésives A4','kit d''étiquetage','petites séries étiquettes']::text[],
  'Planche d''étiquettes A4 {{matiere}} — jusqu''à 40 visuels {{finition}}', 'Planche A4 d''étiquettes adhésives prédécoupées : combinez jusqu''à 40 formes et visuels différents sur une même feuille, dès {{quantite}} planches.',
  '## La solution maligne pour les petites séries

La planche d''étiquettes A4 regroupe sur une seule feuille de 210×297 mm tous les adhésifs dont vous avez besoin : jusqu''à une quarantaine d''étiquettes, de formes et de tailles différentes, prédécoupées en mi-chair pour se détacher d''un geste. C''est le format idéal quand votre gamme compte plusieurs références ou que vos volumes ne justifient pas encore la bobine.

## Caractéristiques techniques

Impression quadrichromie sur papier couché satin adhésif permanent 80 g. La découpe laser autorise toutes les formes — rondes, ovales, contours libres — mixées librement sur la même planche, sans outillage ni frais de forme. Un vernis brillant optionnel protège les visuels des frottements. Chaque planche optimise la surface imprimable et limite la chute de papier.

## Vos avantages

Une commande, une planche, toute votre gamme étiquetée : parfums différents, tailles de pots variées, mentions promotionnelles ponctuelles. Vous détachez ce dont vous avez besoin au fil de la production, sans immobiliser des bobines entières par référence. Les créateurs, artisans et TPE y trouvent une porte d''entrée économique vers un étiquetage vraiment professionnel, avec la même qualité d''impression que les grandes séries.', 'Planches d''étiquettes A4 personnalisées {{finition}}',
  'Planche d''étiquettes A4 personnalisées — multi-formes', 'Planches A4 d''étiquettes adhésives : jusqu''à 40 formes et visuels par feuille, découpe laser, papier 80 g, vernis en option. Idéal petites séries.', array['planche étiquettes A4','étiquettes en planche','planche stickers personnalisés','feuille autocollants','étiquettes prédécoupées','étiquettes petites séries']::text[], 'Product',
  'Toute votre gamme sur une seule feuille : mixez formats et visuels sur la même planche A4 et étiquetez au fil de l''eau. La souplesse d''un kit, la qualité d''une impression professionnelle.', '["Jusqu''à 40 étiquettes par planche, formes et tailles mixables", "Découpe laser sans frais d''outillage", "Détachement facile grâce à la prédécoupe mi-chair", "Économique pour les gammes multi-références", "Vernis de protection en option", "Faible chute de papier, surface optimisée"]'::jsonb, '["Étiquetage de gammes artisanales", "Kits d''étiquettes multi-parfums", "Mentions promo saisonnières", "Étiquetage cadeaux et coffrets", "Tests avant passage en bobine"]'::jsonb,
  '[{"title": "Savonnerie artisanale", "description": "Une créatrice regroupe les étiquettes de ses huit parfums de savons sur une planche unique, et détache selon sa production du jour."}, {"title": "Torréfacteur multi-origines", "description": "Un torréfacteur combine étiquettes de face, pastilles d''origine et mentions de date sur la même planche pour ses sachets de café."}, {"title": "Opération de Noël", "description": "Une boutique commande des planches mêlant stickers cadeaux ronds et bandeaux promotionnels pour habiller ses paquets de fin d''année."}, {"title": "Prototypage packaging", "description": "Une jeune marque valide plusieurs pistes graphiques en réel sur ses emballages avant d''engager une production en rouleau."}]'::jsonb, '[{"question": "Combien d''étiquettes puis-je placer sur une planche ?", "answer": "Jusqu''à une quarantaine selon leurs dimensions. Formes et tailles peuvent être différentes sur la même feuille A4."}, {"question": "Comment fournir mon fichier ?", "answer": "Un fichier à l''échelle de la planche avec chaque tracé de coupe en vectoriel sur un calque séparé, et 2 mm de fond perdu autour de chaque étiquette. Nous vérifions le fichier avant impression."}, {"question": "Qu''est-ce que la découpe mi-chair (kiss-cut) ?", "answer": "La lame entaille uniquement l''étiquette, pas le support siliconé : chaque adhésif se décolle facilement tandis que la planche reste entière et facile à stocker."}, {"question": "Ces étiquettes résistent-elles à l''eau ?", "answer": "Le papier couché 80 g convient aux usages intérieurs et secs ; le vernis améliore la tenue aux frottements. Pour une exposition à l''humidité, orientez-vous vers nos étiquettes en rouleau sur support synthétique."}, {"question": "Quelle quantité minimale ?", "answer": "Quelques planches suffisent pour lancer une commande, ce qui en fait la solution la plus accessible pour démarrer un étiquetage professionnel."}]'::jsonb, '{"formats": ["Planche A4 210×297 mm", "Jusqu''à ~40 étiquettes par planche", "Formes libres, rondes, ovales, rectangulaires mixables"], "supports": ["Papier couché satin adhésif permanent 80 g"], "finitions": ["Vernis brillant en option", "Découpe laser mi-chair (kiss-cut)"], "impression": "Quadrichromie recto", "quantites": "Petites séries dès quelques planches, paliers dégressifs", "delais": "Fabrication rapide, délai précis affiché à la commande", "options": ["Multi-visuels et multi-formes sur une même planche", "Gabarit de placement fourni sur demande"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── etiquette_rouleau : Étiquettes en rouleau ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'etiquette_rouleau', '{}'::jsonb, 'fr', 'Étiquettes adhésives en rouleau (bobine)', array['étiquette en rouleau','étiquette bobine','étiquette pose automatique','étiquette étiqueteuse','étiquette bouteille vin','étiquette cosmétique','étiquette résistante humidité','dorure étiquette','étiquette polypropylène','bande de garantie','étiquette pot','mandrin 76']::text[],
  'Étiquettes en rouleau {{format}} {{matiere}} — {{finition}}, dès {{quantite}} ex.', 'Étiquettes en bobine pour pose manuelle ou automatique : {{format}}, support {{matiere}}, finition {{finition}}, mandrin 40 ou 76 mm.',
  '## L''étiquetage professionnel en série

Conditionnées en bobine, ces étiquettes accompagnent votre production, que vous posiez à la main ou sur ligne automatisée. Formes carrées, rondes, ovales, festonnées ou bandes de garantie, dimensions libres de 1 à 30 cm : chaque étiquette est configurée pour votre contenant, du pot de confiture au fût de bière.

## Caractéristiques techniques

Plus de dix supports au choix : papiers couchés et non couchés, papiers texturés pour le vin, papiers dorés ou noirs pour la cosmétique, films polypropylène blancs ou transparents (50 à 60 µ), et papiers barrière résistants à l''humidité qui supportent le seau à glace. Finitions vernis anti-rayure, pelliculage mat, brillant ou soft-touch, vernis sélectif et dorure or ou argent. Pour la pose automatique : mandrin de 40 ou 76 mm, sens de déroulement et orientation du visuel paramétrables, espacement inter-étiquettes ajusté à votre machine.

## Vos avantages

Vous gagnez un temps précieux au conditionnement et une régularité de pose irréprochable. Le multivisuel permet d''imprimer jusqu''à 20 déclinaisons dans une même commande — toute une gamme de parfums ou de millésimes en une seule fabrication, avec des tarifs dégressifs.', 'Étiquettes en rouleau {{matiere}} pour pose manuelle ou automatique',
  'Étiquettes en rouleau personnalisées — bobine pro', 'Impression d''étiquettes en bobine : pose manuelle ou étiqueteuse, mandrin 40/76 mm, supports résistants à l''eau, dorure, vernis. Multivisuels jusqu''à 20.', array['étiquette en rouleau','étiquette bobine','étiquette pose automatique','étiquette bouteille','étiquette étiqueteuse','étiquette vin','étiquette cosmétique','impression bobine']::text[], 'Product',
  'De la pose à la main aux lignes automatisées, vos étiquettes arrivent en bobine, prêtes à défiler. Jusqu''à 20 visuels par commande : toute votre gamme étiquetée en une seule fabrication.', '["Compatible étiqueteuses : mandrin, sens et espacement configurables", "Plus de 10 supports, du papier texturé vin au film transparent", "Résistance à l''humidité certifiée pour les boissons fraîches", "Dorure or/argent et vernis sélectif pour un rendu premium", "Jusqu''à 20 visuels dans une même commande", "Formes libres, y compris bandes de garantie inviolables"]'::jsonb, '["Habillage bouteilles vin et bière", "Étiquetage flacons cosmétiques", "Conditionnement agroalimentaire en série", "Scellés d''inviolabilité sur packaging", "Identification de pots et bocaux"]'::jsonb,
  '[{"title": "Domaine viticole", "description": "Un vigneron habille son blanc de garde avec un papier texturé résistant au seau à glace, rehaussé d''une dorure or sur le millésime."}, {"title": "Brasserie artisanale", "description": "Une brasserie imprime les étiquettes de ses six recettes en une commande multivisuel, livrées en bobines prêtes pour son étiqueteuse semi-automatique."}, {"title": "Marque de cosmétiques", "description": "Un laboratoire choisit un film transparent avec blanc de soutien pour un effet sans étiquette sur ses flacons de sérum."}, {"title": "Conserverie", "description": "Un producteur utilise un papier anti-tache adapté aux produits gras pour étiqueter ses rillettes et terrines sans auréoles."}]'::jsonb, '[{"question": "Pose manuelle ou pose automatique : comment choisir ?", "answer": "Sans étiqueteuse, la pose manuelle suffit et démarre à une centaine d''étiquettes. Avec une machine, optez pour la version pose automatique : mandrin, sens de déroulement et espacement sont alors calibrés pour votre équipement."}, {"question": "Comment connaître le bon sens de déroulement ?", "answer": "Il dépend de votre étiqueteuse : notez comment la bande se présente en sortie de mandrin (visuel vers l''extérieur ou l''intérieur, tête en premier ou non). Un schéma des orientations vous est proposé à la configuration."}, {"question": "Mes étiquettes tiendront-elles dans un seau à glace ?", "answer": "Oui avec un support barrière résistant à l''humidité, conçu pour les bouteilles servies au frais : le papier ne se délite pas et l''adhésif ne se décolle pas."}, {"question": "Puis-je mélanger plusieurs visuels dans une commande ?", "answer": "Oui, jusqu''à 20 visuels différents à dimensions identiques, avec un tarif dégressif sur le volume global. Idéal pour une gamme complète."}, {"question": "Quel fichier fournir pour une forme personnalisée ?", "answer": "Un visuel avec tracé de coupe vectoriel sur calque dédié et fond perdu de 2 mm. Sur film transparent, indiquez les zones de blanc de soutien pour garder des couleurs denses."}]'::jsonb, '{"formats": ["De 10×10 à 300×300 mm", "Carré, rectangle, cercle, ovale, coins ronds, festonné", "Bande de garantie (scellé)"], "supports": ["Papier couché brillant 80 g", "Papier non couché 73 g", "Papier doré 74 g / noir 95 g", "PP transparent 50 µ / PP blanc brillant 60 µ / film argent 60 µ", "Papier barrière résistant à l''humidité", "Papier sulfurisé anti-tache", "Papier à fibres végétales (éco)"], "finitions": ["Vernis brillant anti-rayure", "Pelliculage brillant / mat / soft-touch", "Vernis sélectif", "Dorure or ou argent"], "impression": "Quadrichromie, blanc de soutien sur supports transparents et métallisés", "quantites": "Dès 100 étiquettes (pose manuelle), 500 (pose automatique), dégressif au-delà de 10 000", "delais": "Fabrication courte en standard, quelques jours pour la pose automatique", "options": ["Mandrin Ø 40 ou 76 mm", "Sens de déroulement intérieur/extérieur, orientation 0/90/180/-90°", "Espacement inter-étiquettes 4 à 100 mm", "Jusqu''à 20 visuels par commande", "Boîte distributrice pour laizes jusqu''à 68 mm"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── sticker_forme : Sticker découpe forme ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'sticker_forme', '{}'::jsonb, 'fr', 'Stickers découpés à la forme', array['sticker découpé à la forme','autocollant forme personnalisée','sticker vinyle','sticker extérieur','autocollant résistant UV','sticker holographique','kiss-cut','sticker logo','autocollant sur mesure','sticker publicitaire']::text[],
  'Stickers découpe forme {{format}} {{matiere}} — {{finition}}', 'Stickers découpés au contour exact de votre visuel, de 4 à 50 cm, sur {{matiere}}, résistants aux UV et à l''eau selon support, dès {{quantite}} exemplaires.',
  '## Votre logo, au millimètre près

Le sticker à la forme épouse exactement le contour de votre visuel : plus de fond carré ni de marge blanche, votre marque s''affiche telle quelle sur un ordinateur, une vitrine, un packaging ou un véhicule. Du petit format de 4 cm au grand adhésif de 50 cm, chaque pièce est découpée numériquement, à pleine chair ou en mi-chair sur son support.

## Caractéristiques techniques

Supports synthétiques pour l''extérieur — polypropylène blanc 50 µ, transparent, holographique métallisé 150 µ, vinyle — ou papiers pour l''intérieur, du couché 80 g au papier coton texturé 222 g. Un adhésif repositionnable sans colle est disponible pour les poses temporaires. Finitions pelliculage brillant, mat ou soft-touch, vernis anti-rayure protégeant des UV, vernis sélectif, dorure or ou argent, effets métallisés ou pailletés. Retrait propre, sans résidu.

## Vos avantages

Un support de communication au coût unitaire imbattable et à la durée d''exposition longue : distribué en caisse, glissé dans un colis ou collé en vitrine, le sticker travaille pour votre marque pendant des mois. Les séries démarrent bas pour tester, et montent à plusieurs milliers pour vos campagnes.', 'Stickers personnalisés découpés à la forme {{format}}',
  'Stickers découpés à la forme — vinyle résistant UV', 'Stickers au contour exact de votre logo, 4 à 50 cm : vinyle, PP, holographique, dorure. Résistants eau et UV, retrait sans résidu. Dès 50 exemplaires.', array['sticker découpe forme','autocollant personnalisé','sticker vinyle extérieur','sticker logo','autocollant UV','sticker holographique','kiss-cut']::text[], 'Product',
  'Un sticker à la forme de votre logo, c''est votre marque qui voyage sur les ordinateurs, les vitrines et les colis de vos clients. Résistant, précis, mémorable — dès 50 exemplaires.', '["Découpe numérique au contour exact du visuel", "Formats de 4 à 50 cm, du goodie au marquage vitrine", "Supports extérieurs résistants eau et UV", "Effets holographique, métallisé, pailleté, dorure", "Retrait sans résidu, option repositionnable sans colle", "Petites séries dès 50 exemplaires, fabrication rapide"]'::jsonb, '["Goodies de marque à distribuer", "Personnalisation de colis e-commerce", "Marquage vitrine et mobilier", "Street-marketing événementiel", "Décoration de matériel et flottes"]'::jsonb,
  '[{"title": "Campagne de notoriété", "description": "Une startup glisse un sticker logo dans chaque commande ; ses clients les collent sur leurs ordinateurs et diffusent la marque au quotidien."}, {"title": "Réseau de franchises", "description": "Une enseigne équipe ses points de vente de stickers vitrine découpés à la forme, résistants aux UV derrière les vitrages exposés."}, {"title": "Festival", "description": "Un organisateur distribue des stickers holographiques en édition limitée, devenus objets de collection pour les festivaliers."}, {"title": "Atelier / flotte technique", "description": "Un artisan marque caisses, machines et véhicules utilitaires avec des adhésifs vinyle qui supportent lavages et intempéries."}]'::jsonb, '[{"question": "Quelle différence entre pleine chair et kiss-cut ?", "answer": "En pleine chair, le sticker et son dorsal sont découpés ensemble : chaque pièce est indépendante. En kiss-cut, seule l''étiquette est entaillée et se décolle d''un support plus grand, plus simple à distribuer."}, {"question": "Ces stickers tiennent-ils en extérieur ?", "answer": "Oui sur supports synthétiques (PP, vinyle) avec vernis anti-rayure ou pelliculage : ils résistent aux UV, à la pluie et aux écarts de température pendant plusieurs années."}, {"question": "Le retrait laisse-t-il des traces ?", "answer": "Non, les adhésifs se retirent proprement des surfaces lisses. Pour des poses temporaires répétées, choisissez l''adhésif repositionnable sans colle."}, {"question": "Comment préparer le tracé de découpe ?", "answer": "Ajoutez un tracé vectoriel fermé sur un calque dédié, à 2-3 mm minimum du visuel, en évitant les angles trop fins. Nous contrôlons et ajustons le tracé si nécessaire."}, {"question": "Quelle est la quantité minimale ?", "answer": "Les séries démarrent à 50 exemplaires et montent jusqu''à 9 000, avec un prix unitaire dégressif — pratique pour tester un visuel avant une grande campagne."}]'::jsonb, '{"formats": ["De 40×40 à 500×500 mm", "Contour libre, rectangle, cercle, ovale, étoile", "Découpe pleine chair ou kiss-cut"], "supports": ["PP blanc 50 µ", "PP transparent", "Film holographique métallisé 150 µ", "Vinyle adhésif", "Papier couché 80 g / non couché 73 g", "Papier coton texturé 222 g", "Adhésif repositionnable sans colle"], "finitions": ["Pelliculage brillant / mat / soft-touch", "Vernis anti-rayure tenue UV", "Vernis sélectif", "Dorure or ou argent", "Effets métallisé et pailleté"], "impression": "Quadrichromie, blanc de soutien sur transparent et holographique", "quantites": "50 à 9 000 exemplaires, dégressif par paliers", "delais": "Fabrication en quelques jours ouvrés", "options": ["Tenue extérieure eau/UV selon support", "Retrait sans résidu", "Livraison à l''unité ou en planches selon format"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── packaging : Packaging / Emballage ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'packaging', '{}'::jsonb, 'fr', 'Packaging et emballages personnalisés', array['packaging personnalisé','emballage sur mesure','boîte carton imprimée','emballage e-commerce','packaging produit','boîte personnalisée','coffret cadeau entreprise','sac papier logo','emballage alimentaire','packaging petite série','étui carton','emballage marque']::text[],
  'Packaging {{format}} {{matiere}} personnalisé — dès {{quantite}} exemplaire', 'Emballages imprimés à vos couleurs : boîtes pliantes, expédition, coffrets premium et sacs papier, en {{matiere}}, dès {{quantite}} exemplaire selon modèle.',
  '## L''emballage, premier contact avec votre marque

Avant même le produit, c''est le packaging que votre client touche. Cette famille rassemble tous vos emballages imprimés : boîtes pliantes pour vos produits, boîtes d''expédition pour vos colis, coffrets rigides pour vos cadeaux d''affaires, sacs papier pour vos boutiques. Chaque modèle se configure en {{format}} avec la matière {{matiere}} et la finition adaptées à votre image.

## Caractéristiques techniques

Cartons graphiques, micro-cannelure E de 1,8 mm et contrecollés rigides jusqu''à 380 g habillés ; kraft brun naturel ou blanc couché. Impression quadrichromie extérieure et intérieure, blanc sélectif sur kraft, fermetures adaptées à chaque usage : rabats, fond automatique, bande de scellage, aimants. Les modèles pliants sont livrés à plat, rainés et découpés, prêts à monter sans outil. Des versions aptes au contact alimentaire complètent la gamme.

## Vos avantages

La plupart des modèles pliants démarrent à l''exemplaire : prototypez, testez en conditions réelles, puis lancez la série sans risque de stock dormant. Fichiers contrôlés systématiquement, délais courts, et une expérience de déballage qui fait la différence entre livrer un produit et livrer une marque.', 'Packaging personnalisé {{format}} : boîtes, coffrets et sacs',
  'Packaging personnalisé — boîtes, coffrets, sacs imprimés', 'Emballages imprimés à vos couleurs : boîtes pliantes dès 1 exemplaire, boîtes e-commerce, coffrets aimantés, sacs kraft. Impression int/ext, montage facile.', array['packaging personnalisé','emballage sur mesure','boîte carton personnalisée','packaging e-commerce','coffret entreprise','sac papier personnalisé','emballage imprimé','packaging marque']::text[], 'Product',
  'Votre packaging est le premier vendeur silencieux de votre marque. Boîtes, coffrets et sacs imprimés à vos couleurs, dès l''exemplaire unique : testez, validez, déployez.', '["Gamme complète : produit, expédition, premium, boutique", "Petites séries dès 1 exemplaire selon modèle", "Impression intérieure et extérieure pour l''effet unboxing", "Kraft recyclable ou carton blanc premium", "Livrés à plat, montage sans outil", "Contrôle des fichiers avant fabrication"]'::jsonb, '["Colis e-commerce à l''image de la marque", "Coffrets cadeaux clients et salariés", "Emballage produit en linéaire", "Sacs boutique et événementiel", "Prototypes packaging avant série"]'::jsonb,
  '[{"title": "Marque DNVB", "description": "Une marque en ligne harmonise boîte d''expédition imprimée à l''intérieur, sticker de scellage et carte de remerciement pour une expérience de déballage signature."}, {"title": "Cadeaux d''affaires", "description": "Une PME offre ses coffrets de fin d''année dans des boîtes aimantées habillées à ses couleurs, sans passer par un packaging générique."}, {"title": "Épicerie fine", "description": "Un producteur conditionne ses bocaux dans des boîtes pliantes kraft imprimées en blanc sélectif, cohérentes avec son positionnement naturel."}, {"title": "Ouverture de boutique", "description": "Un commerce lance son identité avec sacs papier logotés et boîtes à rabat assortis, dès de petites quantités."}]'::jsonb, '[{"question": "Puis-je vraiment commander un seul exemplaire ?", "answer": "Oui sur la plupart des modèles pliants et d''expédition : parfait pour valider un prototype en conditions réelles avant de lancer la série."}, {"question": "Comment choisir entre kraft brun et carton blanc ?", "answer": "Le kraft brun affirme un positionnement naturel et recyclé, avec une impression sobre valorisée par le blanc sélectif ; le carton blanc couché restitue fidèlement les couleurs vives et les photos."}, {"question": "Les boîtes arrivent-elles montées ?", "answer": "Non, elles sont livrées à plat, rainées et prédécoupées : le montage se fait à la main en quelques secondes, sans colle ni outil, et le stockage est compact."}, {"question": "Peut-on imprimer l''intérieur de la boîte ?", "answer": "Oui, extérieur, intérieur ou les deux : l''impression intérieure transforme l''ouverture du colis en véritable moment de marque."}, {"question": "Existe-t-il des emballages pour l''alimentaire ?", "answer": "Oui, une gamme dédiée au contact alimentaire couvre snacking, plats préparés et produits chauds : étuis, barquettes, boîtes à rabat et sachets kraft."}]'::jsonb, '{"formats": ["Boîtes produit et expédition multi-formats", "Coffrets rigides 4 formats standard", "Sacs papier 3 tailles", "Formes : rabat, fond automatique, fourreau, aimantée"], "supports": ["Carton graphique blanc", "Micro-cannelure E 1,8 mm kraft ou blanc", "Carton contrecollé rigide 380 g habillé", "Kraft recyclable 27 à 60 g (sacs)"], "finitions": ["Impression intérieure/extérieure", "Blanc sélectif sur kraft", "Habillage Pantone, sérigraphie", "Fermeture aimantée, rabats, bande de scellage"], "impression": "Quadrichromie recto/verso, sérigraphie 1-2 couleurs sur coffrets", "quantites": "Dès 1 exemplaire (pliant), 5 à 25 minimum sur le premium, paliers dégressifs", "delais": "Express sur les pliants standard, plus long sur le contrecollé premium", "options": ["Contact alimentaire sur gamme dédiée", "Fenêtre selon modèles", "Ruban adhésif personnalisé assorti", "Livraison à plat"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── boite_pliante : Boîte pliante carton ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'boite_pliante', '{}'::jsonb, 'fr', 'Boîtes pliantes carton personnalisées', array['boîte pliante','boîte carton personnalisée','étui carton','boîte fond automatique','boîte à rabat','boîte fourreau','packaging produit','boîte à suspendre','boîte petite série','emballage produit carton']::text[],
  'Boîte pliante {{format}} {{matiere}} — impression {{finition}}', 'Boîtes pliantes en carton imprimées à vos couleurs : fond automatique, rabat, fourreau ou berlingot, livrées à plat, dès {{quantite}} exemplaire.',
  '## La boîte qui habille votre produit

La boîte pliante est l''emballage produit par excellence : légère, compacte à stocker, montée en quelques secondes au moment du conditionnement. Déclinée en une dizaine de modèles — standard, fond automatique, rabat, fourreau coulissant, berlingot bombé, version renforcée ou à suspendre en linéaire — elle s''adapte à chaque produit et à chaque circuit de vente.

## Caractéristiques techniques

Carton graphique ou micro-cannelure, en blanc couché pour des couleurs éclatantes ou en kraft brun pour un rendu naturel, avec impression quadrichromie extérieure et intérieure et blanc sélectif sur kraft. Les découpes spécifiques (fenêtre, perforation de suspension, encoches) se configurent selon le modèle. Toutes les boîtes sont livrées à plat, rainées et prédécoupées : montage manuel sans colle ni outil, le fond automatique se verrouillant d''un simple geste.

## Vos avantages

Vous démarrez à l''exemplaire pour valider un prototype, puis produisez la série au même endroit. Le stockage à plat divise l''encombrement, le montage rapide fluidifie vos conditionnements, et l''impression intérieure ajoute la touche qui transforme un simple emballage en expérience de marque.', 'Boîtes pliantes carton personnalisées {{format}}',
  'Boîte pliante carton personnalisée — dès 1 exemplaire', 'Boîtes pliantes imprimées : fond automatique, rabat, fourreau, à suspendre. Kraft ou blanc, impression int/ext, livrées à plat. Dès 1 exemplaire.', array['boîte pliante carton','boîte personnalisée','étui carton imprimé','boîte fond automatique','packaging produit','boîte à rabat','boîte kraft']::text[], 'Product',
  'Une boîte montée en trois secondes, stockée à plat, imprimée à vos couleurs dedans comme dehors. Du prototype unitaire à la série, votre produit mérite mieux qu''un emballage anonyme.', '["Dix modèles : fond automatique, rabat, fourreau, berlingot, à suspendre…", "Dès 1 exemplaire pour prototyper sans risque", "Livrée à plat : stockage compact, montage sans outil", "Impression intérieure et extérieure", "Kraft naturel ou blanc couché haute fidélité couleur", "Version renforcée pour les produits fragiles"]'::jsonb, '["Emballage primaire produit retail", "Coffret cadeau léger", "PLV et boîte à suspendre en rayon", "Conditionnement cosmétique ou épicerie", "Prototype avant industrialisation"]'::jsonb,
  '[{"title": "Marque de thé", "description": "Un créateur conditionne ses sachets dans des étuis à fond automatique imprimés, montés à la volée pendant les pics de commande."}, {"title": "Cosmétique solide", "description": "Une savonnerie choisit une boîte kraft avec fenêtre de découpe pour montrer le produit tout en affichant un positionnement zéro plastique."}, {"title": "Accessoires en linéaire", "description": "Un fabricant présente ses accessoires en boîtes à suspendre avec perforation européenne, prêtes pour les broches de rayon."}, {"title": "Édition limitée", "description": "Une marque teste trois designs de boîte fourreau en exemplaires uniques avant de retenir la version définitive pour sa série."}]'::jsonb, '[{"question": "Quelle différence entre fond automatique et fond à rabats ?", "answer": "Le fond automatique se verrouille seul au dépliage de la boîte : idéal pour les cadences de conditionnement élevées. Les rabats classiques demandent un pliage manuel mais restent plus économiques."}, {"question": "Puis-je ajouter une fenêtre pour voir le produit ?", "answer": "Oui sur les modèles compatibles : une découpe laisse apparaître le produit, avec ou sans film selon la configuration."}, {"question": "Comment préparer mon fichier d''impression ?", "answer": "Travaillez sur le gabarit à plat du modèle choisi, fourni au format vectoriel : chaque face, rabat et zone de collage y est repérée. Nos équipes vérifient le fichier avant lancement."}, {"question": "Quelle boîte pour un produit lourd ou fragile ?", "answer": "La version renforcée en micro-cannelure absorbe les chocs et supporte davantage de poids que le carton graphique simple. Précisez le poids du produit pour valider le choix."}, {"question": "Quel est le minimum de commande ?", "answer": "Un seul exemplaire sur la plupart des modèles : commandez un prototype, validez le montage et le rendu, puis lancez la quantité définitive."}]'::jsonb, '{"formats": ["Multi-formats configurables par modèle", "Standard, cube, rectangulaire fond automatique, rabat, fourreau, berlingot, renforcée, à suspendre"], "supports": ["Carton graphique blanc couché", "Micro-cannelure kraft brun ou blanc", "Cartons recyclables"], "finitions": ["Impression intérieure et/ou extérieure", "Blanc sélectif sur kraft", "Fenêtre de découpe selon modèle", "Perforation de suspension"], "impression": "Quadrichromie recto/verso", "quantites": "Dès 1 exemplaire, paliers dégressifs en série", "delais": "Fabrication courte, prototype expédié rapidement", "options": ["Livrée à plat rainée et découpée", "Montage sans colle", "Version contact alimentaire sur gamme dédiée"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── boite_expedition : Boîte d'expédition e-commerce ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'boite_expedition', '{}'::jsonb, 'fr', 'Boîtes d''expédition e-commerce personnalisées', array['boîte expédition personnalisée','boîte e-commerce','packaging colis','boîte envoi postal','carton expédition imprimé','boîte unboxing','boîte à rabat expédition','boîte livre','emballage colis marque','micro-cannelure']::text[],
  'Boîte d''expédition {{format}} {{matiere}} — impression {{finition}}', 'Boîtes d''expédition en micro-cannelure imprimées à vos couleurs, intérieur et extérieur, 5 formats de 15×12×5 à 50×50×15 cm, dès {{quantite}} exemplaire.',
  '## Le colis qui fait bonne impression

Dans la vente en ligne, la boîte d''expédition est souvent le seul contact physique entre votre marque et votre client. Cette gamme transforme un carton anonyme en support de marque : impression extérieure pour voyager à vos couleurs, impression intérieure pour soigner l''ouverture, ou les deux pour une expérience de déballage complète.

## Caractéristiques techniques

Micro-cannelure E de 1,8 mm, légère et résistante, dont la structure absorbe les chocs du transport. Deux faces au choix : kraft brun naturel ou blanc couché. Cinq formats couvrent l''essentiel des besoins, de 15×12×5 cm à 50×50×15 cm, complétés par des modèles spécialisés : boîte à rabat, fond semi-automatique pour accélérer la préparation, boîte plate pour documents, boîte à livres et pochettes carton. Fermeture par rabats ou bande de scellage double — la seconde bande facilitant les retours. Livrées à plat, rainées et découpées.

## Vos avantages

Dès l''exemplaire unique et avec une fabrication très courte, vous alignez vos emballages sur vos campagnes sans surstock. Un colis brandé se remarque, se photographie et se partage : c''est du marketing qui voyage avec chaque commande.', 'Boîtes d''expédition personnalisées {{format}} pour l''e-commerce',
  'Boîte d''expédition personnalisée — colis e-commerce', 'Boîtes d''expédition micro-cannelure imprimées int/ext : 5 formats, kraft ou blanc, bande de scellage retour. Dès 1 exemplaire, fabrication rapide.', array['boîte expédition personnalisée','packaging e-commerce','carton colis imprimé','boîte envoi','unboxing','boîte postale personnalisée','emballage colis']::text[], 'Product',
  'Chaque colis expédié est une publicité qui circule : imprimez vos boîtes dedans et dehors et faites de chaque livraison un moment de marque. Dès 1 exemplaire, fabriqué en un temps record.', '["Impression intérieure + extérieure pour l''effet unboxing", "Micro-cannelure E 1,8 mm : légère et protectrice", "5 formats standard + modèles spécialisés (livres, documents)", "Bande de double scellage pour faciliter les retours", "Dès 1 exemplaire, fabrication très rapide", "Livrées à plat, montage instantané"]'::jsonb, '["Colis e-commerce quotidiens", "Box d''abonnement mensuelle", "Expédition de livres et documents", "Envois presse et influenceurs", "Coffrets expédiés en direct"]'::jsonb,
  '[{"title": "Box par abonnement", "description": "Un service mensuel imprime l''intérieur de ses boîtes avec un visuel différent chaque saison, entretenant l''effet de surprise des abonnés."}, {"title": "Librairie en ligne", "description": "Un libraire expédie dans des boîtes à livres ajustées qui caleront les ouvrages sans matériau de rembourrage superflu."}, {"title": "Marque textile", "description": "Une marque de prêt-à-porter utilise la bande de double scellage : le client renvoie son échange dans la même boîte, sans ruban adhésif."}, {"title": "Kit presse", "description": "Une agence envoie ses dossiers de lancement dans des boîtes plates imprimées, qui arrivent impeccables chez les journalistes."}]'::jsonb, '[{"question": "Quelle taille de boîte choisir ?", "answer": "Prenez le format le plus proche des dimensions de vos produits pour limiter le calage et le vide : cinq tailles s''échelonnent de 15×12×5 à 50×50×15 cm."}, {"question": "À quoi sert la bande de double scellage ?", "answer": "Une première bande ferme le colis à l''expédition ; la seconde permet à votre client de refermer la boîte pour un retour, sans adhésif. Un vrai plus pour l''e-commerce."}, {"question": "Kraft brun ou blanc : quel impact sur l''impression ?", "answer": "Le blanc couché restitue fidèlement photos et couleurs vives ; le kraft brun teinte légèrement les encres et valorise les créations sobres, avec un positionnement recyclé assumé."}, {"question": "La boîte protège-t-elle suffisamment sans calage ?", "answer": "La micro-cannelure absorbe les chocs courants du transport. Pour les produits fragiles ou lourds, ajoutez un calage interne ou choisissez un format ajusté qui immobilise le contenu."}, {"question": "Puis-je commander un échantillon avant la série ?", "answer": "Oui, dès un exemplaire : testez le montage, le format et le rendu d''impression en conditions réelles avant de lancer votre volume."}]'::jsonb, '{"formats": ["150×120×50 mm", "200×140×80 mm", "230×230×80 mm", "350×250×100 mm", "500×500×150 mm", "Variantes : rabat, fond semi-automatique, plate, spéciale livres, pochette courrier"], "supports": ["Micro-cannelure E 1,8 mm kraft brun", "Micro-cannelure E 1,8 mm blanc couché", "Pochettes en carton graphique ou kraft"], "finitions": ["Impression extérieure, intérieure ou les deux", "Fermeture rabats ou bande de double scellage"], "impression": "Quadrichromie recto/verso", "quantites": "Dès 1 exemplaire, dégressif par paliers", "delais": "Fabrication express sur les formats standard", "options": ["Bande retour intégrée", "Ruban adhésif personnalisé assorti", "Livraison à plat"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── coffret_premium : Coffret premium / Boîte aimantée ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'coffret_premium', '{}'::jsonb, 'fr', 'Coffrets premium et boîtes aimantées', array['boîte aimantée personnalisée','coffret rigide','coffret cadeau entreprise','boîte luxe','coffret premium','boîte contrecollée','boîte fermeture aimantée','coffret présentation','packaging haut de gamme','boîte cadeau logo']::text[],
  'Coffret premium {{format}} — habillage {{matiere}}, marquage {{finition}}', 'Coffrets rigides et boîtes à fermeture aimantée en carton contrecollé habillé, marquage sérigraphie ou quadri, dès {{quantite}} exemplaires.',
  '## L''écrin qui dit la valeur de ce qu''il contient

Pour un cadeau d''affaires, un produit d''exception ou une box événementielle, le coffret rigide impose d''emblée un niveau de gamme. La boîte aimantée, avec son rabat qui se referme dans un claquement net, offre ce geste d''ouverture que l''on associe aux plus belles marques ; le coffret de présentation en cannelure habillée en propose une version plus accessible.

## Caractéristiques techniques

La boîte aimantée repose sur un carton blanc contrecollé de 380 g, habillé d''un papier couché contrecollé pour une épaisseur totale d''environ 3 mm, en quatre formats de 18×18×7 à 42×30×8 cm. Marquage en sérigraphie une ou deux couleurs, ou en quadrichromie numérique, sur couvercle et rabat, avec une palette d''habillages unis dont or, argent, bordeaux et noir. Le coffret de présentation utilise une micro-cannelure kraft 336 g ou blanche 391 g. Tous sont livrés à plat, rainés et prédécoupés, montage sans collage.

## Vos avantages

Vous offrez une expérience d''ouverture mémorable, réutilisable par son destinataire — votre marque reste sur le bureau ou l''étagère bien après le cadeau. Séries dès 5 à 25 exemplaires selon le modèle : le luxe devient accessible aux opérations ciblées.', 'Coffrets premium et boîtes aimantées personnalisés {{format}}',
  'Boîte aimantée personnalisée — coffret premium rigide', 'Coffrets rigides et boîtes aimantées : contrecollé 380 g habillé, 4 formats, sérigraphie ou quadri, habillages or, noir, bordeaux. Dès 5 à 25 exemplaires.', array['boîte aimantée','coffret premium personnalisé','coffret rigide logo','boîte cadeau entreprise','packaging luxe','coffret présentation','boîte contrecollée']::text[], 'Product',
  'Le claquement d''une fermeture aimantée vaut tous les discours sur la qualité. Offrez vos produits et cadeaux d''affaires dans un écrin rigide à vos couleurs, dès 25 exemplaires.', '["Fermeture aimantée au geste d''ouverture premium", "Contrecollé 380 g habillé, ~3 mm de rigidité totale", "4 formats couvrant du coffret bijou au format cadeau", "Sérigraphie ou quadri, habillages or, argent, noir, bordeaux…", "Réutilisable : votre marque reste chez le client", "Livré à plat, montage sans collage"]'::jsonb, '["Cadeaux d''affaires de fin d''année", "Coffrets produits haut de gamme", "Box événementielles et lancements", "Écrins bijouterie et maroquinerie", "Kits VIP presse et influence"]'::jsonb,
  '[{"title": "Fin d''année corporate", "description": "Une entreprise compose ses coffrets gourmands dans des boîtes aimantées noires marquées à l''or, offertes à ses cent meilleurs clients."}, {"title": "Lancement produit", "description": "Une marque tech envoie son nouveau produit à la presse dans un coffret rigide habillé, dont les photos de déballage circulent sur les réseaux."}, {"title": "Maison de spiritueux", "description": "Un producteur présente sa cuvée limitée dans un coffret de présentation kraft imprimé en blanc sélectif, aligné avec son image artisanale."}, {"title": "Créateur de bijoux", "description": "Un joaillier adopte le petit format aimanté comme écrin permanent, que ses clientes conservent et réutilisent."}]'::jsonb, '[{"question": "Boîte aimantée ou coffret cannelure : comment choisir ?", "answer": "La boîte aimantée en contrecollé habillé vise le très haut de gamme, avec un budget et un délai supérieurs. Le coffret en micro-cannelure offre un rendu soigné plus accessible, dès 5 exemplaires et fabriqué rapidement."}, {"question": "Quelles techniques de marquage sont possibles ?", "answer": "Sérigraphie une ou deux couleurs pour les logos et aplats nets, quadrichromie numérique pour les visuels complexes, sur le couvercle, le rabat ou les deux."}, {"question": "La boîte arrive-t-elle montée ?", "answer": "Non, elle est livrée à plat, rainée et prédécoupée : le montage se fait à la main en quelques instants, sans collage, et le stockage avant usage reste compact."}, {"question": "Quel est le minimum de commande ?", "answer": "25 exemplaires pour la boîte aimantée, 5 pour le coffret de présentation en cannelure : des seuils pensés pour les opérations ciblées."}, {"question": "Quel délai prévoir pour une opération de fin d''année ?", "answer": "Le contrecollé habillé demande un délai de fabrication plus long que le pliant standard : anticipez votre commande de plusieurs semaines pour les échéances de décembre."}]'::jsonb, '{"formats": ["180×180×70 mm", "250×180×100 mm", "350×250×120 mm", "420×300×80 mm (aimantée)", "Coffret présentation : 105×395×300 et 115×450×350 mm"], "supports": ["Carton blanc contrecollé 380 g habillé papier couché (~3 mm)", "Micro-cannelure kraft brun 336 g", "Micro-cannelure blanche 391 g"], "finitions": ["Fermeture aimantée", "Habillages unis : or, argent, noir, bordeaux, bleus, verts…", "Blanc sélectif sur kraft"], "impression": "Sérigraphie 1-2 couleurs ou quadrichromie numérique, couvercle et/ou rabat", "quantites": "Aimantée dès 25 ex. (jusqu''à 10 000) ; coffret cannelure dès 5 ex.", "delais": "Coffret cannelure : rapide ; boîte aimantée : fabrication longue, à anticiper", "options": ["Livré à plat prédécoupé", "Montage sans collage", "Calage intérieur sur demande"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

-- ─── sac_papier : Sac papier kraft ───
INSERT INTO public.product_definitions
  (gamme_slug, variation_filter, locale, name, keywords,
   title_template, short_description_template, description_template, h1_template,
   seo_title, seo_description, seo_keywords, schema_org_type,
   commercial_pitch, benefits, use_cases, usage_examples, faq, technical_spec,
   generated_by, validated_by)
VALUES (
  'sac_papier', '{}'::jsonb, 'fr', 'Sacs papier kraft personnalisés', array['sac papier personnalisé','sac kraft logo','sac boutique','sac poignées torsadées','sac papier commerce','sac papier recyclable','sac kraft imprimé','sac magasin personnalisé','sac papier événementiel','sac emballage boutique']::text[],
  'Sac papier kraft {{format}} — poignées torsadées, impression {{finition}}', 'Sacs papier kraft recyclables à poignées torsadées, 3 tailles imprimées grande surface à vos couleurs, dès {{quantite}} exemplaires.',
  '## Le sac qui prolonge votre boutique dans la rue

Chaque client qui repart avec votre sac devient un ambassadeur : le sac papier kraft affiche votre marque en ville, en salon comme au bureau. Recyclable et solide, il coche à la fois la case image et la case responsabilité, un argument que vos clients regardent de plus en plus.

## Caractéristiques techniques

Trois tailles couvrent l''essentiel des usages du commerce : 225×190×80 mm en kraft 27 g pour les petits articles, 300×220×100 mm en 41 g pour le prêt-à-porter et les coffrets, 340×260×140 mm en 60 g pour les achats volumineux. Les poignées torsadées sont renforcées par une bande de collage interne, pour une charge portée jusqu''à environ 6 kg. L''impression couvre une large surface des faces, pour un logo bien visible ou un visuel pleine face.

## Vos avantages

Vous remplacez un sac générique par un support publicitaire ambulant, au coût maîtrisé et cohérent avec une démarche zéro plastique. La personnalisation grande surface valorise autant une identité minimaliste kraft naturel qu''une création graphique affirmée, en boutique comme en événementiel.', 'Sacs papier kraft personnalisés {{format}} à poignées torsadées',
  'Sac papier kraft personnalisé — poignées torsadées', 'Sacs papier kraft recyclables imprimés à vos couleurs : 3 tailles, poignées torsadées renforcées, charge jusqu''à 6 kg. Idéal boutique et salon.', array['sac papier personnalisé','sac kraft logo','sac boutique imprimé','sac poignées torsadées','sac papier recyclable','sac commerce']::text[], 'Product',
  'Votre logo dans les rues, porté par vos propres clients : le sac kraft personnalisé est la publicité la plus naturelle qui soit. Recyclable, solide, à vos couleurs.', '["Kraft recyclable, alternative crédible au plastique", "3 tailles pour couvrir tous les achats en boutique", "Poignées torsadées renforcées, charge jusqu''à ~6 kg", "Grande surface d''impression sur les faces", "Image responsable valorisée auprès des clients", "Compatible usage boutique, salon et événementiel"]'::jsonb, '["Sacs de caisse en boutique", "Remise de cadeaux clients", "Salons et événements professionnels", "Vente à emporter épicerie fine", "Packaging de commande click-and-collect"]'::jsonb,
  '[{"title": "Boutique de prêt-à-porter", "description": "Un commerce remet chaque achat dans un sac moyen format à ses couleurs, transformant ses clients en vitrines mobiles dans le centre-ville."}, {"title": "Salon professionnel", "description": "Un exposant distribue documentation et goodies dans des sacs kraft logotés, repérables dans toutes les allées du salon."}, {"title": "Cave et épicerie fine", "description": "Un caviste utilise le grand format 60 g pour les achats de plusieurs bouteilles, avec des poignées qui tiennent la charge."}, {"title": "Concept store", "description": "Une enseigne joue le kraft naturel avec un logo une couleur, cohérent avec son positionnement durable, sans surcoût de mise en avant."}]'::jsonb, '[{"question": "Quel poids ces sacs peuvent-ils porter ?", "answer": "Jusqu''à environ 6 kg selon la taille, grâce aux poignées torsadées renforcées par une bande de collage interne. Choisissez le grammage supérieur pour les charges régulières."}, {"question": "Quelle taille pour quel usage ?", "answer": "Le petit format (225×190×80 mm) pour bijoux et petits articles, le moyen (300×220×100 mm) pour textile et coffrets, le grand (340×260×140 mm) pour les achats volumineux ou multiples."}, {"question": "Le sac est-il vraiment recyclable ?", "answer": "Oui, le kraft se recycle dans la filière papier classique, un argument concret pour votre communication responsable en boutique."}, {"question": "Quelle surface puis-je imprimer ?", "answer": "L''impression couvre une large zone des faces principales : logo centré discret ou visuel généreux, selon votre identité."}, {"question": "Quelle quantité commander pour démarrer ?", "answer": "Les séries s''adaptent aux besoins d''une boutique indépendante comme d''un réseau ; les prix affichés à la configuration deviennent vite dégressifs avec le volume."}]'::jsonb, '{"formats": ["225×190×80 mm (petit)", "300×220×100 mm (moyen)", "340×260×140 mm (grand)"], "supports": ["Kraft recyclable 27 g (petit)", "Kraft recyclable 41 g (moyen)", "Kraft recyclable 60 g (grand)"], "finitions": ["Poignées torsadées renforcées par bande de collage interne", "Impression grande surface sur les faces"], "impression": "Quadrichromie sur les faces principales", "quantites": "Paliers dégressifs affichés à la configuration", "delais": "Délais affichés en temps réel selon quantité", "options": ["Charge supportée jusqu''à ~6 kg", "Kraft blanc ou brun selon disponibilité"]}'::jsonb,
  'hybrid', 'pending')
ON CONFLICT (gamme_slug, variation_filter, locale) DO NOTHING;

