  use_cases        = coalesce(use_cases, '["Plaquette commerciale d''entreprise", "Guide ou mode d''emploi", "Carte et menu de restaurant", "Programme d''événement", "Documentation de salon"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['dépliant','dépliant publicitaire','plaquette commerciale','dépliant plié','impression dépliant','dépliant 3 volets','pli roulé','pli accordéon']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["ouverts A5 à A2 et jusqu''à 630 × 297 mm", "fermés DL, A5, A4, carré", "sur mesure"], "supports": ["offset 90-120 g", "couché brillant/demi-mat 130-350 g", "recyclé, kraft, création"], "finitions": ["vernis sélectif 2D/3D", "dorure à chaud", "pelliculage", "rainage dès 170 g"], "impression": "quadri recto/verso", "quantites": "50 → 100 000 ex., paliers 100/250/500/1000/2500", "delais": "standard 48-72 h, express possible", "options": ["plis roulé, central, décalé, accordéon, portefeuille, croisé, fenêtre", "livré plié", "multi-visuels"]}'::jsonb)
WHERE gamme_slug = 'depliant' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'Quand un dépliant ne suffit plus, la brochure prend le relais : des dizaines de pages reliées pour un catalogue, un rapport ou un magazine qui installe durablement votre crédibilité. Le support qui reste sur le bureau de vos clients.'),
  benefits         = coalesce(benefits, '["De 8 à 512 pages selon la reliure choisie", "4 reliures : agrafée, dos carré collé, cousue, wire-o", "Couverture personnalisable : pelliculage, vernis, papier création", "Dès 1 exemplaire : maquette, tirage de tête ou série", "Mix grammages couverture/intérieur pour maîtriser le budget", "Rendu éditorial professionnel type livre ou magazine"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Catalogue produits annuel", "Rapport d''activité ou RSE", "Magazine ou revue interne", "Lookbook de collection", "Manuel ou guide technique"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['brochure','impression brochure','catalogue','livret','brochure agrafée','dos carré collé','magazine entreprise','brochure personnalisée']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["A4, A5, A6, DL 99 × 210 mm", "carrés 148 × 148 et 210 × 210 mm", "portrait ou paysage", "sur mesure"], "supports": ["couverture couché 250-300 g, offset, texturé, recyclé", "intérieur offset 80-120 g ou couché 90-170 g"], "finitions": ["pelliculage mat/brillant/soft touch/sablé", "vernis sélectif 2D", "rabats de couverture"], "impression": "quadri recto/verso", "quantites": "1 → plusieurs milliers selon reliure", "delais": "standard 3-7 jours ouvrés selon reliure, express possible", "options": ["reliures agrafée, collée, cousue, spirale", "onglets sur mesure", "papier intérieur recyclé"]}'::jsonb)
WHERE gamme_slug = 'brochure' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'Deux agrafes, un dos plat, un budget maîtrisé : la brochure piquée est la solution la plus rapide et la plus économique pour publier de 8 à 80 pages. Le standard des catalogues, programmes et livrets qui vont à l''essentiel.'),
  benefits         = coalesce(benefits, '["La reliure la plus économique du marché", "Ouverture à plat facilitant la lecture", "Pagination souple de 8 à 80 pages intérieures (multiples de 4)", "Délais courts, dès 1 exemplaire", "Légère : économique aussi à l''affranchissement", "Couverture 250 g+ pelliculable pour un rendu soigné"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Catalogue ou tarif saisonnier", "Programme de festival ou saison culturelle", "Livret d''accueil entreprise", "Notice ou guide utilisateur", "Fanzine ou publication associative"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['brochure agrafée','piqûre à cheval','brochure piquée','livret agrafé','impression brochure agrafée','catalogue agrafé','brochure 2 agrafes','programme imprimé']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["A4, A5, A6, DL 99 × 210 mm", "carrés 148 et 210 mm", "portrait/paysage", "sur mesure"], "supports": ["couverture couché 250-300 g ou offset, recyclé, texturé", "intérieur offset 80-120 g ou couché demi-mat 90-170 g"], "finitions": ["pelliculage mat/brillant/soft touch/sablé", "vernis sélectif 2D", "sans couverture possible (autocouverture)"], "impression": "quadri recto/verso", "quantites": "1 → 10 000 ex., paliers 25/50/100/250/500", "delais": "standard 48-96 h, express possible", "options": ["8 à 80 pages intérieures par pas de 4", "2 agrafes à cheval", "version recyclée"]}'::jsonb)
WHERE gamme_slug = 'brochure_piquee' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'Le dos carré collé donne à votre document le statut d''un vrai livre : un dos imprimable, une tenue en bibliothèque, une crédibilité immédiate. Le choix des catalogues volumineux, rapports annuels et éditions qui durent.'),
  benefits         = coalesce(benefits, '["Aspect livre professionnel avec dos imprimable", "Grande capacité : de 36 à 500 pages et plus", "Tient debout en rayonnage, tranche visible", "Couverture épaisse pelliculée très résistante", "Valorise le contenu : perçu comme une édition", "Dès l''exemplaire unique pour maquettes et tirages de tête"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Catalogue général volumineux", "Rapport annuel ou institutionnel", "Livre d''entreprise ou beau livre", "Mémoire, thèse, autoédition", "Lookbook premium de marque"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['dos carré collé','brochure dos carré','impression livre','catalogue dos carré','reliure collée','livre broché','rapport annuel imprimé','autoédition']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["A4, A5, A6, carrés", "sur mesure de 145 à 297 mm", "portrait/paysage"], "supports": ["couverture couché demi-mat/brillant 250-300 g, offset 300 g, texturé, recyclé", "intérieur 80-170 g offset ou couché"], "finitions": ["pelliculage mat/brillant/soft touch", "vernis sélectif", "rabats possibles", "dos imprimé"], "impression": "quadri recto/verso", "quantites": "1 → 500 ex. en numérique, milliers en offset", "delais": "standard 4-7 jours ouvrés, express possible", "options": ["36 à 512 pages, dos minimum ~1,3 mm", "couverture à rabats", "version cousue pour durabilité maximale"]}'::jsonb)
WHERE gamme_slug = 'brochure_dos_carre' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'La spirale métallique est la seule reliure qui s''ouvre parfaitement à plat et se replie sur elle-même : idéale pour tout document qu''on consulte en travaillant. Manuels, carnets techniques, supports de formation — la reliure des documents qui servent.'),
  benefits         = coalesce(benefits, '["Ouverture 100 % à plat, rotation complète à 360°", "Consultation mains libres pendant le travail", "Reliure métallique très résistante à l''usage intensif", "Spirale blanche ou noire assortie à votre charte", "Pages tournées des centaines de fois sans fatigue", "Couverture rigide 300 g protégeant l''intérieur"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Support de formation ou séminaire", "Manuel technique d''atelier", "Carnet de suivi ou de chantier", "Book de présentation commerciale", "Recueil de recettes ou protocoles"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['reliure spirale','wire-o','brochure spirale','reliure métallique','document relié spirale','support de formation imprimé','manuel spirale','impression wire-o']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["A4 210 × 297 mm", "A5 148 × 210 mm", "sur mesure"], "supports": ["couverture couché 300 g demi-mat ou brillant", "intérieur couché 130 g demi-mat ou brillant"], "finitions": ["pelliculage de couverture", "spirale métal blanche ou noire", "couverture transparente en option"], "impression": "quadri recto/verso", "quantites": "5 → 2 000 ex., paliers 5/10/25/50/100", "delais": "standard 5-8 jours ouvrés", "options": ["12 à 64 pages totales", "trous calibrés wire-o", "ouverture à plat garantie"]}'::jsonb)
WHERE gamme_slug = 'brochure_spirale' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'Le dos cousu est la reliure des éditions qui traversent le temps : les cahiers sont cousus au fil avant collage, le livre s''ouvre généreusement et ne perd jamais une page. Le haut de gamme de la brochure, pour les documents qui engagent votre image.'),
  benefits         = coalesce(benefits, '["Solidité maximale : pages cousues, jamais arrachées", "Ouverture ample sans casser le dos", "Fil apparent possible : signature artisanale visible", "Longévité d''édition : le choix des beaux livres", "Positionne le document comme un objet précieux", "Compatible couvertures création et finitions premium"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Beau livre ou ouvrage d''art", "Édition anniversaire d''entreprise", "Portfolio d''architecte ou de studio", "Catalogue d''exposition", "Livre de marque (brand book)"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['dos cousu','reliure cousue','brochure cousue','dos carré collé cousu','beau livre','reliure fil','édition premium','livre cousu collé']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["A4, A5", "carrés", "sur mesure"], "supports": ["couverture couché 250-300 g, papiers de création, texturés", "intérieur couché ou offset 90-170 g"], "finitions": ["pelliculage mat/soft touch", "dorure à chaud sur couverture", "fil de couture apparent en option", "rabats"], "impression": "quadri recto/verso", "quantites": "10 → 2 000 ex. selon projet", "delais": "standard 7-10 jours ouvrés", "options": ["cahiers cousus puis collés", "pagination élevée possible", "tranchefile sur devis"]}'::jsonb)
WHERE gamme_slug = 'brochure_cousue' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'L''affiche impose votre message dans l''espace : vitrine, mur, panneau, abribus — du A3 de comptoir au 4×3 urbain, c''est le média de la visibilité pure. Un visuel fort, un format adapté au lieu, et votre communication existe physiquement.'),
  benefits         = coalesce(benefits, '["Tous formats du A3 au panneau 4×3 m", "Papiers dédiés à chaque usage : intérieur, vitrine, extérieur", "Impression dès 1 exemplaire, HD disponible", "Papier fluo pour les promotions à fort impact", "Dos bleu et encapsulage pour l''extérieur", "Renouvellement rapide au rythme de vos campagnes"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Vitrine et point de vente", "Campagne d''affichage urbain", "Signalétique d''événement", "Décoration murale de locaux", "Annonce culturelle (concert, expo)"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['affiche','poster','impression affiche','affiche publicitaire','affiche personnalisée','affiche grand format','affiche événement','impression poster']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["A3 297 × 420 mm à A0 841 × 1189 mm", "400 × 600, 600 × 800 mm", "1200 × 1760 mm abribus", "jusqu''à 4 × 3 m en lés", "sur mesure"], "supports": ["couché demi-mat/brillant 130-170 g", "offset 90-120 g", "dos bleu 120 g", "recyclé 115-135 g", "fluo", "papier photo 200-230 g"], "finitions": ["vernis 2D", "encapsulage", "bords vifs"], "impression": "quadri recto (recto/verso possible), standard ou HD", "quantites": "1 → 20 000 ex., paliers 1/5/10/25/50/100", "delais": "standard 24-96 h selon format, express possible", "options": ["pli optionnel pour expédition", "livraison roulée", "usage intérieur/extérieur"]}'::jsonb)
WHERE gamme_slug = 'affiche' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'L''A3 est l''affichette universelle : format des vitrines de proximité, des panneaux d''information et des supports de caisse. Imprimée à l''unité ou en série, elle se renouvelle aussi vite que vos actualités.'),
  benefits         = coalesce(benefits, '["Format compact adapté aux petits espaces d''affichage", "Compatible cadres clic-clac et porte-affiches A3", "Très économique, même en petite quantité", "Impression dès 1 exemplaire", "Parfaite en réseau : une affichette par point de vente", "Déclinable depuis vos fichiers A4 agrandis"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Affichette vitrine de commerce", "Information en point de vente", "Menu ou promo du jour", "Communication interne (locaux, ateliers)", "Annonce associative locale"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['affiche A3','affichette A3','poster A3','impression A3','affiche 297x420','affiche vitrine','affiche petit format','affichette commerce']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["297 × 420 mm (A3)"], "supports": ["couché demi-mat/brillant 130-170 g", "offset 90-120 g", "recyclé 115-135 g"], "finitions": ["sans finition", "vernis 2D recto"], "impression": "quadri recto ou recto/verso", "quantites": "1 → 20 000 ex., paliers 1/10/25/50/100/250", "delais": "standard 24-72 h, express possible", "options": ["qualité standard ou HD", "livraison à plat"]}'::jsonb)
WHERE gamme_slug = 'affiche_a3' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'L''A2 double la présence de l''A3 sans exiger un grand mur : le bon format pour être vu à cinq mètres dans une vitrine, un hall ou un couloir de passage. L''équilibre parfait entre impact et encombrement.'),
  benefits         = coalesce(benefits, '["Lisibilité confortable jusqu''à 5 mètres", "S''insère dans vitrines et halls sans dominer l''espace", "Compatible cadres et chevalets A2 standards", "Impression unitaire pour tests de visuels", "Coût contenu pour un renouvellement fréquent", "Papier fluo disponible pour les urgences promo"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Vitrine de moyenne surface", "Affichage hall d''accueil", "Promotion en pharmacie ou commerce", "Signalétique de salon", "Affiche culturelle de proximité"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['affiche A2','poster A2','impression A2','affiche 420x594','affiche vitrine A2','affiche moyenne format','impression affiche','affiche promotionnelle']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["420 × 594 mm (A2)"], "supports": ["couché demi-mat/brillant 130-170 g", "offset 90-120 g", "recyclé", "fluo"], "finitions": ["sans finition", "vernis 2D recto"], "impression": "quadri recto ou recto/verso", "quantites": "1 → 10 000 ex., paliers 1/5/10/25/50/100", "delais": "standard 24-72 h, express possible", "options": ["qualité standard ou HD", "pli central optionnel pour expédition"]}'::jsonb)
WHERE gamme_slug = 'affiche_a2' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'Avec près d''un demi-mètre carré, l''A1 entre dans la cour du vrai grand format : visible à dix mètres, elle habille chevalets de trottoir, vitrines profondes et murs d''événements. Le format qui se remarque sans exiger un panneau dédié.'),
  benefits         = coalesce(benefits, '["≈0,5 m² : impact visuel fort à distance", "Standard des chevalets et stop-trottoirs grands modèles", "Idéale murs d''accueil et fonds de vitrine", "Impression HD pour visuels photographiques", "Unité possible pour événements ponctuels", "Livrée roulée, sans marque de pli"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Chevalet de trottoir grand format", "Fond de vitrine ou mur d''accueil", "Plan ou programme d''événement", "Affiche de spectacle en réseau urbain", "Signalétique directionnelle temporaire"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['affiche A1','poster A1','impression A1','affiche 594x841','affiche grand format','affiche chevalet','poster mural','impression grand format']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["594 × 841 mm (A1)"], "supports": ["couché demi-mat/brillant 130-170 g", "offset 90-120 g", "recyclé satin 115 g", "dos bleu 120 g", "fluo"], "finitions": ["sans finition", "vernis 2D", "encapsulage en option"], "impression": "quadri recto ou recto/verso, standard ou HD", "quantites": "1 → 5 000 ex., paliers 1/5/10/25/50/100", "delais": "standard 24-72 h, express possible", "options": ["livraison roulée", "bords vifs"]}'::jsonb)
WHERE gamme_slug = 'affiche_a1' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'L''A0, c''est un mètre carré de communication : le format des murs d''exposition, des salons professionnels et des posters scientifiques. Quand le message doit dominer l''espace, aucun format standard ne va plus loin.'),
  benefits         = coalesce(benefits, '["1 m² de surface : présence maximale en format standard", "Format officiel des posters scientifiques et congrès", "Lisible à plus de dix mètres", "Impression HD pour cartes, plans et photos détaillées", "Unité possible : parfait pour un événement unique", "Livrée roulée en emballage renforcé"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Poster scientifique de congrès", "Mur d''exposition ou de salon", "Plan de site grand format", "Décor événementiel ponctuel", "Affichage institutionnel de hall"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['affiche A0','poster A0','impression A0','affiche 841x1189','poster scientifique','poster congrès','impression grand format','affiche 1m2']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["841 × 1189 mm (A0)"], "supports": ["couché demi-mat/brillant 130-170 g", "offset 120 g", "dos bleu 120 g", "papier photo 200-230 g"], "finitions": ["sans finition", "vernis 2D", "encapsulage en option"], "impression": "quadri recto, qualité standard ou HD", "quantites": "1 → 1 000 ex., paliers 1/5/10/25/50", "delais": "standard 24-72 h, express possible", "options": ["livraison roulée", "tube renforcé", "bords vifs"]}'::jsonb)
WHERE gamme_slug = 'affiche_a0' AND locale = 'fr';

UPDATE public.product_definitions SET
  commercial_pitch = coalesce(commercial_pitch, 'Le format le plus vendu du marché, et pour cause : assez large pour votre message, assez compact pour voyager partout. Structure, toile M1 et sac inclus — déployé en moins d''une minute.'),
  benefits         = coalesce(benefits, '["Le standard universel : compatible avec tous les espaces", "Montage en moins d''une minute, sans outil", "Structure aluminium lestée, stable et légère (~3 kg)", "Sac de transport inclus, portable à une main", "Toile classée M1 acceptée dans tous les salons et ERP", "Le meilleur prix d''entrée de la gamme kakémono"]'::jsonb),
  use_cases        = coalesce(use_cases, '["Stand de salon professionnel", "Accueil de boutique ou d''agence", "Animation en galerie commerciale", "Signalétique de séminaire", "Vitrine promotionnelle temporaire"]'::jsonb),
  seo_keywords     = coalesce(seo_keywords, array['roll-up 80x200','roll-up 85x200','kakémono 80x200','impression roll-up','roll-up pas cher','enrouleur publicitaire standard','roll-up salon']::text[]),
  technical_spec   = coalesce(technical_spec, '{"formats": ["~84×204 cm (standard marché 80/85×200 cm)"], "supports": ["Bâche PVC 450 g dos occultant M1", "Polyester 270 g M1", "Polyester 260 g sans PVC M1"], "finitions": ["Toile enroulable dans la base", "Visuel remplaçable selon modèle"], "impression": "Quadri recto haute définition", "quantites": "1 à 50 exemplaires, tarif dégressif", "delais": "Standard 3 à 5 jours ouvrés, express possible", "options": ["Structure aluminium incluse", "Barre de lestage", "Sac de transport inclus", "Classement feu M1"]}'::jsonb)
WHERE gamme_slug = 'roll_up_80x200' AND locale = 'fr';

